-- Poems batch 150
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0c79faeb-0291-437c-824c-976f2c790aca','茅齋','許及之','宋','宋诗','song-poetry','','[]','市近無營地自幽，身閒何羨水中鷗。',32,'全唐诗/poet.song.153000.json','["市近無營地自幽，身閒何羨水中鷗。", "因思客路竿遮日，得似君家茅蓋頭。"]'),
('193e64c5-c8f0-4c4b-b58d-75e20679b9f7','梅坡','許及之','宋','宋诗','song-poetry','','[]','買得梅坡與衆看，折花教折莫催殘。',32,'全唐诗/poet.song.153000.json','["買得梅坡與衆看，折花教折莫催殘。", "虯枝裹蘚能炊玉，留與梅坡伴歲寒。"]'),
('fff6ed0b-e1a5-4f34-801f-242bf85000fc','松林','許及之','宋','宋诗','song-poetry','','[]','蒼髯老氣已雄豪，偃蹇連延結虹橋。',32,'全唐诗/poet.song.153000.json','["蒼髯老氣已雄豪，偃蹇連延結虹橋。", "當暑含颸時瑟瑟，底須屋角相風招。"]'),
('c2466f03-8a3e-4acb-959b-d1913dd0259c','信筆戒子種花木  其一','許及之','宋','宋诗','song-poetry','','[]','君恩未許乞分符，三徑無資地亦無。',32,'全唐诗/poet.song.153000.json','["君恩未許乞分符，三徑無資地亦無。", "或借或資分養種，閒時趁早著工夫。"]'),
('aeffb196-0c57-4214-a820-c0c98434ca94','信筆戒子種花木  其二','許及之','宋','宋诗','song-poetry','','[]','廼翁未遂投閒計，吾子宜殫幹蠱才。',32,'全唐诗/poet.song.153000.json','["廼翁未遂投閒計，吾子宜殫幹蠱才。", "已辦一區供戲綵，更營三徑待歸來。"]'),
('8a840545-12b7-42d3-8b30-0ae825a2627a','信筆戒子種花木  其三','許及之','宋','宋诗','song-poetry','','[]','一年活計在春初，處世光陰不可虛。',32,'全唐诗/poet.song.153000.json','["一年活計在春初，處世光陰不可虛。", "莫謂窺園全廢學，昔人猶有带經鋤。"]'),
('56ee6d83-066a-409e-b9d0-e6ae6caea9e7','信筆戒子種花木  其四','許及之','宋','宋诗','song-poetry','','[]','栽種成陰動十年，風流遺恨憶蘇宣。',32,'全唐诗/poet.song.153000.json','["栽種成陰動十年，風流遺恨憶蘇宣。", "西園近有移園法，大樹根盤只儼然。"]'),
('35b8fab1-5aad-4a84-850e-328bada4022d','信筆戒子種花木  其五','許及之','宋','宋诗','song-poetry','','[]','買宅慇懃爲海棠，却因改築遂移將。',32,'全唐诗/poet.song.153000.json','["買宅慇懃爲海棠，却因改築遂移將。", "前園褊小鄰遷次，好補霓裳斷續行。"]'),
('979433a4-c32c-4e5e-bde8-46d25f18e78d','信筆戒子種花木  其六','許及之','宋','宋诗','song-poetry','','[]','池妨屋地故應填，取土成池却自然。',32,'全唐诗/poet.song.153000.json','["池妨屋地故應填，取土成池却自然。", "愛惜清漪添淤壤，買根歸種撫州蓮。"]'),
('69f18c52-1231-46ab-8f89-d18ba1211abd','信筆戒子種花木  其七','許及之','宋','宋诗','song-poetry','','[]','買石雖非自鬰林，窠窠盡費俸餘金。',32,'全唐诗/poet.song.153000.json','["買石雖非自鬰林，窠窠盡費俸餘金。", "傍人應笑謀生拙，航海梯山枉費心。"]'),
('4ec424c0-4153-463c-a0a2-f95ec7cb12dc','信筆戒子種花木  其八','許及之','宋','宋诗','song-poetry','','[]','買石爲山任笑癡，癡翁真箇似童兒。',32,'全唐诗/poet.song.153000.json','["買石爲山任笑癡，癡翁真箇似童兒。", "奇峰峭石勤收拾，莫使他年一簣虧。"]'),
('7ff96168-0c52-4a0b-a6e1-f9e2ce6475c3','信筆戒子種花木  其九','許及之','宋','宋诗','song-poetry','','[]','我山壘土仍栽石，下有嵌岩上有亭。',32,'全唐诗/poet.song.153000.json','["我山壘土仍栽石，下有嵌岩上有亭。", "石少闕邊添種樹，種時須要樹長青。"]'),
('3e438cd3-d451-4dca-bbb5-c1f4ab4fe96f','信筆戒子種花木  其一○','許及之','宋','宋诗','song-poetry','','[]','四時巖桂度香風，十月桃花吐艷紅。',32,'全唐诗/poet.song.153000.json','["四時巖桂度香風，十月桃花吐艷紅。", "當暑拒霜同愛惜，種成方可醉鄰翁。"]'),
('81a0b396-780f-40d4-9a51-ef98e595e779','信筆戒子種花木  其一一','許及之','宋','宋诗','song-poetry','','[]','水仙繡菊麝香萱，久種成畦長養便。',32,'全唐诗/poet.song.153000.json','["水仙繡菊麝香萱，久種成畦長養便。", "分向北堂三益近，遶牆秋色要爭妍。"]'),
('5b395db0-c457-4fae-8bfc-8b796617ab91','信筆戒子種花木  其一二','許及之','宋','宋诗','song-poetry','','[]','種樹還如種善根，自須積累付兒孫。',32,'全唐诗/poet.song.153000.json','["種樹還如種善根，自須積累付兒孫。", "從人覓得能多少，爭得成陰便滿園。"]'),
('4dcd9653-8e74-4a46-b741-4b8c8c1e78f7','信筆戒子種花木  其一三','許及之','宋','宋诗','song-poetry','','[]','莫將桃杏等閒看，栽接名窠有幾般。',32,'全唐诗/poet.song.153000.json','["莫將桃杏等閒看，栽接名窠有幾般。", "爲是開花仍結實，花供賞翫果供餐。"]'),
('ffe966c3-6e1d-4f6d-9c03-d68802b5b143','信筆戒子種花木  其一四','許及之','宋','宋诗','song-poetry','','[]','飛霞園地固無多，我愛他時號繭窩。',32,'全唐诗/poet.song.153000.json','["飛霞園地固無多，我愛他時號繭窩。", "若繚城跟疎織竹，錦屏環列繡成窠。"]'),
('b2b10df8-14c8-40a5-8a9e-182c88cd40bc','信筆戒子種花木  其一五','許及之','宋','宋诗','song-poetry','','[]','金沙安敢齒酴醾，白白紅紅間却宜。',32,'全唐诗/poet.song.153000.json','["金沙安敢齒酴醾，白白紅紅間却宜。", "但是籬邊多種取，他年步障要相隨。"]'),
('4d103a0e-f2a4-4161-b3c3-96e46a020327','梅花十首  其一','許及之','宋','宋诗','song-poetry','','[]','每憶山居氣味長，梅花時節只清狂。',32,'全唐诗/poet.song.153000.json','["每憶山居氣味長，梅花時節只清狂。", "若教玉鑑堂前看，認得花光是玉光。"]'),
('96b8d52a-918f-408e-95dd-904e2342ba0b','梅花十首  其二','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詩到西湖更不疑，西湖以外可無詩。',32,'全唐诗/poet.song.153000.json','["詩到西湖更不疑，西湖以外可無詩。", "孤山水月無邊思，只在清香不在枝。"]'),
('10d46499-c07b-4a77-af1c-e63efeeb05e3','梅花十首  其三','許及之','宋','宋诗','song-poetry','','[]','一頃園池半種梅，更將窠石傍梅栽。',32,'全唐诗/poet.song.153000.json','["一頃園池半種梅，更將窠石傍梅栽。", "愛風愛月隨宜看，合是詩家带得來。"]'),
('e57ce040-87f5-41e0-9f26-f6e47f020fb6','梅花十首  其四','許及之','宋','宋诗','song-poetry','','[]','隔水尋幽妙莫傳，一年勝處是春前。',32,'全唐诗/poet.song.153000.json','["隔水尋幽妙莫傳，一年勝處是春前。", "縱饒爛熳春吹却，猶得殘香伴鶴眠。"]'),
('26fdab7d-30fd-4756-9088-407fb88317a9','梅花十首  其五','許及之','宋','宋诗','song-poetry','','[]','玉川夢事不紛紜，一樹相思正憶君。',32,'全唐诗/poet.song.153000.json','["玉川夢事不紛紜，一樹相思正憶君。", "君若移舟來問訊，莫教驚動一溪雲。"]'),
('8eb13e8c-5569-414f-b3ac-441c53f7ca05','梅花十首  其六','許及之','宋','宋诗','song-poetry','','[]','爲愛林林次第開，却須雪壓與霜催。',32,'全唐诗/poet.song.153000.json','["爲愛林林次第開，却須雪壓與霜催。", "歲寒偃蹇非無意，破冷衝寒來幾回。"]'),
('44b7cf3b-6cf4-4290-b450-4ffba3ef401f','梅花十首  其七','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去歲來時恰犯寒，枝頭未放雪漫漫。',32,'全唐诗/poet.song.153000.json','["去歲來時恰犯寒，枝頭未放雪漫漫。", "一年鞭影紅塵裏，猶得西湖立馬看。"]'),
('809a1f9e-b7f7-48c4-b2df-ade0b36dc328','梅花十首  其八','許及之','宋','宋诗','song-poetry','','[]','湖上歸鴉落照昏，一聲漁唱與招魂。',32,'全唐诗/poet.song.153000.json','["湖上歸鴉落照昏，一聲漁唱與招魂。", "紉蘭餐菊生平事，沙冷月寒何處村。"]'),
('0248a502-fc22-4c7c-bedf-0815767690c4','梅花十首  其九','許及之','宋','宋诗','song-poetry','','[]','醉餘看字眼麻茶，佳句拈來似隔紗。',32,'全唐诗/poet.song.153000.json','["醉餘看字眼麻茶，佳句拈來似隔紗。", "讀去讀來元有味，南湖從此說梅花。"]'),
('a7912b49-b716-4450-b48b-d4536eb043f4','梅花十首  其一○','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老去哦詩懶解工，筆端隨分有春風。',32,'全唐诗/poet.song.153000.json','["老去哦詩懶解工，筆端隨分有春風。", "傍人若問梅花句，盡在西湖風雪中。"]'),
('51fb44b4-c4e8-4e73-b775-b33c81204acf','次韻常之用前人韻賦梅花十絕  其一','許及之','宋','宋诗','song-poetry','','[]','老來爲圃萬緣輕，一見梅花眼倍明。',32,'全唐诗/poet.song.153000.json','["老來爲圃萬緣輕，一見梅花眼倍明。", "所恨平生無句眼，其如相與有詩情。"]'),
('a1f854be-d9c5-40c2-97f0-0d351d84d98a','次韻常之用前人韻賦梅花十絕  其二','許及之','宋','宋诗','song-poetry','','[]','淵明豈獨愛東籬，便愛東籬亦匪私。',32,'全唐诗/poet.song.153000.json','["淵明豈獨愛東籬，便愛東籬亦匪私。", "耐雪耐霜同臭味，佳花尤愛夾花枝。"]'),
('1bf1d553-c6a4-4ecc-9ccc-ffb8865f9668','次韻常之用前人韻賦梅花十絕  其三','許及之','宋','宋诗','song-poetry','','[]','風靜得香多醖藉，雪殘觀色轉精神。',32,'全唐诗/poet.song.153000.json','["風靜得香多醖藉，雪殘觀色轉精神。", "不教翠竹疎松畔，清殺天寒日暮人。"]'),
('87e8f18a-87c0-46b0-b914-36f1c6c5407e','次韻常之用前人韻賦梅花十絕  其四','許及之','宋','宋诗','song-poetry','','[]','拙速誠難語巧遲，誰知先進野人爲。',32,'全唐诗/poet.song.153000.json','["拙速誠難語巧遲，誰知先進野人爲。", "絕憐飯顆山頭老，江路聞香有喜詞。"]'),
('0988c9eb-e3ee-4142-b60a-4fc670a5260b','次韻常之用前人韻賦梅花十絕  其五','許及之','宋','宋诗','song-poetry','','[]','每愛孤山靜思凝，歲寒不脫柏青青。',32,'全唐诗/poet.song.153000.json','["每愛孤山靜思凝，歲寒不脫柏青青。", "暗中參得橫斜趣，不費陶潜影答形。"]'),
('93368b61-07ae-41d6-b65c-7635cdd18fd3','次韻常之用前人韻賦梅花十絕  其六','許及之','宋','宋诗','song-poetry','','[]','玉川清苦更清狂，一夜相思不可當。',32,'全唐诗/poet.song.153000.json','["玉川清苦更清狂，一夜相思不可當。", "解道是君看亦好，不然白地斷人腸。"]'),
('534b02b8-c1e3-4273-95a4-792be2fe1c72','次韻常之用前人韻賦梅花十絕  其七','許及之','宋','宋诗','song-poetry','','[]','未點蒼苔已點衣，遽辭脩竹翠相依。',32,'全唐诗/poet.song.153000.json','["未點蒼苔已點衣，遽辭脩竹翠相依。", "若教笛怨歌催盡，寧受風吹雨打稀。"]'),
('1e519a2c-7ebd-4a2b-82c6-00f7ef4a98e1','次韻常之用前人韻賦梅花十絕  其八','許及之','宋','宋诗','song-poetry','','[]','浮玉飄香別緒多，緩流溪水浸銅柯。',32,'全唐诗/poet.song.153000.json','["浮玉飄香別緒多，緩流溪水浸銅柯。", "先春有意春無意，春奈千紅百紫何。"]'),
('d7b3b9c8-810b-449f-a4a6-d394c6dd4571','次韻常之用前人韻賦梅花十絕  其九','許及之','宋','宋诗','song-poetry','','[]','臘雪溶溶斷送冬，明朝波面受春風。',32,'全唐诗/poet.song.153000.json','["臘雪溶溶斷送冬，明朝波面受春風。", "北園幾樹紅苞坼，只合吹將酒盞中。"]'),
('880bdb2e-ed96-4fc9-b8fc-a7098edbde5c','次韻常之用前人韻賦梅花十絕  其一○','許及之','宋','宋诗','song-poetry','','[]','桃縱夭夭杏縱繁，衰翁其奈眼尤寒。',32,'全唐诗/poet.song.153000.json','["桃縱夭夭杏縱繁，衰翁其奈眼尤寒。", "自知不是尋芳伴，且把寒枝子細看。"]'),
('beacefb4-8194-428b-976a-2939921a6f49','次韻古梅二首  其一','許及之','宋','宋诗','song-poetry','','[]','綠苔枝上玉疎疎，折贈詩人意不孤。',32,'全唐诗/poet.song.153000.json','["綠苔枝上玉疎疎，折贈詩人意不孤。", "惱殺渠儂歸未得，梅坡千樹有如無。"]'),
('c29deb8d-e817-44be-a20b-8a22cdbdb6d9','次韻古梅二首  其二','許及之','宋','宋诗','song-poetry','','[]','玉鑑堂前迹已疎，殘香應伴鶴聲孤。',32,'全唐诗/poet.song.153000.json','["玉鑑堂前迹已疎，殘香應伴鶴聲孤。", "郎潜桂隠身藏却，新爲梅花著句無。"]'),
('a420bc2b-23d0-4756-9d7f-db194636c29d','直舍紫薇花身可以題字因作一絕書其上','許及之','宋','宋诗','song-poetry','','[]','赤立嚴霜如槁木，爛開炎日似紅霞。',32,'全唐诗/poet.song.153000.json','["赤立嚴霜如槁木，爛開炎日似紅霞。", "耐寒耐暑真能事，豈是人間怕癢花。"]'),
('dcd14f43-ba1e-42a6-a6f4-9ce3adb5778a','揚州席上次蔣右衛韻賦白牡丹二絕  其一','許及之','宋','宋诗','song-poetry','','[]','秋思憑高不易裁，陽和喚得故人來。',32,'全唐诗/poet.song.153000.json','["秋思憑高不易裁，陽和喚得故人來。", "自憐梅萼成孤絕，借與春風一色開。"]'),
('c6396fb9-129e-47b0-9115-a2357b71bffe','揚州席上次蔣右衛韻賦白牡丹二絕  其二','許及之','宋','宋诗','song-poetry','','[]','玉甃銀缾千尺清，喚回玉色謫仙人。',32,'全唐诗/poet.song.153000.json','["玉甃銀缾千尺清，喚回玉色謫仙人。", "沉香亭畔無消息，付與揚州十月春。"]'),
('bc655f08-fa76-4ca7-9795-f8e0a4601699','北方館馹屏風皆畫落墨牡丹','許及之','宋','宋诗','song-poetry','','[]','停車京洛浄風沙，幾見屏開落墨花。',32,'全唐诗/poet.song.153000.json','["停車京洛浄風沙，幾見屏開落墨花。", "故國似人猶可喜，穠肌何况謝鉛華。"]'),
('476e21c5-795d-46c6-b0e8-042bc05a2c37','池荷','許及之','宋','宋诗','song-poetry','','[]','高高碧蓋擁紅衣，拍拍方塘漾渺瀰。',32,'全唐诗/poet.song.153000.json','["高高碧蓋擁紅衣，拍拍方塘漾渺瀰。", "前竹後松相映带，香風何自透禪扉。"]'),
('3f1e7cbc-2506-445b-9856-16c15e2068fd','次韻方叔媚川圖亭上觀芙蓉','許及之','宋','宋诗','song-poetry','','[]','篩霞擘錦炫晴空，碧玉芙蓉晚更紅。',32,'全唐诗/poet.song.153000.json','["篩霞擘錦炫晴空，碧玉芙蓉晚更紅。", "只道商秋爲素景，也教春色艷秋風。"]'),
