('79fa7954-0c38-49a3-ae63-cda16ae85aad','次韻周畏知用南軒聞說城東梅十里句爲韻六言七首  其一','許及之','宋','宋诗','song-poetry','','[]','湘西山亦既見，城東梅所未聞。',28,'全唐诗/poet.song.153000.json','["湘西山亦既見，城東梅所未聞。", "急須盍簪共賞，可惜委地餘芬。"]'),
('486c1e67-f2c4-45ec-ae34-2061fadb820c','次韻周畏知用南軒聞說城東梅十里句爲韻六言七首  其二','許及之','宋','宋诗','song-poetry','','[]','廣平心腸鐵石，姑射肌膚冰雪。',28,'全唐诗/poet.song.153000.json','["廣平心腸鐵石，姑射肌膚冰雪。", "共令索笑求詩，未免嬰情駕說。"]'),
('4dc74f0a-d4b6-4f97-ae11-6c0a2e5f2fbc','次韻周畏知用南軒聞說城東梅十里句爲韻六言七首  其三','許及之','宋','宋诗','song-poetry','','[]','故人馳一枝使，詩翁築五言城。',28,'全唐诗/poet.song.153000.json','["故人馳一枝使，詩翁築五言城。", "須邀從事入幕，休喚孔方作兄。"]'),
('7d547bb3-32e0-4aef-b1bf-d92765412c81','次韻周畏知用南軒聞說城東梅十里句爲韻六言七首  其四','許及之','宋','宋诗','song-poetry','','[]','夢蝶驅除枕上，驚鴻約略牆東。',28,'全唐诗/poet.song.153000.json','["夢蝶驅除枕上，驚鴻約略牆東。", "石裂巖前積雪，角咽城頭曉風。"]'),
('daf07bbe-c53e-493b-94db-4c3b157d4b56','次韻周畏知用南軒聞說城東梅十里句爲韻六言七首  其五','許及之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','意了無東閣興，句不到西湖梅。',28,'全唐诗/poet.song.153000.json','["意了無東閣興，句不到西湖梅。", "非公安得聞此，欲往何其快哉。"]'),
('d907c4c8-e2ca-457d-842b-062c7b0d798c','次韻周畏知用南軒聞說城東梅十里句爲韻六言七首  其六','許及之','宋','宋诗','song-poetry','','[]','松逕晴泥欲乾，茅簷宿雪猶濕。',28,'全唐诗/poet.song.153000.json','["松逕晴泥欲乾，茅簷宿雪猶濕。", "滿枝空懷杜二，夜誦誰德計十。"]'),
('6cc4dee7-8742-4cb1-b6a5-64f439a1e73f','次韻周畏知用南軒聞說城東梅十里句爲韻六言七首  其七','許及之','宋','宋诗','song-poetry','','[]','行歌已聞落梅，寡和猶傳下里。',28,'全唐诗/poet.song.153000.json','["行歌已聞落梅，寡和猶傳下里。", "好步故難卒行，迅雷那及掩耳。"]'),
('08ccca9f-529d-43c0-b590-f44643928138','周畏知遺二毫筆雖舊猶耐書戲作六言奉簡  其一','許及之','宋','宋诗','song-poetry','','[]','我愧不能扛鼎，君安得此如椽。',28,'全唐诗/poet.song.153000.json','["我愧不能扛鼎，君安得此如椽。", "拔羊兔毛以利，較夔蚿足相憐。"]'),
('d0d4e10e-5a52-4f7c-9a8c-297eccfe162c','周畏知遺二毫筆雖舊猶耐書戲作六言奉簡  其二','許及之','宋','宋诗','song-poetry','','[]','不肯羊質欺世，寧作兔園隠居。',28,'全唐诗/poet.song.153000.json','["不肯羊質欺世，寧作兔園隠居。", "令尹雖舊令尹，中書今尚中書。"]'),
('49b421d7-88d3-4093-986b-eab726728ef1','高宗皇帝挽詞  其一','許及之','宋','宋诗','song-poetry','','[]','鼇極恩難報，龍髯恨莫扳。',48,'全唐诗/poet.song.153000.json','["鼇極恩難報，龍髯恨莫扳。", "興平三紀內，壽老九齡間。", "遜德光千古，仁心亙八寰。", "數周將必復，盍看版圖還。"]'),
('6bb56261-6059-4c2c-b614-d616b4f28cfc','高宗皇帝挽詞  其二','許及之','宋','宋诗','song-poetry','','[]','夷夏均哀涕，空同只故仙。',48,'全唐诗/poet.song.153000.json','["夷夏均哀涕，空同只故仙。", "衣冠趍禹穴，雲日慘堯天。", "嗣聖昭誠孝，通喪振古先。", "小臣思罔極，生長中興年。"]'),
('7bd20d2f-6c74-4b8b-b7fe-22327bdb6acf','和韻題繭庵','許及之','宋','宋诗','song-poetry','','[]','榮枯翻覆手，生死出入息。',144,'全唐诗/poet.song.153000.json','["榮枯翻覆手，生死出入息。", "那將有限身，苦作無俚畫。", "譬彼三眠蠶，已足三食力。", "作繭聊自藏，隨化各有適。", "石槨翁固癡，鍤埋兒作劇。", "憶昨辦同穴，物理念終極。", "斸地號繭窩，開徑延友益。", "今聞梅山作，真得曹溪滴。", "袖手將詩壇，忘形規壽宅。", "達觀接前脩，美意非毒腊。", "智愚雖相較，今古歸一識。", "何當訪此老，同爲逆旅客。"]'),
('0339581d-4679-4711-8fb1-ac2aa45c1809','聚螢齋','許及之','宋','宋诗','song-poetry','','[]','書蠹猶堪讀，囊螢亦强觀。',24,'全唐诗/poet.song.153000.json','["書蠹猶堪讀，囊螢亦强觀。", "競辰規後學，繼晷匪油乾。"]'),
('307950fa-be6e-4300-bc37-cff799f46304','竹村','許及之','宋','宋诗','song-poetry','','[]','種竹亦云好，結交當有道。',24,'全唐诗/poet.song.153000.json','["種竹亦云好，結交當有道。", "能邀歲寒伴，同呼酒家保。"]'),
('e3e4c388-d3b5-445c-bb65-aad1370700d1','老婆娑','許及之','宋','宋诗','song-poetry','','[]','不怕沙頭納納行，男兒報國一身輕。',32,'全唐诗/poet.song.153000.json','["不怕沙頭納納行，男兒報國一身輕。", "斬可擬變黄河水，却挽天河洗甲兵。"]'),
('4b9409d7-e51b-4bb7-9763-3c9fc5c7aa57','題景賢堂','許及之','宋','宋诗','song-poetry','','[]','過眼繁華脫絳英，歲寒松柏只青青。',64,'全唐诗/poet.song.153000.json','["過眼繁華脫絳英，歲寒松柏只青青。", "古來何限馳天壤，賢者于今炳日星。", "意在高山知處鄉，訓垂後葉見儀刑。", "此堂應與人無朽，白首韋郎守一經。"]'),
('6649f20f-d3cb-4e13-bae3-0423f932c6ca','詠史','許及之','宋','宋诗','song-poetry','','[]','南漢傾頹宮女亡，風流爭覩一花香。',32,'全唐诗/poet.song.153000.json','["南漢傾頹宮女亡，風流爭覩一花香。", "香名認取素馨字，玉樹瓊花一樣粧。"]'),
('dde8db94-2710-4488-a0b7-5311341c08f4','雨度西興','許及之','宋','宋诗','song-poetry','','[]','身世重逢舜繼堯，諫垣收拾到芻蕘。',64,'全唐诗/poet.song.153000.json','["身世重逢舜繼堯，諫垣收拾到芻蕘。", "若無闕事關愚慮，何有微塵答聖朝。", "卿列驟遷妨駿穎，君恩寬許逐漁樵。", "江神何事風波惡，冒雨錢塘試晚潮。"]'),
('0e0660be-9820-4863-bf3e-451d99abe85c','虜宮闕','許及之','宋','宋诗','song-poetry','','[]','不翦茅茨聖不憂，虜巢宮殿切雲愁。',32,'全唐诗/poet.song.153000.json','["不翦茅茨聖不憂，虜巢宮殿切雲愁。", "小雛似道朝廷小，復作阿房意未休。"]'),
('c3ab9030-5c82-40b9-bc8d-55e7552fec73','虜行移以盱眙爲肝胎','許及之','宋','宋诗','song-poetry','','[]','華風雖染不知裁，將底論思獻納來。',32,'全唐诗/poet.song.153000.json','["華風雖染不知裁，將底論思獻納來。", "杕杜昔曾聞杖社，盱眙今却見肝胎。"]'),
('ddf0bd2f-5da1-46ba-beda-83829c1d40d5','喜德久從人使虜來歸','許及之','宋','宋诗','song-poetry','','[]','詩翁萬里恰歸來，滌面那無一點埃。',64,'全唐诗/poet.song.153000.json','["詩翁萬里恰歸來，滌面那無一點埃。", "生馬闇騎便武事，故京熟覽動詩才。", "別來我已成炊夢，此去君應悟劫灰。", "具說胡危猶假息，可無尊酒沃崔嵬。"]'),
('3d57991c-69e3-4033-9cee-e3dea93b13fc','玉虹洞','許及之','宋','宋诗','song-poetry','','[]','九醖耐留春，檀心嬌未吐。',24,'全唐诗/poet.song.153000.json','["九醖耐留春，檀心嬌未吐。", "須結舞霓技，怕作行雲去。"]'),
('60d46409-7383-43bd-a7b6-9034ede8a5d9','客有自成都來者傳制帥華學尚書年丈巫山詩輒次韻奉寄','許及之','宋','宋诗','song-poetry','','[]','巖壑豈是鐘鼎姿，出處相較黠與癡。',384,'全唐诗/poet.song.153000.json','["巖壑豈是鐘鼎姿，出處相較黠與癡。", "我家淛東山水窟，閒窺壺中日月遲。", "坎蛙固守井底見，鴈蕩斷云天下奇。", "坐想天柱高突兀，便覺穹障排參差。", "歸胡不歸歸未得，吾非故吾吾何之。", "南宦祝融常在眼，北征太行長相隨。", "每欲拓關令混一，其奈意廣憐庸疲。", "故人開府鎮巴蜀，大江揚舲張虹旗。", "紀行先要實古錦，及境始事蹇赤帷。", "陽侯似知公得句，吳榜婁舞下折枝。", "有客傳誦巫山高，長安那復紙價低。", "襄王胡爲愛文賦，宋玉大以供戲嬉。", "山川本以靈雨祀，神明何及褻凟爲。", "牽牛織女謗自古，小姑彭郎訛一時。", "剩喜新篇有如此，洗空遺恨從今茲。", "蜀道誰云在天上，政譽已逐詩聲馳。", "世情嚮背南北阮，人物妍醜東西施。", "願君滄溟恢宇量，聽披缾罌居井湄。", "已爲下戶代輸額，更要全蜀俱伸眉。", "西都父老久延頸，關外士卒寬張頤。", "訪尋恐有玄尚白，流落寧無素染緇。", "規模所至欣濟濟，民俗定自臻嘻嘻。", "政成化洽公何疑，無人風月鎸峨嵋。", "歸來要著浯溪頌，吾上中和宣布詩。"]'),
('f53e2925-d8f6-43b9-8241-50ab9b7de145','湯婆子','許及之','宋','宋诗','song-poetry','','[]','一冬專寵道人房，不藉華清賜浴湯。',64,'全唐诗/poet.song.153000.json','["一冬專寵道人房，不藉華清賜浴湯。", "皤腹却無璋瓦分，矮身難稱綺羅妝。", "春生蝴蝶半牀夢，暖逼梅花一帳香。", "醉倚肉屏君莫羨，北邙多少黑頭郎。"]'),
('4934959e-cc94-4073-9b45-28dc6eb92a9f','廢冢','許及之','宋','宋诗','song-poetry','','[]','石人猶自立蒿萊，拂讀殘碑字字哀。',32,'全唐诗/poet.song.153000.json','["石人猶自立蒿萊，拂讀殘碑字字哀。", "鄰冢已澆寒食酒，野風分送紙錢來。"]'),
('a2382fee-193e-4c08-a0ee-ce4527a9d39c','句','百七丈','宋','宋诗','song-poetry','','[]','盡道溫柔別有鄉，誰知絳闕水茫茫。',16,'全唐诗/poet.song.153000.json','["盡道溫柔別有鄉，誰知絳闕水茫茫。"]'),
('12f73f64-579d-400b-83df-7b6fd5c2e7aa','晚步南城下','張良臣','宋','宋诗','song-poetry','','[]','冷雲堆屋晚仍春，惘惘人行陌上昏。',32,'全唐诗/poet.song.153000.json','["冷雲堆屋晚仍春，惘惘人行陌上昏。", "飛去飛來沙上雁，去年洲渚舊蘆根。"]'),
('a41cdca9-2883-43d7-99b8-e25bc19a18a5','春詞  其一','張良臣','宋','宋诗','song-poetry','','[]','竚蘭無限楚時春，罨岸風平綠自熏。',32,'全唐诗/poet.song.153000.json','["竚蘭無限楚時春，罨岸風平綠自熏。", "睡起畫簷雙語燕，梨花留得夜來雲。"]'),
('de818c50-06df-4bde-906c-6c5412de0521','春詞  其二','張良臣','宋','宋诗','song-poetry','','[]','後主搴香復倚春，潘嬙梳洗最輕盈。',32,'全唐诗/poet.song.153000.json','["後主搴香復倚春，潘嬙梳洗最輕盈。", "南朝破後無詞客，燕子桃花古石城。"]'),
('8287cd50-3792-4ba1-92ca-ddde13af8ba9','芳草復芳草','張良臣','宋','宋诗','song-poetry','','[]','芳草復芳草，有人孤倚樓。',52,'全唐诗/poet.song.153000.json','["芳草復芳草，有人孤倚樓。", "明月復明月，何處照離洲。", "相見渺無期，此恨詎相知。", "日暮天寒吹屬玉，蠻江豆蔻重重綠。"]'),
('98aa3dce-b405-4815-ad12-b2cf8b03e957','玉臺體  其一','張良臣','宋','宋诗','song-poetry','','[]','一寸春霏拂綺寮，蕙花江上雪初銷。',32,'全唐诗/poet.song.153000.json','["一寸春霏拂綺寮，蕙花江上雪初銷。", "傷心燕子重來地，無復人吹紫玉簫。"]'),
('7c6ee899-002b-4632-9224-e9b5a8c29889','玉臺體  其二','張良臣','宋','宋诗','song-poetry','','[]','主人流落委荒墳，燕子還來壞㦸門。',32,'全唐诗/poet.song.153000.json','["主人流落委荒墳，燕子還來壞㦸門。", "惟有桃花古時月，端端正正照啼痕。"]'),
('62c1ab2e-5b18-4d99-9d55-1e60dcad98e8','曉行','張良臣','宋','宋诗','song-poetry','','[]','千山萬山星斗落，一聲兩聲鐘磬清。',32,'全唐诗/poet.song.153000.json','["千山萬山星斗落，一聲兩聲鐘磬清。", "路入小橋和夢過，豆花深處草蟲鳴。"]'),
('ed773916-b542-4164-9882-ea6d42124054','陪天童覺禪師如城','張良臣','宋','宋诗','song-poetry','','[]','風勒江雲雪未勻，夢寒不到碧梅春。',32,'全唐诗/poet.song.153000.json','["風勒江雲雪未勻，夢寒不到碧梅春。", "破帆又指蕪城近，漠漠平沙落雁頻。"]'),
('b6e20494-e359-48ba-954e-8ad0e22587af','賦','張良臣','宋','宋诗','song-poetry','','[]','柳暗旗亭不忍看，臨江愁殺晉衣冠。',32,'全唐诗/poet.song.153000.json','["柳暗旗亭不忍看，臨江愁殺晉衣冠。", "傷心明月揚州路，十里珠簾蕙草寒。"]'),
('4e134f5e-0e2e-49ad-9007-fab2200bdfd1','示長蘆仁禪師','張良臣','宋','宋诗','song-poetry','','[]','叢叢竹雀閙人家，農事春來漸有涯。',32,'全唐诗/poet.song.153000.json','["叢叢竹雀閙人家，農事春來漸有涯。", "品字柴頭煨政暖，不知風雪到梅花。"]'),
('cddaae72-ba19-446f-90f3-2c534243ebad','別持上人','張良臣','宋','宋诗','song-poetry','','[]','茂竹永和字，浣花天寶詩。',24,'全唐诗/poet.song.153000.json','["茂竹永和字，浣花天寶詩。", "清江入舟楫，忍淚別僧持。"]'),
('338c438c-cfa8-4f74-bed4-078b47c357df','梅市道中','張良臣','宋','宋诗','song-poetry','','[]','連雨疏篷不耐關，脩眉如失更晴慳。',32,'全唐诗/poet.song.153000.json','["連雨疏篷不耐關，脩眉如失更晴慳。", "越王故國無人問，艇子穿花自往還。"]'),
('a3f9713b-34c3-4b29-92dd-a39a6be35e14','有懷山房','張良臣','宋','宋诗','song-poetry','','[]','每憶山房話夜深，几前無主亦無賓。',32,'全唐诗/poet.song.153000.json','["每憶山房話夜深，几前無主亦無賓。", "老兵未領西來意，斜倚屏風一欠伸。"]'),
('9f2621ac-252e-4a84-a322-32f6bb321993','西湖晚歸','張良臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帖帖平湖印晚天，踏歌遊女錦相牽。',32,'全唐诗/poet.song.153000.json','["帖帖平湖印晚天，踏歌遊女錦相牽。", "鳳城半掩人爭路，猶有胡琴落後船。"]'),
('6a46734d-ed4e-4a87-b398-f28a115457cc','書情奉寄蔣弋陽公  其一','張良臣','宋','宋诗','song-poetry','','[]','五都一何綺，歌管政繁會。',48,'全唐诗/poet.song.153000.json','["五都一何綺，歌管政繁會。", "睠我友明月，援琴寫秋瀨。", "何言昃離後，一飽困藜稗。", "風雨墨如翳，欲往徒自礙。"]'),
('92abbfb2-796d-4c0a-ba34-ac9efeac3fd8','書情奉寄蔣弋陽公  其二','張良臣','宋','宋诗','song-poetry','','[]','頹年去堂堂，白髮新種種。',48,'全唐诗/poet.song.153000.json','["頹年去堂堂，白髮新種種。", "崎嶇造化久，敗屨常决踵。", "從來萬里意，不料乘嶮恐。", "鳴鶴略九皋，未羨乘軒寵。"]'),
('2c000586-ee7a-4444-83e2-2231fd356cd0','留題吳興投老庵','張良臣','宋','宋诗','song-poetry','','[]','白鷺悠悠去不還，渚雲汀草一生閑。',32,'全唐诗/poet.song.153000.json','["白鷺悠悠去不還，渚雲汀草一生閑。", "暮年不入西州路，空倚梅花說住山。"]'),
('983089a0-ef94-466d-b18f-bb44bba66aaf','送人遊姑蘇','張良臣','宋','宋诗','song-poetry','','[]','兒時吾亦寄君州，細細聽君說舊遊。',32,'全唐诗/poet.song.153000.json','["兒時吾亦寄君州，細細聽君說舊遊。", "處處綠波通酒巷，女郎多在採菱舟。"]'),
('1d4c82bc-cd65-4d28-a2be-c0fab2d99c20','雪後','張良臣','宋','宋诗','song-poetry','','[]','雪花竹屋未全消，寒雀梢頭眼擘椒。',32,'全唐诗/poet.song.153000.json','["雪花竹屋未全消，寒雀梢頭眼擘椒。", "紙閤不烟梅自放，底能踏濕渡溪橋。"]'),
('cdaf86e0-6e8b-4ead-b15a-56d2a59463bb','九日書呂季慈室','張良臣','宋','宋诗','song-poetry','','[]','上池入寺見承平，影落南州迹易陳。',32,'全唐诗/poet.song.153000.json','["上池入寺見承平，影落南州迹易陳。", "手把黄花看新雁，風烟愁殺舊京人。"]'),
('19b896fb-23b1-463e-928a-db8e169ed63d','感舊','張良臣','宋','宋诗','song-poetry','','[]','三十六陂春水綠，四十九年人事非。',32,'全唐诗/poet.song.153000.json','["三十六陂春水綠，四十九年人事非。", "楊子江頭永嘉後，吳儂蕩槳北人稀。"]'),
('0fea77a2-6e9d-44de-933d-3a5473ccfd9d','山房惠貓','張良臣','宋','宋诗','song-poetry','','[]','從來憐汝丈人烏，端正銜蟬雪不如。',32,'全唐诗/poet.song.153000.json','["從來憐汝丈人烏，端正銜蟬雪不如。", "江海歸來聲繞膝，定知分訴食無魚。"]'),
('33f736b3-0101-4e5f-81c1-9621c95e8e49','過臨平','張良臣','宋','宋诗','song-poetry','','[]','兒時曾憶此登臨，細說窮途有述征。',32,'全唐诗/poet.song.153000.json','["兒時曾憶此登臨，細說窮途有述征。", "四十九年蘧伯玉，月明人靜過臨平。"]'),
('45011357-b7cc-4e85-8e70-ec81c7038fea','過西溪','張良臣','宋','宋诗','song-poetry','','[]','罨畫層波蕙草荒，冷雲客雁兩回皇。',32,'全唐诗/poet.song.153000.json','["罨畫層波蕙草荒，冷雲客雁兩回皇。", "梅花到得吹成雪，盡是清愁不是香。"]'),
('716204bf-fbf0-4321-b572-5a7d0a0a1070','贈英上人','張良臣','宋','宋诗','song-poetry','','[]','之秦剩肯迎張祿，踏越何曾用計然。',32,'全唐诗/poet.song.153000.json','["之秦剩肯迎張祿，踏越何曾用計然。", "元鼎事看蛙勝負，大槐人與蟻相連。"]'),
('ea5daf1c-e4fc-4ae4-9d6d-d8cb4591bfcb','酒熟','張良臣','宋','宋诗','song-poetry','','[]','濁醪初熟薦霜螯，不擬寒山不廣騷。',32,'全唐诗/poet.song.153000.json','["濁醪初熟薦霜螯，不擬寒山不廣騷。", "清曉豆花籬下立，竹梢獨與月爭高。"]'),
('0f0765dd-bb07-4ea4-befe-532a27d313c3','遣家書','張良臣','宋','宋诗','song-poetry','','[]','家住鄱城小洞天，經年烹鯉尚茫然。',32,'全唐诗/poet.song.153000.json','["家住鄱城小洞天，經年烹鯉尚茫然。", "幾回鵲喜無消息，吹殺燈花獨自眠。"]'),
('2aa95ed2-c64e-4c2c-af6e-3c370ae12c4f','祝貓','張良臣','宋','宋诗','song-poetry','','[]','江上孤篷雪壓時，每懷寒夜暖相依。',32,'全唐诗/poet.song.153000.json','["江上孤篷雪壓時，每懷寒夜暖相依。", "從今休慣穿籬落，取次懷春屢不歸。"]'),
('38d70ad0-9baa-4788-9801-2f4fc91afb3e','偶題','張良臣','宋','宋诗','song-poetry','','[]','誰家池館靜蕭蕭，斜倚朱門不敢敲。',32,'全唐诗/poet.song.153000.json','["誰家池館靜蕭蕭，斜倚朱門不敢敲。", "一段好春藏不盡，粉牆斜露杏花梢。"]'),
('c9ddee48-1711-41a1-b0df-62f913f65b2b','萱草','張良臣','宋','宋诗','song-poetry','','[]','雪色侵凌綠剪芽，枝抽寒玉带金葩。',32,'全唐诗/poet.song.153000.json','["雪色侵凌綠剪芽，枝抽寒玉带金葩。", "北堂回首傷心處，却復令人恨此花。"]'),
('d79c034e-d1b7-4ee0-b4d1-ac960e34e380','小破','張良臣','宋','宋诗','song-poetry','','[]','小破燕支鈿早梅，雪雲平澹越江遲。',32,'全唐诗/poet.song.153000.json','["小破燕支鈿早梅，雪雲平澹越江遲。", "青山歲夜行人少，鴨鴨羣飛淺草時。"]'),
('7b0b1121-8f93-4c03-92af-72e771fbe436','謝汪尚書見訪','張良臣','宋','宋诗','song-poetry','','[]','黄葉聲中接錦韉，添丁籬落怪相牽。',32,'全唐诗/poet.song.153000.json','["黄葉聲中接錦韉，添丁籬落怪相牽。", "歸來剩欲從僧話，正掩楞伽曝背眠。"]'),
('0b7fa683-32f7-494b-8258-136b382dd591','夏夜','張良臣','宋','宋诗','song-poetry','','[]','恰則黄昏雨便晴，青塘迤邐盡蛙鳴。',32,'全唐诗/poet.song.153000.json','["恰則黄昏雨便晴，青塘迤邐盡蛙鳴。", "月明已在芭蕉上，猶有殘簷點滴聲。"]'),
('31a2c943-a4e3-49c7-824f-1d34b9d58d4c','平旦','張良臣','宋','宋诗','song-poetry','','[]','平旦梅花破冷紅，越香何限水流東。',32,'全唐诗/poet.song.153000.json','["平旦梅花破冷紅，越香何限水流東。", "陳年翠袖新年恨，盡在吹香笑語中。"]'),
('50214ee7-677a-4135-a912-cae735f62da1','清修嶺','張良臣','宋','宋诗','song-poetry','','[]','喪膽巖上人，怖死巖下人。',48,'全唐诗/poet.song.153000.json','["喪膽巖上人，怖死巖下人。", "周道自砥直，何枉不問津。", "人生貴適意，毋容矯吾真。", "淵明兀餘年，漉酒乃一巾。"]'),
('5487b0fd-f32b-4b2f-a070-1e6b0ddf7931','長松丹井','張良臣','宋','宋诗','song-poetry','','[]','九轉丹砂煉得成，飄飄仙袂入青冥。',32,'全唐诗/poet.song.153000.json','["九轉丹砂煉得成，飄飄仙袂入青冥。", "一泓寒水留真汞，千歲長松産茯苓。"]'),
('2c9eb4e6-e384-4c92-b81a-d6bba4cc1aed','留雲門山中','張良臣','宋','宋诗','song-poetry','','[]','僑裝結束燦花衣，採藿蘭娘釂翠卮。',64,'全唐诗/poet.song.153000.json','["僑裝結束燦花衣，採藿蘭娘釂翠卮。", "三五二八月皎皎，東西南北草離離。", "非君之故豈妄集，對酒不狂無乃癡。", "口住山閒省前夢，而今不似洛陽時。"]'),
('326ed86b-ea14-4dfd-b90c-a9d99b815136','上雪竇山奉慈院','張良臣','宋','宋诗','song-poetry','','[]','迢迢嶺外雪雲明，猶憶塵中見偉人。',32,'全唐诗/poet.song.153000.json','["迢迢嶺外雪雲明，猶憶塵中見偉人。", "沙上豈無新到雁，附來莫厭尺書頻。"]'),
('09e87454-9a49-4dd5-9cb9-41b10c0cf6fd','次韻持上人題延慶寺清玉軒','張良臣','宋','宋诗','song-poetry','','[]','水芳未動城南路，一一僧簷有竹看。',64,'全唐诗/poet.song.153000.json','["水芳未動城南路，一一僧簷有竹看。", "政爾塵埃能自表，故應悠久澹相安。", "長楊曉獵干戈肅，古棘春朝萬玉寒。", "碧眼阿師來授記，化龍飛去抑何難。"]'),
('7608cafc-edab-4944-bb97-d097dcc1c6f5','老子像','張良臣','宋','宋诗','song-poetry','','[]','函谷關頭紫氣濃，獨教關尹喜相逢。',32,'全唐诗/poet.song.153000.json','["函谷關頭紫氣濃，獨教關尹喜相逢。", "如何道德五千字，不載周家藏室中。"]'),
('2a5c71e7-1452-4543-b462-f4ec4bd11f50','句  其一','張良臣','宋','宋诗','song-poetry','','[]','願同丑萬輩，終老孟子門。',12,'全唐诗/poet.song.153000.json','["願同丑萬輩，終老孟子門。"]'),
('a28212e5-1bb6-4053-bc20-c7ca520f2e3d','句  其二','張良臣','宋','宋诗','song-poetry','','[]','客向愁中都老盡，祇留平楚伴銷凝。',16,'全唐诗/poet.song.153000.json','["客向愁中都老盡，祇留平楚伴銷凝。"]'),
('82d025f2-ad4f-4ef5-801f-0906f4ddf9e5','句  其三','張良臣','宋','宋诗','song-poetry','','[]','流落荒郊道轉孤。',8,'全唐诗/poet.song.153000.json','["流落荒郊道轉孤。"]'),
('98507222-f055-4e16-af35-2299097f173e','句  其四','張良臣','宋','宋诗','song-poetry','','[]','老去青林又一霜。',8,'全唐诗/poet.song.153000.json','["老去青林又一霜。"]'),
('651dee49-3e52-4669-821a-e8f73fe01c6e','句  其五','張良臣','宋','宋诗','song-poetry','','[]','秦南燕北見君難。',8,'全唐诗/poet.song.153000.json','["秦南燕北見君難。"]'),
('f7b9252a-af39-441e-864f-ea6230dfc798','句  其六','張良臣','宋','宋诗','song-poetry','','[]','指似鳳城煙月路。',8,'全唐诗/poet.song.153000.json','["指似鳳城煙月路。"]'),
('a324a1c9-c626-4917-a2da-444fd8b92e5b','句  其七','張良臣','宋','宋诗','song-poetry','','[]','空掩玉樓先睡去。',8,'全唐诗/poet.song.153000.json','["空掩玉樓先睡去。"]'),
('3bd3922a-0d30-4c81-98c5-51314ab8d8e0','句  其八','張良臣','宋','宋诗','song-poetry','','[]','腸斷江南一百五。',8,'全唐诗/poet.song.153000.json','["腸斷江南一百五。"]'),
('d9786708-e668-40d9-9bd7-9569a9f16449','句  其九','張良臣','宋','宋诗','song-poetry','','[]','先到王城第一橋。',8,'全唐诗/poet.song.153000.json','["先到王城第一橋。"]'),
('363d7740-3ed1-41e7-81b5-f97b1eec0619','句  其一○','張良臣','宋','宋诗','song-poetry','','[]','長干白下相逢少。',8,'全唐诗/poet.song.153000.json','["長干白下相逢少。"]'),
('c31d4d1b-de18-448e-915c-537459a1d3bd','句  其一一','張良臣','宋','宋诗','song-poetry','','[]','客子摇船繞畫圖。',8,'全唐诗/poet.song.153000.json','["客子摇船繞畫圖。"]'),
('96a9d028-e44b-44f9-9952-f06752099de6','暇日邀王天任諸公遊南坡天任有詩因次韻  其一','虞儔','宋','宋诗','song-poetry','','[]','梅黄收宿雨，山綠呈層巔。',192,'全唐诗/poet.song.153000.json','["梅黄收宿雨，山綠呈層巔。", "高軒蔭修竹，朱檻俯流泉。", "雅致軼天外，俗物無眼前。", "笑人聲利場，蛾眉競爭妍。", "半生政坐拙，州縣空迴旋。", "自視甘寂寞，何心慕華鮮。", "南坡吾菟裘，杖履有厚緣。", "暇日領佳客，頗辦沽酒錢。", "愧無絲與竹，後堂欠彭宣。", "何以侑談笑，頼有茲山川。", "送鴻煩遠目，落鴈驚虛弦。", "門徑迴俗駕，山澤非臞仙。", "劇談交玉麈，醉吟飛彩牋。", "榴花媚紅皺，李實薦翠圓。", "相忘恣諧謔，小謹畧跽拳。", "茲遊無可紀，須君賦長篇。"]'),
('5bbc25ac-951c-4f10-8019-f3c2aab7b566','暇日邀王天任諸公遊南坡天任有詩因次韻  其二','虞儔','宋','宋诗','song-poetry','','[]','我詩苦艱澁，蹇步太行巔。',192,'全唐诗/poet.song.153000.json','["我詩苦艱澁，蹇步太行巔。", "筆乾硯欲裂，何地覓湧泉。", "巧匠愧傍觀，袖手不能前。", "敝帚徒自珍，捧心豈成妍。", "辟舍不獲命，屬鞬試周旋。", "君詩巧層出，浥露晨花鮮。", "前輩借波瀾，後生敢並緣。", "平生程不識，毀不直一錢。", "五色爛摩尼，八音和相宣。", "挹袂庾開府，拍肩楊盈川。", "每發必中的，矢脫無空弦。", "我蓋三復之，飄飄意欲仙。", "此計太冷淡，浪費五彩牋。", "不如醉紅裙，且聽歌喉圓。", "况當荷傾蓋，莫待栗過拳。", "徐看騎鯨伯，一斗揮百篇。"]'),
('24ed0c86-7a27-45e3-9d94-863a9ffe6d9d','暇日邀王天任諸公遊南坡天任有詩因次韻  其三','虞儔','宋','宋诗','song-poetry','','[]','雨驟頻垂脚，山高故隠巔。',192,'全唐诗/poet.song.153000.json','["雨驟頻垂脚，山高故隠巔。", "南坡疑斷路，平地怪流泉。", "猿鶴誰爲伴，鳬鴻亦墮前。", "梅黄雖借潤，榴火漫呈妍。", "人世隙駒過，天形磨蟻旋。", "雲容愁暮合，霞彩望朝鮮。", "已負杖藜約，宜修香火緣。", "江山如得助，風月敢論錢。", "今日苦不樂，此情誰與宣。", "高歌懷杜曲，晚賦擬樊川。", "屋破時懸溜，弓驚不受弦。", "好邀沽酒伴，却羨泛舟仙。", "竹色杯中綠，花光筆下牋。", "左持還有蟹，右畫更成圓。", "自笑牛刀割，難安鷄肋拳。", "補天非我事，聊爾繼新篇。"]'),
('c7fc1ee3-5fce-4341-989c-2207d652ef6f','暇日邀王天任諸公遊南坡天任有詩因次韻  其四','虞儔','宋','宋诗','song-poetry','','[]','君家有西園，望我南山巔。',192,'全唐诗/poet.song.153000.json','["君家有西園，望我南山巔。", "觴詠繼曲水，花石希平泉。", "長溝流砌下，遠岫列楹前。", "春風一披拂，百卉爲渠妍。", "迨茲夏日永，杖履宜盤旋。", "梅黄已過雨，清潤霽景鮮。", "主人雖好事，欲往無由緣。", "似聞三徑深，日夜長苔錢。", "行當載酒過，高情與君宣。", "飛鴻渺天末，浴鷺來平川。", "良辰恐易失，勿待月下弦。", "前者坐中看，俱是桂堂仙。", "酒豪倒金壺，詩健輕華牋。", "琴弄朱弦古，碁枰寒玉圓。", "君才尤中的，霜鶻無空拳。", "諄復記幽會，舂容看大篇。"]'),
('936cbd05-2f3f-4c72-8dc5-6f3a9dbbdaa4','和姜總管喜民間種麥','虞儔','宋','宋诗','song-poetry','','[]','腰鐮刈晚禾，荷鋤種新麥。',84,'全唐诗/poet.song.153000.json','["腰鐮刈晚禾，荷鋤種新麥。", "田家競作苦，羔豚勞歲夕。", "翠浪愜初懷，黄雲期後穫。", "晴暖得天時，肥瘠隨地力。", "賸欲觀風謠，未暇履阡陌。", "寧唯餠餌香，庶免鞭笞責。", "擬踏青州麴，釀酒邀佳客。"]'),
('b6cb91f3-d086-4ab9-8f09-632488b60d64','病起據案無緒輒書二十五韻呈簿尉','虞儔','宋','宋诗','song-poetry','','[]','祇役來異鄉，瘧鬼巧伺便。',288,'全唐诗/poet.song.153000.json','["祇役來異鄉，瘧鬼巧伺便。", "寒熱四五行，大小六七戰。", "初如蹈陰壑，赤身卧冰霰。", "繼若煽紅爐，虐焰工煆鍊。", "先生但堅壁，高卧觀物變。", "謂我則忘吾，曰舍其猶傳。", "童子更進藥，先生强起嚥。", "羣鬼競揶揄，醫工何瞑眩。", "忽然汗四出，心愧顔有靦。", "須臾返清凉，輕健欲舞抃。", "寧唯疏枕簟，便覺美肴膳。", "氣和疾自去，福至禍亦轉。", "我生多蹇剝，縣尹劇卑賤。", "王事有期程，私室敢安宴。", "日出事還生，孤游無一援。", "訟牒猶山積，愚拙費裁剸。", "催科正火急，日夕竢訶譴。", "督郵顧小忍，斗米那可戀。", "彈琴不復夢，據案敢告倦。", "仇梅二友生，灑落邦之彥。", "頗復相料理，何嘗語遊衍。", "城南萬荷花，浣溪錦一片。", "凉生雨初過，香度風微扇。", "碧筩亦易辦，白墮儻可薦。"]'),
('15c297f4-41e2-4a76-9af3-a648d2181fcf','除日獄空唯欠租監繫頗衆因悉縱遣之期以開歲五日畢來因記東坡先生倅杭除夜直都廳囚繫皆滿題詩壁間輒用其韻','虞儔','宋','宋诗','song-poetry','','[]','訟牒日已稀，私幸庭無留。',72,'全唐诗/poet.song.153000.json','["訟牒日已稀，私幸庭無留。", "胡不了租稅，顧爲此拘囚。", "催科迫星火，對案亦包羞。", "作苦念田家，歲莫得少休。", "羔酒會鄰里，盍歸與婦謀。", "刻期亦人耳，吾其反自修。"]'),
('333cf59c-d9fb-4800-85b3-c8355fd24d6a','病後有感作','虞儔','宋','宋诗','song-poetry','','[]','今旦病思清，把書坐晴簷。',204,'全唐诗/poet.song.153000.json','["今旦病思清，把書坐晴簷。", "體舒百息勻，心遠萬慮恬。", "收視等庖郢，妙觀到羲炎。", "頓忘饑寒苦，但覺中邊甜。", "習氣尚稍稍，自喜良沾沾。", "故家東堂書，高架紛懸籤。", "我時且兒子，氣欲俱并兼。", "澆著胸次間，政爾意不廉。", "此意竟蹉跎，衰遲侵戟髯。", "邇來又留滯，鬰鬰三年淹。", "是秋節物高，露白原草霑。", "斜河轉空闊，夜氣方森嚴。", "此日足可惜，黄塵滿征襜。", "明年會當歸，赤米薦白鹽。", "繙經慰老眼，甘作書蠹潜。", "共嘲玄尚白，指笑突不黔。", "亦知屠沽兒，羔豚方屬饜。"]'),
('6228c8e3-81a0-4c50-b47e-03bd3af791f6','和張伯子韻','虞儔','宋','宋诗','song-poetry','','[]','士流競彈冠，州牧紛勸駕。',120,'全唐诗/poet.song.153000.json','["士流競彈冠，州牧紛勸駕。", "器識在所先，文藝乃其亞。", "朅來同抱關，因得奉餘暇。", "軟語雜嘲謔，小酌見藴藉。", "官禁不通風，門鍵那容罅。", "豹斑縱未窺，鯨背幾思跨。", "君來怪已三，我到嗟方乍。", "前頭萬木春，當戶三星夜。", "棄甲勿復來，背城寧一借。", "新詩抵驪珠，歸橐何妨詫。"]'),
('9fd7bb82-de1f-48f3-8539-2110a7453680','詠麥','虞儔','宋','宋诗','song-poetry','','[]','平生笑盜儒，口誦青青麥。',84,'全唐诗/poet.song.153000.json','["平生笑盜儒，口誦青青麥。", "刻燭和新詩，此夕知何夕。", "六花來未晚，三白會有穫。", "雨暘亦天事，勤惰繄人力。", "何妨縱牛羊，况已遍隴陌。", "青黄未交時，補助豈無責。", "我亦念歸田，聊作數旬客。"]'),
('e723ab2d-e818-4d3b-8abc-8a36009e0e38','和姜總管送別','虞儔','宋','宋诗','song-poetry','','[]','富貴如浮雲，于我初何有。',252,'全唐诗/poet.song.153000.json','["富貴如浮雲，于我初何有。", "轉徙浙東西，僅足餬其口。", "去年在吳興，民物猶未阜。", "賑荒事方殷，奚暇詩與酒。", "今年到東陽，政成不待久。", "邂逅遇詩仙，襟抱得細剖。", "切磋愧子貢，起予幸魯叟。", "琮琤蒼玉佩，關鍵黄金鈕。", "擬學西子顰，益愧鄰女醜。", "賡酬强追逐，要是非敵手。", "目短曹劉牆，氣轢鮑謝囿。", "我如武成策，第可二三取。", "山澤多蛇龍，松柏無培塿。", "緬懷南澗老，斯人骨已朽。", "人事真好乖，又假蘇臺守。", "遽辭山水邦，暫缺雲龍耦。", "酒罷雨沾裾，船開山入牖。", "似鶴出樊籠，如魚脫窠臼。", "分袂却關情，鼓棹猶回首。", "長篇肯贈我，字字炳星斗。", "願保歲寒心，莫愧金石友。"]'),
('34acbd51-96af-4d92-94d9-85755b3ce636','和寧國守沈察院九月嚴霜十五韻','虞儔','宋','宋诗','song-poetry','','[]','九月十月交，卦應西北乾。',180,'全唐诗/poet.song.153000.json','["九月十月交，卦應西北乾。", "少昊猶執矩，玄冥遽行權。", "慶元敦牂歲，夏無雨暘愆。", "早禾既有秋，人斯望有年。", "晚稻亦懷新，穎實相接連。", "不間東南畝，寧分左右肩。", "嚴霜忽早降，節候無餘暄。", "黄熟乃無日，青乾空在田。", "殆不如稊稗，那敢詠好堅。", "造物豈棄遺，繄時失後先。", "農夫亟欲訴，有司不謂然。", "課無責之有，何異扼其咽。", "使君惻興念，官租爲渠蠲。", "作詩寬彼憂，至哉仁人言。", "幸甚宣城民，信乎有二天。"]'),
('43df2e0a-1ea9-4b0e-9715-9ce6510acb4e','冬至念母','虞儔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','兒行十里程，母心千里逐。',132,'全唐诗/poet.song.153000.json','["兒行十里程，母心千里逐。", "昔者子曾子，不忍離一宿。", "今我獨何爲，旅食久輦轂。", "來時月中秋，坐待陽初復。", "薄命難推挽，闊步窘邊幅。", "慰藉煩友朋，栖遲愧僮僕。", "畫餠唐生相，說河嚴子卜。", "世態方奔競，人情慮反覆。", "夫豈不懷歸，所惡在欲速。", "眉壽翠濤春，洞庭霜橘熟。", "亦足盡親歡，何必此微祿。"]'),
('8e6c40f5-561b-4fe5-b607-f572e7b8460f','秋日同官遊聖感寺晚飲范公亭分韻得須對二字  其一','虞儔','宋','宋诗','song-poetry','','[]','招提城東隅，勝集僚友俱。',72,'全唐诗/poet.song.153000.json','["招提城東隅，勝集僚友俱。", "腐儒元自臞，午飯厄齋盂。", "不如計一醉，况有高陽徒。", "小秋頗解事，鷄鶩營庖厨。", "我歸與婦謀，但問酒有無。", "婦言有斗酒，待子不時須。"]'),
('97a354d6-410e-42b6-9385-b00ae38161a9','秋日同官遊聖感寺晚飲范公亭分韻得須對二字  其二','虞儔','宋','宋诗','song-poetry','','[]','木末好風來，山頭凉月朏。',72,'全唐诗/poet.song.153000.json','["木末好風來，山頭凉月朏。", "快哉城上亭，登臨吾亦再。", "堂堂文正公，精神凜猶在。", "盃行且停飲，四座俱起酹。", "義氣激余衷，豁若挹沆瀣。", "此夕飲也清，且無俗子對。"]'),
('b26fa495-9a5f-4835-9112-4d0306758c5a','次早再出','虞儔','宋','宋诗','song-poetry','','[]','晨起候鷄鳴，我車催發軔。',72,'全唐诗/poet.song.153000.json','["晨起候鷄鳴，我車催發軔。", "列炬犯星微，衣襟蒙霧潤。", "將迎恐後期，奔走追前進。", "拭面愧緇塵，墊巾憐雪鬢。", "吾年已如此，世態何當徇。", "曷不歸去來，榮枯才一瞬。"]'),
('d8cfc4d1-8821-4f9c-904d-a188c9982e0b','秋雨歡','虞儔','宋','宋诗','song-poetry','','[]','少昊欲行秋，驕陽猶跋扈。',168,'全唐诗/poet.song.153000.json','["少昊欲行秋，驕陽猶跋扈。", "炎蒸不易滌，頗費天公雨。", "浸淫三日霖，雲氣政旁午。", "所慮早禾傷，佳實卧場圃。", "翻思向來旱，南畝生塵土。", "矯首望雲霓，一滴如膏乳。", "及茲收斂際，反以多爲苦。", "蒼蒼匪天歟，惻怛羣物祖。", "怨咨尚未免，是非何所付。", "會當返秋陽，新晴照區宇。", "禾實趁登場，不特盈我庾。", "荷擔赬肩歸，亦足慰田父。", "黄鷄能漸肥，紅酒幸可酤。", "持用答豐年，造物儻復許。"]'),
('4eb87c13-67ab-4270-be8b-d2e1b2e79e97','和張文潜有所嘆韻','虞儔','宋','宋诗','song-poetry','','[]','老驥困鹽車，四足若有絆。',96,'全唐诗/poet.song.153000.json','["老驥困鹽車，四足若有絆。", "鶑鳩搶榆枋，控地不能遠。", "我本田家子，釋耒事游宦。", "少壯耻干請，老大誰推挽。", "撫字亦徒勞，催科寧趣辦。", "於心儻無愧，此首何妨俛。", "財由政事足，軻也豈好辯。", "苟得而富貴，孰若甘貧賤。"]'),
('ce39cc38-5cbb-4f66-b027-e57200abb593','和陳倅留題奉聖','虞儔','宋','宋诗','song-poetry','','[]','飛鴻渺天末，目送類中散。',216,'全唐诗/poet.song.153000.json','["飛鴻渺天末，目送類中散。", "謫仙負詩狂，直欲摘星漢。", "白雲千丈峯，金碧美且煥。", "忘言老瞿曇，祇作空花觀。", "軒冕儻來耳，世事亦其漫。", "鸞鳳在赤霄，寧肯就紲絆。", "惟餘憂國心，撫事輒悲怨。", "饑饉有流離，十室九不爨。", "上動黄屋念，每日不遑旰。", "公豈愛登覽，微意寓篇翰。", "山僧遽傳似，字字如珠貫。", "勸分豈無術，未必愧鞭算。", "升斗倘均惠，溝壑庶少逭。", "福星公恐是，疇復虞歲旱。", "王事敢告勞，行役春過半。", "鬢絲禪榻畔，綸巾時一岸。", "溪山得勝賞，歌舞廢屢按。", "請頌海沂康，民謠茲可翫。"]'),
('289e6346-365a-47c6-a0c9-bbd0d2091fcd','和陳倅遊石門弔瞿硎先生','虞儔','宋','宋诗','song-poetry','','[]','我坐南坡上，高鴻忽飛去。',192,'全唐诗/poet.song.153000.json','["我坐南坡上，高鴻忽飛去。", "指點夕陽外，文脊蓋其處。", "下有奇洞府，有道乃宜據。", "鹿裘坐石室，先生豈真踞。", "儻是我輩人，傲視非所慮。", "桓溫汝何爲，乃欲效三顧。", "姦心妄窺鼎，未見神合沮。", "猿鶴亦汝羞，未易飲食舉。", "伏滔不自重，且爲溫所遇。", "贊詞縱云美，所耻非所慕。", "邇來賢別駕，物外欲軒翥。", "功名恐未免，溪山亦已飫。", "五字識巖石，千載想風馭。", "神交付冥漠，心契自平素。", "蒼苔留履跡，飛花約歸路。", "先生還一笑，晴雲爲披絮。"]'),
('fa60566a-bd2e-4280-b3fd-e558aa062085','林子長見示悼鶴之詩若不能釋然者因次韻以廣其意且於鶴不能無責焉耳','虞儔','宋','宋诗','song-poetry','','[]','君家青田姿，見之毛骨寒。',228,'全唐诗/poet.song.153000.json','["君家青田姿，見之毛骨寒。", "方當秋露警，遽迫夏景殘。", "年來縱飲啄，意外失防閑。", "誰歟不具眼，斃之于汝安。", "竹林有餘蔭，荷塘豈不寬。", "正坐出門誤，寧虞行路難。", "因思出處理，士君子惟艱。", "方其窮居時，孤進無還丹。", "山林欲長往，鐘鼎夫豈慳。", "一朝隴書至，倏若登天翰。", "肉食無遠謀，伐檀譏素餐。", "失身墜戮辱，無乃佞與姦。", "逐兔牽黄犬，東門那得還。", "竟死咸陽市，慟哭何辛酸。", "丹塗布衣願，恨不蒯與菅。", "富貴履危機，悵望扶摇摶。", "世事亦墮甑，天理真循環。", "向來京口銘，俯仰成悲歡。", "世無薛公筆，想像付永歎。"]'),
('2637d519-3e4e-4f3a-96b7-fee240bb5af3','和萬元亨舍人送芡實','虞儔','宋','宋诗','song-poetry','','[]','吳興魚稻鄉，來視刺史印。',132,'全唐诗/poet.song.153000.json','["吳興魚稻鄉，來視刺史印。", "適丁饑饉後，倉廩無餘藴。", "當饋不下嚥，寧望饌中雋。", "年來稻如雲，便覺摇其吻。", "豐年百物熟，天意毋寧靳。", "君侯有佳惠，芡實粲光潤。", "東山願不違，南蕩居其近。", "此物舊知名，採擷手自引。", "剖蚌訝珠還，泣蛟疑淚迸。", "軟溫新剝肉，飣餖初嘗醖。", "遺我水之濱，此意君其問。"]'),
('4aba734a-eac2-460b-867d-e4702c9a34f1','和王天任喜雪  其一','虞儔','宋','宋诗','song-poetry','','[]','姑射之山果何如，往者吾言聞接輿。',80,'全唐诗/poet.song.153000.json','["姑射之山果何如，往者吾言聞接輿。", "肌膚冰雪能綽約，是中知有神人居。", "神凝自使年穀熟，况有疵癘煩驅除。", "乘雲四海聊戲劇，磅礴萬物同慘舒。", "至哉河漢已無極，俗士區區窮尾閭。"]'),
('6df34c1f-ca31-4290-80c3-fae8bc3b339e','和王天任喜雪  其二','虞儔','宋','宋诗','song-poetry','','[]','我家四壁真相如，晨興欲出無車輿。',80,'全唐诗/poet.song.153000.json','["我家四壁真相如，晨興欲出無車輿。", "獨騎瘦馬南坡下，閬風十二仙人居。", "書生一朝忽富貴，瑶林瓊樹環玉除。", "梅花失喜爲三白，一枝放我眉頭舒。", "春風醉眼紅綠亂，爾時獨醒如三閭。"]'),
('71083827-bd55-42ff-a212-c342d0191e71','送隠靜恭老','虞儔','宋','宋诗','song-poetry','','[]','妙喜老人骨應槁，明月堂空迹如掃。',144,'全唐诗/poet.song.153000.json','["妙喜老人骨應槁，明月堂空迹如掃。", "叢林耆舊半消磨，砥柱頹波餘此老。", "五峯深處開道場，道價重於連城寶。", "我蓋知名二十年，長恨識師之不早。", "朅來陵陽第二峯，一笑相從即傾倒。", "午窗對坐語笑清，夜榻歸來魂夢好。", "大顛理勢恐是渠，澄觀公才何足道。", "青衫我亦行作吏，未盡俗緣多病惱。", "相期巢父早掉頭，共住山中拾瑶草。"]'),
('bbc43c04-21bc-44da-bf12-8158b20d3692','和中本留題照石詩','虞儔','宋','宋诗','song-poetry','','[]','故人別來知幾年，怪我相逢鬚鬢白。',64,'全唐诗/poet.song.153000.json','["故人別來知幾年，怪我相逢鬚鬢白。", "看鏡功名不用頻，蒼苔遍教留行跡。", "蚤知宇定發天光，未聞終日介如石。", "此理昭然何足疑，來詩併遣鎸崖壁。"]'),
('2b72cce5-fc1e-4240-a041-ce137fe60860','贈孫尉姑蘇紫石銚孫有詩次韻','虞儔','宋','宋诗','song-poetry','','[]','吳儂生長水與雲，不採蓮花拔蒲根。',256,'全唐诗/poet.song.153000.json','["吳儂生長水與雲，不採蓮花拔蒲根。", "窮山鑿石出奇怪，顛坑仆谷無寒溫。", "宣和倖臣以佞進，橫江花石如雲屯。", "造化有此誠瘡痏，奈何浮靡誇朴敦。", "守令誅求星火迫，州縣驚擾河濤翻。", "舉觴誰酹栟櫚子，我欲從之以爲昆。", "爾來刳作短尾銚，形模簡古得全渾。", "遺君日以烹龍鳳，要和松風瀉潺湲。", "彌明譏評二子媿，盧仝風味千載存。", "搜攪胸中萬卷富，傾動筆下三峽源。", "可憐長安貴公子，飽餐荔支饜河豚。", "豈知是中有佳趣，目方忤視手不捫。", "武夫丁字且不識，一礮擬落天驕魂。", "平生攘臂咤飛石，唾取青衫明主恩。", "書生調度清且苦，臭味不同誰與論。", "祝君勿遣羊羹污，以友石供古銅盆。"]'),
('7e4b4060-8f97-4fa6-b473-ead27bb04608','食後過竹堂風雨遽作賦所見','虞儔','宋','宋诗','song-poetry','','[]','雲氣四蒸雷蓄怒，山雨一來風借助。',64,'全唐诗/poet.song.153000.json','["雲氣四蒸雷蓄怒，山雨一來風借助。", "抱頭乳燕竄低簷，噤口黄鸝在深樹。", "竹圍萬槊齊驚呼，老松不動如亞夫。", "何人筆端带三昧，畫作竹堂風雨圖。"]'),
('79018737-4d4d-4357-a1fe-331404d5cd40','監學同舍餞南康新使君黄雍文分韻','虞儔','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','人生五馬古云樂，今君此行殊不惡。',96,'全唐诗/poet.song.153000.json','["人生五馬古云樂，今君此行殊不惡。", "君才自是瑚璉器，十載聲華滿臺閣。", "胡爲忽厭東華塵，一麾要把江之濱。", "聞道豐登少公事，姑與匡廬作主人。", "到郡莫辭譏屢費，政恐朝來多爽氣。", "山中向有讀書人，爲問歸來頭白未。"]'),
('d7000455-2eda-4ccd-99e2-ddd910163261','成均同舍餞別新安使君徐子宜太丞分韻','虞儔','宋','宋诗','song-poetry','','[]','我昔絃歌乳溪側，嗟哉所割真鷄肋。',192,'全唐诗/poet.song.153000.json','["我昔絃歌乳溪側，嗟哉所割真鷄肋。", "斯民疾苦得飽諳，離彼三年能記憶。", "丁男箇箇事播殖，紅女家家勤紡織。", "可憐卒歲無完褐，縱使豐年有菜色。", "夏稅未畢秋稅來，縣家小緩州家逼。", "拆東補西恐不免，剜肉醫瘡寧有極。", "小儒安敢私其民，上官貽怒幾遭劾。", "痛定還思當痛時，至今夢裏猶心惻。", "歙爲富州傳自舊，誰以留州事苛刻。", "徐侯固是清廟器，撫摩暫遣憑熊軾。", "朝廷選用蓋不輕，祖帳衣冠傾上國。", "德星往矣勿復道，田里從茲無嘆息。"]'),
('38f4b6ab-2cf4-4848-a097-a8dab0272f60','同舍餞新滁陽使君范子由寺丞于成均芳潤軒分韻','虞儔','宋','宋诗','song-poetry','','[]','憶昔飛鳬來上國，作縣聲名動宸極。',64,'全唐诗/poet.song.153000.json','["憶昔飛鳬來上國，作縣聲名動宸極。", "今朝頗怪空馬羣，十年所得真鷄肋。", "笑指滁陽有佳處，手把一麾留不得。", "醉翁相望百年間，瑯琊自此添顔色。"]'),
('9f75efc8-1f76-4615-b8fe-5427f2ec051b','食墨魚有感','虞儔','宋','宋诗','song-poetry','','[]','誑人吐盡胸中墨，不料反爲人所得。',112,'全唐诗/poet.song.153000.json','["誑人吐盡胸中墨，不料反爲人所得。", "禍變之來非所慮，僅與詩人供一筯。", "韓非竟以說難死，楊惲詩成汙刀机。", "子雲嗜學甘寂寞，晚年奇字終投閣。", "撐腸文字五千卷，不救顔回忍饑面。", "三年博士冗不治，半生鉛槧寧非癡。", "老兵兩眼不識書，飽食高眠我不如。"]'),
('def50571-edb1-4703-a8ed-fb9372414fae','次韻漢老弟假山','虞儔','宋','宋诗','song-poetry','','[]','庭空吏散無公事，一枕清風供午睡。',384,'全唐诗/poet.song.153000.json','["庭空吏散無公事，一枕清風供午睡。", "列仙之陬渺何許，化蝶翩翩可坐致。", "夢中意行不識路，神前那有車乘墜。", "立壁延緣蘿蔓綠，滑徑行視莓苔翠。", "南遊忽到九疑峯，竹痕斑斑湘娥淚。", "簫韶聲斷蒼梧雲，石上虛餘千古意。", "回鑣斜經少昊墟，閬風縣圃窮幽邃。", "崑崙銅柱高隠天，河流九曲東南被。", "高掌遠蹠得我驚，二華巨靈留贔屭。", "三丘却轉問勾芒，首冠連鼇誰所置。", "蓬萊浪自弱水隔，俛仰之間興已寄。", "傳聞有棗大如瓜，一笑安期方指示。", "惡風驟起吹船回，未悟此身在平地。", "鼕鼕衙鼓忽驚覺，起來恰見羣兒戲。", "疊石亭前作假山，列嶂層峯生詭異。", "有如中怒互拏攫，或似畫眉相嫵媚。", "神獒獅子豈其朋，伏虎卧駝非若類。", "珠屏九摺地不惜，西柱一峯天所棄。", "眼中乍見已堪賞，夢裏曾遊俱可誌。", "連筒灌水瀑泉飛，薄岸臨坻盤石巋。", "瓦盤拳石養菖蒲，小有仇池今見二。", "乃知仙境只人間，跬步不移千里至。", "向來封國在槐枝，我今此夢真相似。", "要知萬事孰非夢，何物世間能久嗜。"]'),
('331e0547-67ef-4204-a79f-c3e8d97c1c16','偶食鷄頭有懷萬元亨沈德遠林子長橫塘三主人  其一','虞儔','宋','宋诗','song-poetry','','[]','秋風一熟平湖芡，滿市明珠如土賤。',64,'全唐诗/poet.song.153000.json','["秋風一熟平湖芡，滿市明珠如土賤。", "昔也兼名鴻鴈頭，今茲始識胡孫面。", "應須我輩賸著語，會有後人來作傳。", "橫塘地主總好事，凌波不過空山嚥。"]'),
('8a95575d-171d-4232-9464-2d685d2542b0','偶食鷄頭有懷萬元亨沈德遠林子長橫塘三主人  其二','虞儔','宋','宋诗','song-poetry','','[]','年豐豈特菱蓮芡，米價新來如許賤。',64,'全唐诗/poet.song.153000.json','["年豐豈特菱蓮芡，米價新來如許賤。", "不孤后稷由已思，誰作顔回忍饑面。", "清朝已拜富民侯，太史莫書循吏傳。", "我今何事不歸田，豆飯芋魁甘得嚥。"]'),
('7017c5b0-f84e-4c14-b14a-5334dcc9741a','和張簿南坡','虞儔','宋','宋诗','song-poetry','','[]','春風吹水生碧鱗，南坡花事日日新。',256,'全唐诗/poet.song.153000.json','["春風吹水生碧鱗，南坡花事日日新。", "水流花出人間去，應有桃源迷路人。", "四圍山色染黛綠，夾道柳絲摇麴塵。", "碧桃和露真含笑，海棠過雨猶橫陳。", "蜜脾未滿蜂子閙，麥穗欲齊媒雉馴。", "滿堂金玉空爲爾，不博斑衣膝下春。", "我今家居奉慈母，長年直欲齊大椿。", "每當淑景恣遊覽，白藤肩輿敷錦茵。", "華髮映花更蕭爽，朱顔得酒能精神。", "授柑政類潘騎省，舉觴敢望周伯仁。", "仙家日月雖不老，人生行樂須及辰。", "張侯故是名家子，萬里碧雲看致身。", "朅來吾縣鸞栖棘，少年得祿說及親。", "洛濱侍從追前躅，喜君有此與我均。", "花間不用錦步障，鶑蝶近前君勿嗔。", "雙缾姑餉千日壽，待戒園夫休厭頻。"]'),
('0c1051da-38ba-4843-b957-def84220a045','和郁簿述懷古風','虞儔','宋','宋诗','song-poetry','','[]','莫笑當年韓與侯，釣魚溫水垂纖鈎。',224,'全唐诗/poet.song.153000.json','["莫笑當年韓與侯，釣魚溫水垂纖鈎。", "鳶肩自是騰上速，安用常何薦馬周。", "先生直氣摩星斗，肯來州縣甘低頭。", "蒞官姑欲行所學，一猿未足勝衆猴。", "平生一介重取與，邈視不義如雲浮。", "同舍償金初何有，從者竊屨還言否。", "古井新來亦波浪，夷途强指如山丘。", "毀言中人以疑似，心苟無瑕何足尤。", "雖然鑠金忌衆口，此語不妄聞諸鄒。", "誰知三月未得祿，長饑日典鷫鸘裘。", "不作顔公乞米帖，吟詩肝腎愁鎸鎪。", "詩成險語破鬼膽，我慚屬和真蠻謳。", "願須暇日薦所有，君方有行寧少留。", "何妨暫駕揚州鶴，猶勝他人萬斛舟。"]'),
('352d4ff7-a46c-4de4-a59f-7fcad928f330','昨日於竹堂後開一逕通南坡甚近從此便於往還遂成日涉之趣矣','虞儔','宋','宋诗','song-poetry','','[]','先生一室如懸罄，彈鋏浩歌誰復聽。',96,'全唐诗/poet.song.153000.json','["先生一室如懸罄，彈鋏浩歌誰復聽。", "籃輿每出欠僕夫，蹇馿試跨愁泥濘。", "南坡日涉恐負渠，寸步躋攀如折脛。", "偶向田頭問小溪，何妨竹裏通幽徑。", "杖藜從此便還往，出趁晨光歸及暝。", "更遣蒼頭佩一壺，醉中却愛風吹醒。"]'),
('61b97259-b5cc-4d18-866d-09915ea4cf2b','春蠶行','虞儔','宋','宋诗','song-poetry','','[]','今年桑葉賤如土，吳蠶戢戢多於魯。',96,'全唐诗/poet.song.153000.json','["今年桑葉賤如土，吳蠶戢戢多於魯。", "葉底時聞健食聲，樹頭颯颯初來雨。", "辛勤出火倏三眠，準擬收功千萬縷。", "縣官何忍爲繭絲，女紅切勿事纂組。", "愚儒請遺天下衣，各使蒼生有環堵。", "天寒歲暮田舍翁，白髮霜風吹兩股。"]'),
('1b0176f3-d03b-43cf-b3a0-013b402e3af5','林正甫舉似所和雙丫巖詩且索同賦','虞儔','宋','宋诗','song-poetry','','[]','君不見羅敷採桑城南路，不肯輕爲使君婦。',142,'全唐诗/poet.song.153000.json','["君不見羅敷採桑城南路，不肯輕爲使君婦。", "又不見銀釵垂頸負薪歸，四十未嫁夔州女。", "雙丫何自老山中，當年豈羨西鄰富。", "花前啼鳥春不知，水裏姮娥夜相顧。", "寧爲山頭望夫石，儻有飛鴻傳尺素。", "莫學巫山十二峯，爲雲爲雨朝還暮。", "老奴玉鏡誰自料，阿嬌金屋知何所。", "明珠節婦浪悲吟，羅襪洛神空有賦，蛾眉入宮須見妬。"]'),
('420aff9a-6a4b-4853-9882-62dd03585313','觀園夫種菜','虞儔','宋','宋诗','song-poetry','','[]','町畦紛接壤，灌溉細穿渠。',48,'全唐诗/poet.song.153000.json','["町畦紛接壤，灌溉細穿渠。", "坐待佳蔬長，應須惡草除。", "向來師老圃，此去遂閒居。", "遶屋扶疎處，兼尋種樹書。"]'),
('a39d66ec-54ad-4285-b470-c8b61bb8b352','和林子長分贈丹桂韻','虞儔','宋','宋诗','song-poetry','','[]','月桂天應惜，溪堂人與清。',48,'全唐诗/poet.song.153000.json','["月桂天應惜，溪堂人與清。", "五枝蒙折贈，雙目喜增明。", "紅藥羞丹禁，彤霞避赤城。", "賸聞燒燭賞，有底置公榮。"]'),
('de501bf3-1416-472a-a7b4-3289651c107e','雨中偶成呈天任','虞儔','宋','宋诗','song-poetry','','[]','久雨苦不樂，吾廬亦未貧。',48,'全唐诗/poet.song.153000.json','["久雨苦不樂，吾廬亦未貧。", "十旬兼美醖，千畝長脩筠。", "睡蝶頻來夢，歌鶑皆惱人。", "得君新唱和，懶病起精神。"]'),
('9e7d8df8-092d-448b-a082-602ba901320b','秋晚矣菊猶未開小詩速之  其一','虞儔','宋','宋诗','song-poetry','','[]','問訊東籬菊，如今開未開。',48,'全唐诗/poet.song.153000.json','["問訊東籬菊，如今開未開。", "不應辜酒伴，寧是欠詩催。", "屈指秋將盡，關心日幾回。", "霜風不相借，何意尚徘徊。"]'),
('da24452f-7a3f-44e7-84af-ab7c0c027ed3','秋晚矣菊猶未開小詩速之  其二','虞儔','宋','宋诗','song-poetry','','[]','酒爲多多辦，花須早早開。',48,'全唐诗/poet.song.153000.json','["酒爲多多辦，花須早早開。", "已愆重九約，猶待兩番催。", "明日還何益，西風定肯回。", "游言空自解，蜂蝶笑徘徊。"]'),
('e6a0a21a-ebf0-4098-835f-37013540cc50','再促花','虞儔','宋','宋诗','song-poetry','','[]','珍重栽培意，商量仔細開。',48,'全唐诗/poet.song.153000.json','["珍重栽培意，商量仔細開。", "花心終有待，詩句漫勞催。", "莫恨三秋去，須教一笑回。", "但儲千斛酒，端的奉徘徊。"]'),
('aec7dbff-044d-4471-b8ef-5a2a9be99c78','數詩煎迫太甚再爲花下一轉語','虞儔','宋','宋诗','song-poetry','','[]','蝶自無心懶，花應有意開。',48,'全唐诗/poet.song.153000.json','["蝶自無心懶，花應有意開。", "含香特珍寵，顧影尚低回。", "畢竟風流在，從渠火急催。", "浮華不相待，莊重政徘徊。"]'),
('f93f96bb-0742-4a51-85a1-e1beae3339c3','喜花開','虞儔','宋','宋诗','song-poetry','','[]','落木驚秋晚，黄花徹夜開。',48,'全唐诗/poet.song.153000.json','["落木驚秋晚，黄花徹夜開。", "便教雙蝶舞，寧是萬牛回。", "有酒須頻舉，將詩莫浪催。", "淵明千古意，爲汝轉徘徊。"]'),
('14762edc-8599-4e42-adf7-8c69b5332184','諸公和詩而菊開主簿沃同年乃有褒拂之語用韻謝之','虞儔','宋','宋诗','song-poetry','','[]','怪底花心轉，知從筆力回。',48,'全唐诗/poet.song.153000.json','["怪底花心轉，知從筆力回。", "不嫌嘲我廋，良是爲君開。", "白雪詞何有，黄鷄曲漫催。", "待牽重九興，籬下醉徘徊。"]'),
('f2d578c5-bac0-4df1-a3a1-18912e2cdb9a','比收張伯子尚書書報諸公有相招意因賦拙句  其一','虞儔','宋','宋诗','song-poetry','','[]','入臺羞結舌，去國坐嬰鱗。',48,'全唐诗/poet.song.153000.json','["入臺羞結舌，去國坐嬰鱗。", "東道今行李，南宮乃故人。", "寒溫煩見問，書劄不辭頻。", "向日區區意，還曾扣大鈞。"]'),
('899b57b6-62e3-4756-853d-27f50ee75b59','比收張伯子尚書書報諸公有相招意因賦拙句  其二','虞儔','宋','宋诗','song-poetry','','[]','與物初無競，何人苦見銜。',48,'全唐诗/poet.song.153000.json','["與物初無競，何人苦見銜。", "馮唐雖白首，商皓豈空函。", "烏鵲新傳喜，青蠅漸息讒。", "鴛鴻滿臺閣，祇合理歸帆。"]'),
('5890c82f-bdea-4b58-83e3-3178372daa44','比收張伯子尚書書報諸公有相招意因賦拙句  其三','虞儔','宋','宋诗','song-poetry','','[]','天上張公子，殷勤忽枉書。',48,'全唐诗/poet.song.153000.json','["天上張公子，殷勤忽枉書。", "幾年憐潦倒，今日遂吹噓。", "貢喜慚何暮，馮招恐不虛。", "吾生真有命，造物合何如。"]'),
('5445af1c-f15b-4d99-85af-610b5c59c57c','韓知府挽詩二首  其一','虞儔','宋','宋诗','song-poetry','','[]','宦路雲霄近，鄉評月旦賢。',48,'全唐诗/poet.song.153000.json','["宦路雲霄近，鄉評月旦賢。", "不惟同里巷，曾是接官聯。", "西浙勞裨贊，東淮適後先。", "向來吹送意，豈料隔重泉。"]'),
('d98bed36-bdbe-4758-9a4f-5e685cbd1145','韓知府挽詩二首  其二','虞儔','宋','宋诗','song-poetry','','[]','方美朱輪貴，俄驚丹旐新。',48,'全唐诗/poet.song.153000.json','["方美朱輪貴，俄驚丹旐新。", "鳳毛看二子，鶴髮慰偏親。", "甲第歸無日，名園跡已陳。", "風流山下路，楚挽倍傷神。"]'),
('d4cb25b1-acd9-4d0b-9341-c6e1d2725249','林子中知府挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','彩棒初行志，華途蚤策勳。',48,'全唐诗/poet.song.153000.json','["彩棒初行志，華途蚤策勳。", "旋聞鳬舄召，徑有虎符分。", "嘆息誰爲黨，推求誤到君。", "天公還憒憒，玉石竟俱焚。"]'),
('45c38645-a577-4541-89e6-cf987eaf098c','林子中知府挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','疇昔因難弟，夤緣幸識君。',48,'全唐诗/poet.song.153000.json','["疇昔因難弟，夤緣幸識君。", "宦途俱別日，苕水再披雲。", "勞苦驚多病，悲凉惜離羣。", "斗金峯下路，鐸挽不堪聞。"]'),
('709f9e5e-1509-4251-93db-b3a0931ee2a7','李參政挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','望重三朝舊，年過八秩希。',48,'全唐诗/poet.song.153000.json','["望重三朝舊，年過八秩希。", "股肱康帝室，羽翼傅儲闈。", "北闕恩雖厚，東山願豈違。", "蒼生猶有恨，不見衮衣歸。"]'),
('0d46d679-917e-476d-a69e-7a1ade5283c7','李參政挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','廊廟推良弼，屏藩紀吏師。',48,'全唐诗/poet.song.153000.json','["廊廟推良弼，屏藩紀吏師。", "三孤崇恤典，公座有佳兒。", "風節蕭長倩，詩篇杜拾遺。", "倏騎箕尾去，名共列星垂。"]'),
('ceba17be-546b-4e0e-b61e-030e6b463bbd','李參政挽詩  其三','虞儔','宋','宋诗','song-poetry','','[]','末路懷前輩，分符記舊臨。',48,'全唐诗/poet.song.153000.json','["末路懷前輩，分符記舊臨。", "吳興慚薤本，寶婺仰棠陰。", "驥子嘗傾蓋，龍門亦整襟。", "無繇陪執紼，楚挽寄哀音。"]'),
('5e3ea558-5b33-4618-ac5d-e0f9415074b0','參議余公挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','慘澹門闌色，凄凉月旦評。',48,'全唐诗/poet.song.153000.json','["慘澹門闌色，凄凉月旦評。", "居官皆可紀，當路競知名。", "香火祠庭老，錙銖郡紱輕。", "彈冠公自懶，相國詎忘情。"]'),
('41c2129c-9ae2-496d-84e5-125f6c2fa62a','參議余公挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','假蔭非公志，書生若命何。',48,'全唐诗/poet.song.153000.json','["假蔭非公志，書生若命何。", "高才寧汩沒，榮路故蹉跎。", "仲子能傳業，詞場遂决科。", "暮年方慰意，樂極又悲歌。"]'),
('37b0542e-4996-4b02-be03-693080dfc8a6','和姜總管歸途','虞儔','宋','宋诗','song-poetry','','[]','城郭迎車騎，溪山展畫圖。',48,'全唐诗/poet.song.153000.json','["城郭迎車騎，溪山展畫圖。", "歸鴉翻落葉，宿雁集寒蕪。", "酒裏傾肝膽，吟邊識步趨。", "佳人來底暮，心傒碧雲蘇。"]'),
('b22544a0-00f0-4421-9178-2e657f5baf6e','元日小室獨坐情思不怡','虞儔','宋','宋诗','song-poetry','','[]','坐久無人問，愁多莫我娛。',48,'全唐诗/poet.song.153000.json','["坐久無人問，愁多莫我娛。", "頗知新歲好，却訝五行孤。", "書亂塵凝案，灰寒雪擁爐。", "可能無斗酒，牆外雜歌呼。"]'),
('09fdce02-bd72-48e0-84fa-14938ee71fb3','故奚公學長挽詩','虞儔','宋','宋诗','song-poetry','','[]','詩酒平生興，人琴畢竟空。',48,'全唐诗/poet.song.153000.json','["詩酒平生興，人琴畢竟空。", "儒冠成晚歲，尺牘到諸公。", "忽嘆羣無鶴，誰留目送鴻。", "竹林家世事，清節見君同。"]'),
('06057688-f089-47a8-9b94-d7ce431fb672','中書黄舍人父總幹挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','孝子推慈父，明君有直臣。',48,'全唐诗/poet.song.153000.json','["孝子推慈父，明君有直臣。", "豈惟成羽翼，况復掌絲綸。", "想像成齋舊，昭回宸翰新。", "固應方寸地，種德玉堂人。"]'),
('fd1815fb-1e7d-4183-8119-d6cb7014e88f','中書黄舍人父總幹挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','有子能傳業，黄金笑滿籯。',48,'全唐诗/poet.song.153000.json','["有子能傳業，黄金笑滿籯。", "去華雖不第，谷口豈其卿。", "四海知名姓，諸儒仗老成。", "平生郭有道，真不媿碑銘。"]'),
('03ba8ee4-346a-4ef3-a0d2-8651e2dc3360','挽余丞相  其一','虞儔','宋','宋诗','song-poetry','','[]','淑氣含公鼎，明時預政機。',48,'全唐诗/poet.song.153000.json','["淑氣含公鼎，明時預政機。", "仲山維補衮，文子不勝衣。", "南國恩偏厚，東山志偶違。", "一爲天下慟，無以我公歸。"]'),
('d1413e67-a9b2-48bf-9917-750447fcca0f','挽余丞相  其二','虞儔','宋','宋诗','song-poetry','','[]','暑路驅紅旆，天書趣紫泥。',48,'全唐诗/poet.song.153000.json','["暑路驅紅旆，天書趣紫泥。", "長沙元忌鵩，太歲又逢鷄。", "挽鐸春風咽，銘旌夕照低。", "冠車紛會葬，桃李自成蹊。"]'),
('65247764-0f97-4b0c-972c-bb28a435c2d3','寶閣尚書凌公挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','新學輕餘子，忠懷策萬言。',48,'全唐诗/poet.song.153000.json','["新學輕餘子，忠懷策萬言。", "治安猶涕泣，師友故淵源。", "日曳尚書履，風生刺史轓。", "漢庭誰第一，殊未遜公孫。"]'),
('94ed7733-0873-4488-91c6-cb8f6d5be083','寶閣尚書凌公挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','未識嵇中散，今無元魯山。',48,'全唐诗/poet.song.153000.json','["未識嵇中散，今無元魯山。", "宦游真恨晚，逸駕竟難攀。", "閲月推評旦，聞風尚起頑。", "九原那可作，蒼弁亦推顔。"]'),
('f47254a8-36fe-4d18-94ec-5ad0c99c157b','繆夫人挽詩','虞儔','宋','宋诗','song-poetry','','[]','黯淡金花誥，凄凉柏葉觴。',48,'全唐诗/poet.song.153000.json','["黯淡金花誥，凄凉柏葉觴。", "開屏慘佳婿，扇枕念諸郎。", "家事千奴橘，僊遊一夢粱。", "了知元不朽，千載有銘章。"]'),
('b96a6f40-183b-439b-ba4e-dd79e5cfb533','萬侍郎母夫人挽詩','虞儔','宋','宋诗','song-poetry','','[]','閨壼高風在，鄉閭美事傳。',48,'全唐诗/poet.song.153000.json','["閨壼高風在，鄉閭美事傳。", "寧須伯仁長，更覺壽昌賢。", "祿養酬初志，恩封慰暮年。", "侍郎官已貴，遽返閬崑僊。"]'),
('1822655b-1d03-4e76-980a-f4b197cdfef2','漢老弟去秋留別有明年桃李月春入馬蹄輕之句今其時也因次韻招之','虞儔','宋','宋诗','song-poetry','','[]','晤言堪慰意，別語最關情。',48,'全唐诗/poet.song.153000.json','["晤言堪慰意，別語最關情。", "老我春還暮，思君月共明。", "丁寧期後會，容易即前程。", "命駕何妨再，聞知四體輕。"]'),
('69a454a4-c374-44d0-a5ee-97802c29b95b','奚通直挽詩','虞儔','宋','宋诗','song-poetry','','[]','自昔高陽里，嘗推月旦評。',48,'全唐诗/poet.song.153000.json','["自昔高陽里，嘗推月旦評。", "華簪先德齒，朱紱羨恩榮。", "奴豈謀千樹，金方笑滿籯。", "有孫看鼎貴，鍾慶驗佳城。"]'),
('9b154476-29a5-427a-b43a-4c90c3a3dba8','元衍曹居士挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','與物初無競，安居不用名。',48,'全唐诗/poet.song.153000.json','["與物初無競，安居不用名。", "平生惟下澤，月旦有南評。", "歲月驚飄忽，鄉閭失老成。", "聯翩先友記，百代許同聲。"]'),
('373cb134-41d4-4da7-a096-77a66534db04','元衍曹居士挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','先君無恙日，居士得游從。',48,'全唐诗/poet.song.153000.json','["先君無恙日，居士得游從。", "酒醆花前月，茶甌石上松。", "有時連款段，勝槩每從容。", "指點佳城處，相聞道院鐘。"]'),
('c74b17a7-9e57-42d7-86bc-918c44f2588f','故安國夫人挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','雅趣工書畫，高懷陋鼎鐘。',48,'全唐诗/poet.song.153000.json','["雅趣工書畫，高懷陋鼎鐘。", "家聲推兩大，壼範見三從。", "賢得魯侯配，榮開安國封。", "平生耽靜勝，宸翰煥鸞龍。"]'),
('fd113d8a-c378-4911-a0ed-8606b782db2b','故安國夫人挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','閥閲聯蟬冕，臺郎有鳳毛。',48,'全唐诗/poet.song.153000.json','["閥閲聯蟬冕，臺郎有鳳毛。", "美形彤管舊，節視柏舟高。", "南澗夫人藻，西池阿母桃。", "哀榮生死是，詔墨看重褒。"]'),
('e13af619-16e0-4220-a294-03eccd1b7451','堂前東偏松棚清蔭可愛爲賦五言八句','虞儔','宋','宋诗','song-poetry','','[]','問訊蒼官舊，掀髯肯見臨。',48,'全唐诗/poet.song.153000.json','["問訊蒼官舊，掀髯肯見臨。", "笑談驅酷暑，朝夕托清陰。", "便引夷風至，寧容盾日侵。", "北窗高卧處，靖節是知音。"]'),
('0f5671b1-ffe0-4e48-a630-a6703683d466','再寄廣文俞同年','虞儔','宋','宋诗','song-poetry','','[]','有客傳新句，呼兒整舊書。',48,'全唐诗/poet.song.153000.json','["有客傳新句，呼兒整舊書。", "勞生徒擾擾，不動只如如。", "病瘧猶憐我，流行也到渠。", "平生真莫逆，裹飯肯躊躕。"]'),
('549eb686-1b2d-410f-bca7-6c7357917882','無眠','虞儔','宋','宋诗','song-poetry','','[]','丙夜不成寐，可知心念家。',48,'全唐诗/poet.song.153000.json','["丙夜不成寐，可知心念家。", "人情風上草，身世眼中沙。", "宿鳥司更漏，黄蜂集晚衙。", "了忘官府事，高枕是生涯。"]'),
('c10cb2f0-5bff-4b5d-81bf-9c71f8230d62','脚婆子  其一','虞儔','宋','宋诗','song-poetry','','[]','百沸催湯沃，孤燈迫睡昏。',48,'全唐诗/poet.song.153000.json','["百沸催湯沃，孤燈迫睡昏。", "復皤餘豕漲，足蹜但鴟蹲。", "一衲包纏密，重衾底裏溫。", "窮冬爲老伴，永夜得深論。"]'),
('bc2871d7-d2f1-45ee-81f4-8bd7d70e851c','脚婆子  其二','虞儔','宋','宋诗','song-poetry','','[]','著瓦霜威重，侵窗月色昏。',48,'全唐诗/poet.song.153000.json','["著瓦霜威重，侵窗月色昏。", "相依紙帳夢，猶勝火爐蹲。", "伸脚三更穩，回頭一笑溫。", "溫柔非老事，付與少年論。"]'),
('8436c8c1-a227-4a52-96f2-ebf9ae952119','官况  其一','虞儔','宋','宋诗','song-poetry','','[]','流落經年別，平安只信通。',48,'全唐诗/poet.song.153000.json','["流落經年別，平安只信通。", "宦情元自薄，春色爲誰濃。", "撫字愁眉上，青紅醉眼中。", "著詩無好語，還往負筠筒。"]'),
('a631eb31-6680-43a0-8dd3-f8912a0aeae9','官况  其二','虞儔','宋','宋诗','song-poetry','','[]','觸手逢人怒，低頭與俗同。',48,'全唐诗/poet.song.153000.json','["觸手逢人怒，低頭與俗同。", "一慚那可忍，百巧固應窮。", "酒有兼旬綠，花無百日紅。", "悲歡真破甑，墮地併成空。"]'),
('46b64824-eb0f-418e-a247-173c580fb3f8','早上過溪報謁林子長承約客回途作  其一','虞儔','宋','宋诗','song-poetry','','[]','臭味還吾輩，炎凉笑若曹。',48,'全唐诗/poet.song.153000.json','["臭味還吾輩，炎凉笑若曹。", "相逢傾蓋舊，可但泛舟勞。", "夜雨湖山好，西風鼓角豪。", "主人寧避客，祇覺杜門高。"]'),
('83f12c36-7194-4a68-8ec5-9a2ce60e0fb1','早上過溪報謁林子長承約客回途作  其二','虞儔','宋','宋诗','song-poetry','','[]','畫諾何如瑨，歌呼敢效曹。',48,'全唐诗/poet.song.153000.json','["畫諾何如瑨，歌呼敢效曹。", "一饑才免死，千慮亦忘勞。", "酒裏愁先醉，吟邊句未豪。", "菟裘吾欲老，不是故爲高。"]'),
('4d1fd967-c12a-40c8-8921-c6bf8fd79330','早上過溪報謁林子長承約客回途作  其三','虞儔','宋','宋诗','song-poetry','','[]','伏日當休沐，頑軀困坐曹。',48,'全唐诗/poet.song.153000.json','["伏日當休沐，頑軀困坐曹。", "驟然秋雨至，一洗夏畦勞。", "懷祖何須怒，劉伶亦未豪。", "北窗陶靖節，千載只渠高。"]'),
('9e30b125-53fc-4255-8881-44392fbef801','久不得廣文俞同年書頗聞病瘧小詩往問訊','虞儔','宋','宋诗','song-poetry','','[]','問訊俞夫子，兼旬不寄書。',48,'全唐诗/poet.song.153000.json','["問訊俞夫子，兼旬不寄書。", "官居還獨冷，體力復何如。", "藥石寧須爾，炎凉一任渠。", "詩能驅瘧鬼，下筆莫躊躕。"]'),
('2fa7666d-2dec-4838-b0ae-e74e969310aa','六月請俸張簿攝邑止支其半因却還之','虞儔','宋','宋诗','song-poetry','','[]','閒居須薄俸，未足保妻孥。',48,'全唐诗/poet.song.153000.json','["閒居須薄俸，未足保妻孥。", "州縣真徒爾，兒曹敢料吾。", "揮金憐橐在，儲粟笑缾無。", "敝褐猶堪典，新凉要一壺。"]'),
('bfff35f4-0e52-41ea-aad4-cdf58e0e8fde','十月到南坡','虞儔','宋','宋诗','song-poetry','','[]','觸眼嗟黄落，憑高接翠微。',48,'全唐诗/poet.song.153000.json','["觸眼嗟黄落，憑高接翠微。", "幽禽私自語，寒蝶晚相依。", "醉熟風吹帽，愁生带減圍。", "功名竟何許，尊酒莫相違。"]'),
('1b508623-1c96-45b9-b9aa-ef1692a161da','將至天目登高嶺','虞儔','宋','宋诗','song-poetry','','[]','天近初凝目，雲橫便躡梯。',48,'全唐诗/poet.song.153000.json','["天近初凝目，雲橫便躡梯。", "前瞻千嶂列，回首一川低。", "雨過黄梅盡，風來翠剡齊。", "靈源窮不到，晴晝掛虹霓。"]'),
('2b4b90cc-6517-4550-b580-b4d5e2c29457','將至富陽','虞儔','宋','宋诗','song-poetry','','[]','宦路初無定，吾行有底忙。',48,'全唐诗/poet.song.153000.json','["宦路初無定，吾行有底忙。", "江清魚不聚，天遠鴈南翔。", "整棹須平進，回瀾亦太狂。", "平生湖海意，何夢到凝香。"]'),
('a4a8ce38-8fc7-4dea-9285-d9af6777336c','和潘簿旅懷','虞儔','宋','宋诗','song-poetry','','[]','朔風動關塞，羈人先自知。',48,'全唐诗/poet.song.153000.json','["朔風動關塞，羈人先自知。", "忘情須我輩，了事豈兒癡。", "鴈信憑誰寄，蛩吟暗自悲。", "遣排消底物，不飲復何爲。"]'),
('4c17fe3d-cbe9-40da-9c78-09d67adc694a','韓知閤挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','一品真王裔，先朝長主孫。',48,'全唐诗/poet.song.153000.json','["一品真王裔，先朝長主孫。", "華途聲烈在，上閤典刑存。", "閭里羣知敬，朝廷愈覺尊。", "天胡嗇之壽，莫返九原魂。"]'),
('ba4ea984-08e6-46e0-add6-625e2c6d38b1','韓知閤挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','容色雖嚴重，襟懷實坦夷。',48,'全唐诗/poet.song.153000.json','["容色雖嚴重，襟懷實坦夷。", "功名期自奮，趨向肯隨進。", "翻念懸車樂，俄成易簀悲。", "扁舟苕霅上，此意幾人知。"]'),
('a13e0f35-8b8c-4065-b60b-efdcf4cdfcdd','程待制挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','科第聯三世，聲名動九垓。',48,'全唐诗/poet.song.153000.json','["科第聯三世，聲名動九垓。", "激昂存壯志，盤錯見奇才。", "往者分邊閫，胡然避憲臺。", "教忠知有待，餘慶接三台。"]'),
('50e754d3-7961-4fcc-80bf-ff1e5aa669e0','程待制挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','有子巖廊貴，知公衣鉢傳。',48,'全唐诗/poet.song.153000.json','["有子巖廊貴，知公衣鉢傳。", "內祠初趣召，次對暫迴旋。", "偕老萊衣喜，虛懷帝席前。", "恩榮方沓至，遽返九華僊。"]'),
('bf77a3ec-b4b8-499c-84da-a94a0e921893','挽吳公祥承事詩  其一','虞儔','宋','宋诗','song-poetry','','[]','故國衣冠後，傳家禮法尊。',48,'全唐诗/poet.song.153000.json','["故國衣冠後，傳家禮法尊。", "擊鮮更下舍，容駟閌高門。", "河潤金揮橐，風流酒滿罇。", "平生陰德事，五世眼中孫。"]'),
('ad56df49-a7b1-4e12-af07-08a5ead201c1','挽吳公祥承事詩  其二','虞儔','宋','宋诗','song-poetry','','[]','昔過高陽里，嘗登通德門。',48,'全唐诗/poet.song.153000.json','["昔過高陽里，嘗登通德門。", "敢違鄉黨敬，尚想典刑存。", "喬木縈心曲，空花浥淚痕。", "定應歸凈土，何必賦招魂。"]'),
('fc6c98bc-5806-4384-abd0-aa95b7be305e','挽承事湯公詩','虞儔','宋','宋诗','song-poetry','','[]','屋底千金潤，尊前一笑真。',48,'全唐诗/poet.song.153000.json','["屋底千金潤，尊前一笑真。", "名藍尋入社，家事豈關身。", "丈室空天女，凌波悼洛神。", "鹿門携手後，還有姓龐人。"]'),
('90e03929-3391-4c17-8cc3-8e33ab12f3ce','挽范承事詩','虞儔','宋','宋诗','song-poetry','','[]','貝葉神怡處，南柯夢覺時。',48,'全唐诗/poet.song.153000.json','["貝葉神怡處，南柯夢覺時。", "月評依舊好，露挽不堪悲。", "分米誰懷惠，兼金肯拾遺。", "紺蓮華發後，見佛想舒眉。"]'),
('0235aee5-357e-4bde-970e-1482ae573045','挽奚公彥章承奉詩  其一','虞儔','宋','宋诗','song-poetry','','[]','上國曾傾蓋，文闈昔盍簪。',48,'全唐诗/poet.song.153000.json','["上國曾傾蓋，文闈昔盍簪。", "科名終在子，章服果何心。", "朝露悲蒿里，遺風上竹林。", "人琴俱不見，哀挽爲沾襟。"]'),
('fe9e7dff-0d1c-4731-8952-3a570a47b1e1','挽奚公彥章承奉詩  其二','虞儔','宋','宋诗','song-poetry','','[]','已識嵇中散，誰慚王濬沖。',48,'全唐诗/poet.song.153000.json','["已識嵇中散，誰慚王濬沖。", "鴻飛嗟目斷，鶴化駭羣空。", "懶作金門客，寧爲鐵面翁。", "後園花木在，回首又春風。"]'),
('428abb5f-b1a2-4c25-bbe4-fc2c934d1ba7','挽都運徽猷陳君詩  其一','虞儔','宋','宋诗','song-poetry','','[]','煮海攄忠論，潢池讋武威。',48,'全唐诗/poet.song.153000.json','["煮海攄忠論，潢池讋武威。", "分符留惠愛，持節借光輝。", "閥閲伊誰似，功名與願違。", "未前宣室問，遽作九原歸。"]'),
('5fd9d23f-41bd-4b56-8606-4fd42be47e14','挽都運徽猷陳君詩  其二','虞儔','宋','宋诗','song-poetry','','[]','玉節稽嚴召，琳宮暫列僊。',48,'全唐诗/poet.song.153000.json','["玉節稽嚴召，琳宮暫列僊。", "月華方喜見，薤露忽悲纏。", "回首長安日，傷心蜀道天。", "初無封禪議，遺藁總堪傳。"]'),
('1faf40db-bcc0-4e00-9c2e-df8eaa5c2fec','途中得姜總管詩因和韻','虞儔','宋','宋诗','song-poetry','','[]','相知何必舊，我輩正鍾情。',48,'全唐诗/poet.song.153000.json','["相知何必舊，我輩正鍾情。", "老去難爲別，詩來愈覺清。", "舟虛和雪載，水淺過灘平。", "一路俱佳境，收歸五字城。"]'),
('b51bb6b5-c4df-4d56-b3a0-d923991e6647','宋宰不赴王倅招有詩次韻  其一','虞儔','宋','宋诗','song-poetry','','[]','冷宦門羅雀，高軒間不過。',48,'全唐诗/poet.song.153000.json','["冷宦門羅雀，高軒間不過。", "似聞諠棰楚，莫恨笑弦歌。", "會意庭前柏，輸香水面荷。", "道人觀物妙，宴坐養天和。"]'),
('4b71afcb-c8f6-44b2-9170-bf58c0dfb0c8','宋宰不赴王倅招有詩次韻  其二','虞儔','宋','宋诗','song-poetry','','[]','風號天籟怒，雷引雨聲長。',48,'全唐诗/poet.song.153000.json','["風號天籟怒，雷引雨聲長。", "但喜書帷潤，那知酒斚凉。", "夜光宜月露，霽色醒松篁。", "通介從流俗，徐公自有常。"]'),
('aa64c3bc-b717-4c7a-ae11-730c07f456b0','觸事  其一','虞儔','宋','宋诗','song-poetry','','[]','製錦無工拙，迷途有是非。',48,'全唐诗/poet.song.153000.json','["製錦無工拙，迷途有是非。", "承符何所恃，投檄會須歸。", "未飽豺狼欲，寧論鴈鶩肥。", "歸來羞碌碌，老去與心違。"]'),
('0a9d770d-6973-4433-b861-22dbb2b5aa68','觸事  其二','虞儔','宋','宋诗','song-poetry','','[]','綠匣何煩至，黄衣尚有云。',48,'全唐诗/poet.song.153000.json','["綠匣何煩至，黄衣尚有云。", "催科寧是拙，稼穡亦良勤。", "當念溝中瘠，難專柱後文。", "誰令公喜怒，鴈鶩政紛紛。"]'),
('a1193a52-b8f3-43f1-af63-8e98482881ca','歐公詩有云俸優食飽力不用官閒日永睡莫興因廣之','虞儔','宋','宋诗','song-poetry','','[]','日長官事少，食飽俸錢優。',48,'全唐诗/poet.song.153000.json','["日長官事少，食飽俸錢優。", "宴坐香凝篆，欲眠書枕頭。", "莫知斯我貴，此外更何求。", "畢竟歸田是，他鄉莫久留。"]'),
('639045cf-bf88-4eab-9fb1-dbb7b17bcc86','偶成二詩  其一','虞儔','宋','宋诗','song-poetry','','[]','閒處田園好，愁邊歲月催。',48,'全唐诗/poet.song.153000.json','["閒處田園好，愁邊歲月催。", "事多違壯志，吾亦愧無材。", "有底金千鋝，無何酒一盃。", "漫憑詩遣興，情至却生哀。"]'),
('88f79fa2-c6c1-4b7f-ae6b-622bce252b2e','偶成二詩  其二','虞儔','宋','宋诗','song-poetry','','[]','今夕知何夕，吾年且暮年。',48,'全唐诗/poet.song.153000.json','["今夕知何夕，吾年且暮年。", "勞生斫桂斧，游宦逆風船。", "幸不愁婚嫁，何須問計然。", "男兒有門戶，溫飽故隨緣。"]'),
('568fb1f2-b082-48ca-ba48-30f0bb977a2a','偶和萬舍人中秋有月無客有酒無殽韻','虞儔','宋','宋诗','song-poetry','','[]','積陰成久雨，浹日掩三辰。',48,'全唐诗/poet.song.153000.json','["積陰成久雨，浹日掩三辰。", "吏已疲祈禱，天方殺怒嗔。", "但愁雲似墨，那顧月如銀。", "辜負中秋約，姮娥莫妬人。"]'),
('db5c0b2b-d1b0-4b00-88c4-34600b346c9b','即事  其一','虞儔','宋','宋诗','song-poetry','','[]','天末孤鴻遠，園荒一徑深。',48,'全唐诗/poet.song.153000.json','["天末孤鴻遠，園荒一徑深。", "畦蔬供小摘，家釀慰孤斟。", "齋日渾無事，春天故作陰。", "濬池兼插柳，取次見吾心。"]'),
('51eeb408-c826-4218-b76c-092d3ac2e10d','即事  其二','虞儔','宋','宋诗','song-poetry','','[]','問訊鶑猶懶，尋芳花較遲。',48,'全唐诗/poet.song.153000.json','["問訊鶑猶懶，尋芳花較遲。", "忽驚雷送雨，漸喜水平池。", "竊祿慙無補，歸耕未有期。", "春工誰道巧，不染鬢成絲。"]'),
('19b870e9-c637-4062-ad40-7354aabe7de2','即事  其三','虞儔','宋','宋诗','song-poetry','','[]','已是春光晚，那堪雨氣昏。',48,'全唐诗/poet.song.153000.json','["已是春光晚，那堪雨氣昏。", "數莖驚白髮，萬感集清樽。", "才力須時展，功名有命存。", "眼前何足校，一笑任乾坤。"]'),
('1e933ba6-4729-41a0-ae26-1e9e13b66d90','即事  其四','虞儔','宋','宋诗','song-poetry','','[]','酷吏人同疾，流民天亦憐。',48,'全唐诗/poet.song.153000.json','["酷吏人同疾，流民天亦憐。", "麥登收兩倍，蠶好得三眠。", "况是寬征賦，那憂有俗緣。", "眼前百事好，買酒答豐年。"]'),
('651b0fd3-7b3f-42e4-b64e-2121ae80e573','舟中','虞儔','宋','宋诗','song-poetry','','[]','寒日移陰短，清溪放溜遲。',48,'全唐诗/poet.song.153000.json','["寒日移陰短，清溪放溜遲。", "歸田真晚矣，泛宅欲何之。", "鴻送天邊目，山橫雪後眉。", "詩中無限興，一一報公知。"]'),
('b9ef7aa3-e015-4b73-bdc4-fc68eb9cca91','舟中睡起','虞儔','宋','宋诗','song-poetry','','[]','望外星占婺，年餘水記苕。',48,'全唐诗/poet.song.153000.json','["望外星占婺，年餘水記苕。", "去思誰結戀，來暮豈聞謠。", "季布從渠毀，馮唐莫我招。", "舟中無一事，睡足有今朝。"]'),
('5ae2c1f6-b5be-46e7-9fce-6364c83424c1','和陳德章春日送客  其一','虞儔','宋','宋诗','song-poetry','','[]','年華看鬢上，春事轉頭中。',48,'全唐诗/poet.song.153000.json','["年華看鬢上，春事轉頭中。", "羯鼓催花雨，虹橋送客風。", "未須愁酒債，政復坐詩窮。", "誰識揮絃意，寥寥寄遠鴻。"]'),
('ceeac67c-2c8a-47b0-990d-7ca791d8edfc','和陳德章春日送客  其二','虞儔','宋','宋诗','song-poetry','','[]','花柳無多事，陰晴不必天。',48,'全唐诗/poet.song.153000.json','["花柳無多事，陰晴不必天。", "急舂村外雨，並舍晚來煙。", "白墮先春手，紅粧最妙年。", "龐翁雖不出，門巷得相連。"]'),
('5dc5d335-5607-496f-baea-60b3d1d6ef28','和陳德章春日送客  其三','虞儔','宋','宋诗','song-poetry','','[]','勝事壺觴裏，韶華杖履中。',48,'全唐诗/poet.song.153000.json','["勝事壺觴裏，韶華杖履中。", "歌情千里月，花信幾番風。", "取友須三益，論文笑五窮。", "含含歌麥秀，廡下老梁鴻。"]'),
('fbd86ee4-789b-4f81-ab1e-4de11503400c','和陳德章春日送客  其四','虞儔','宋','宋诗','song-poetry','','[]','歲月斜川路，風流杜曲天。',48,'全唐诗/poet.song.153000.json','["歲月斜川路，風流杜曲天。", "過牆紅杏雨，低戶綠楊烟。", "鴻鵠今千里，鶑花又一年。", "陽春慙屬和，五字得珠連。"]'),
('93fc0064-874d-49aa-b12d-f0c5089a7e1c','舟中冬至','虞儔','宋','宋诗','song-poetry','','[]','陰陽消長際，新舊送迎中。',48,'全唐诗/poet.song.153000.json','["陰陽消長際，新舊送迎中。", "異縣他鄉泊，天時人事同。", "世方期道泰，我豈坐途窮。", "兒女番爲壽，衰顔借酒紅。"]'),
('16a067ec-71a7-444d-b456-7ffb9b042458','和林卿盤隠詩  其一','虞儔','宋','宋诗','song-poetry','','[]','溪山千里勝，花木四時春。',96,'全唐诗/poet.song.153000.json','["溪山千里勝，花木四時春。", "家釀新來熟，園收舊不貧。", "上都無闕事，空谷有佳人。", "天下滔滔者，誰能此問津。", "般礴五千卷，辛勤四十春。", "向來憂國意，肯顧在家貧。", "丘壑寧違性，功名恐悞人。", "似聞歸賦後，喜氣日津津。"]'),
('0f5af325-35c9-4d37-87b7-814a59784fd3','和林卿盤隠詩  其二','虞儔','宋','宋诗','song-poetry','','[]','倘佯三徑裏，陶冶一家春。',48,'全唐诗/poet.song.153000.json','["倘佯三徑裏，陶冶一家春。", "筆下文爲富，胸中道不貧。", "窮通知有命，行止信非人。", "第恐歸田計，翻成要路津。"]'),
('601658e0-3dfb-49a5-a75d-4de74a738a27','和沈祭酒韻','虞儔','宋','宋诗','song-poetry','','[]','詩思花前發，春光眼底來。',48,'全唐诗/poet.song.153000.json','["詩思花前發，春光眼底來。", "一區聊自適，三徑爲誰開。", "聖主方求舊，清時况急才。", "鳳池波自暖，鷗鷺勿多猜。"]'),
('6802eed0-d0ef-4068-a899-4078bc1a9c20','和勸農詩  其一','虞儔','宋','宋诗','song-poetry','','[]','世故偶夷險，吾行無介通。',48,'全唐诗/poet.song.153000.json','["世故偶夷險，吾行無介通。", "誰爲青眼舊，人想翠眉濃。", "風雨花時過，溪山酒聖中。", "何時蓮蕩裏，共把碧彎筒。"]'),
('30cc6ebd-845e-408d-bfa8-676772c01758','和勸農詩  其二','虞儔','宋','宋诗','song-poetry','','[]','節物常流轉，人情作異同。',48,'全唐诗/poet.song.153000.json','["節物常流轉，人情作異同。", "頗期千載後，寧忍一朝窮。", "隔葉饒晴哢，遊絲罥墮紅。", "老春何足恨，結習本來空。"]'),
('4f0a48c0-a483-4c18-9695-1fc595e45fc2','罷郡遊何山','虞儔','宋','宋诗','song-poetry','','[]','尋山多勝概，輟棹偶留連。',48,'全唐诗/poet.song.153000.json','["尋山多勝概，輟棹偶留連。", "南浦渾無緒，東風忽放顛。", "蹊成桃李退，人去蝶蜂喧。", "氣味餘禪榻，煎茶竹裏烟。"]'),
('27894ea8-744e-4bec-8f09-7dc9b110f28a','賦芍藥','虞儔','宋','宋诗','song-poetry','','[]','紛紛時世粧，爭欲媚韶光。',48,'全唐诗/poet.song.153000.json','["紛紛時世粧，爭欲媚韶光。", "正值三春暮，能教一國狂。", "妖嬈欺酒聖，豪麗僣花王。", "不料東風惡，飄零亦太忙。"]'),
('2017a8e9-f719-4135-9135-0fc915b6d880','晚花','虞儔','宋','宋诗','song-poetry','','[]','花開春已去，春在此中藏。',48,'全唐诗/poet.song.153000.json','["花開春已去，春在此中藏。", "可恨芳菲晚，翻令氣味長。", "繁陰供翠幄，輕暑絢紅粧。", "莫起後時嘆，時來未遽央。"]'),
('58b06b39-666d-44e2-9896-9fb9fdcdf247','往瓜洲護使客回程','虞儔','宋','宋诗','song-poetry','','[]','北使朝京闕，東淮領計臺。',48,'全唐诗/poet.song.153000.json','["北使朝京闕，東淮領計臺。", "舟師雖夙戒，頓食更頻催。", "州縣愁勞費，風霜困往來。", "和盟終不贊，舊好政無猜。"]'),
('9d5b4cda-1dfc-4729-8eda-c25918653999','新晴','虞儔','宋','宋诗','song-poetry','','[]','凹沼幾平岸，晴雲故出溪。',48,'全唐诗/poet.song.153000.json','["凹沼幾平岸，晴雲故出溪。", "已添新綠潤，尚有暗芳栖。", "風雨將春去，樽罍欠日携。", "歸田吾未果，愧爾杜鵑啼。"]'),
('921301b2-68e9-4a4f-9fa2-105d99342a74','秋雨','虞儔','宋','宋诗','song-poetry','','[]','陰風攪林壑，驟雨倒江湖。',48,'全唐诗/poet.song.153000.json','["陰風攪林壑，驟雨倒江湖。", "白日不覺沒，繁雲何處無。", "樓吟凉筆硯，溪夢亂菰蒲。", "聞說京華甚，污泥入敝廬。"]'),
('540ed640-c15d-497f-b5be-efad533e6fe1','喜雨','虞儔','宋','宋诗','song-poetry','','[]','雲釀南山雨，風勾北牖凉。',48,'全唐诗/poet.song.153000.json','["雲釀南山雨，風勾北牖凉。", "綠蒲澄水石，丹藕浄池塘。", "冷客頻牽興，炎官罷鬭强。", "無波真古井，此味淡中長。"]'),
('84abf7ec-8c02-4e40-9c62-64831c05e6d2','和鮑倅首夏聞鶑','虞儔','宋','宋诗','song-poetry','','[]','芳草池塘晚，垂楊院宇清。',48,'全唐诗/poet.song.153000.json','["芳草池塘晚，垂楊院宇清。", "夢回初恨蝶，春去懶聞鶑。", "翠幄何須戀，金丸恐見驚。", "一枝棲更穩，好去鳳凰城。"]'),
('d55003b1-6334-41a2-b8e9-c7e4845b7b78','道場山勸農','虞儔','宋','宋诗','song-poetry','','[]','粵在千峯頂，重來二月天。',48,'全唐诗/poet.song.153000.json','["粵在千峯頂，重來二月天。", "雨紅晴尚濕，波碧遠相連。", "旌旆行雲裏，樓臺落照邊。", "一犁農事起，胡不早歸田。"]'),
('b9f75d46-2bda-4ee2-8242-ca5a22120412','勸農  其一','虞儔','宋','宋诗','song-poetry','','[]','郊原春已半，溝洫水先通。',48,'全唐诗/poet.song.153000.json','["郊原春已半，溝洫水先通。", "勸相寧文具，歸耕亦興濃。", "一犁新雨後，小隊亂山中。", "粗識斯民意，何須教缿筒。"]'),
('1be59765-9146-4919-94f3-e2289bd18dbb','勸農  其二','虞儔','宋','宋诗','song-poetry','','[]','慚愧荒三徑，羈棲漫一同。',48,'全唐诗/poet.song.153000.json','["慚愧荒三徑，羈棲漫一同。", "青春非老事，白眼有途窮。", "柳暗鴉藏綠，花飄燕蹴紅。", "平生孔北海，未放酒樽空。"]'),
('e262782f-3127-49fd-96f4-701fff77dd0c','喜雨','虞儔','宋','宋诗','song-poetry','','[]','雲氣翻車蓋，天河注瓦溝。',48,'全唐诗/poet.song.153000.json','["雲氣翻車蓋，天河注瓦溝。", "滂沱三日雨，登濟一年秋。", "旱火掃無迹，狂雷怒不收。", "腐儒營一飽，卒歲恐優游。"]'),
('fe954c7c-02ed-4f8b-9568-5a893e01123d','初夏凹沼獨坐','虞儔','宋','宋诗','song-poetry','','[]','芳草沿堤長，圓荷出水遲。',48,'全唐诗/poet.song.153000.json','["芳草沿堤長，圓荷出水遲。", "倚欄風醒酒，岸幘雨催詩。", "鸂鶒巢安在，仙鳬舄詎期。", "遊鱼知我意，吹沫弄清漪。"]'),
('8451c37f-2cde-4317-8d7b-72483b7ed528','縣中迎石金山甘靈大士就放生池祈雨早上偕簿尉往炷香  其一','虞儔','宋','宋诗','song-poetry','','[]','甘雨祈三日，香雲捧一龕。',48,'全唐诗/poet.song.153000.json','["甘雨祈三日，香雲捧一龕。", "依歸甘露滅，珍重蔚頭藍。", "官事何當了，枯禪且罷參。", "蓮花初出水，朝日借紅酣。"]'),
('2e4d4298-b742-4b8f-b5b3-66273eb35722','縣中迎石金山甘靈大士就放生池祈雨早上偕簿尉往炷香  其二','虞儔','宋','宋诗','song-poetry','','[]','夜起占星畢，朝趨禮佛龕。',48,'全唐诗/poet.song.153000.json','["夜起占星畢，朝趨禮佛龕。", "擁橋蓮墜粉，縈沼水揉藍。", "屏翳何須靳，登伽不受參。", "懸知天欲雨，蟻戰已酣酣。"]'),
('ddee8cd9-a0b7-48a6-9696-fe442aa73414','再用韻謝王簿來詩褒借過當之意  其一','虞儔','宋','宋诗','song-poetry','','[]','黄嬭朝千卷，書燈夜一龕。',48,'全唐诗/poet.song.153000.json','["黄嬭朝千卷，書燈夜一龕。", "玄文今尚白，袍色故應藍。", "簿領聊爾耳，朝班行矣參。", "驚雷雖破柱，午寢不妨酣。"]'),
('4c269fc7-41f3-4402-858d-435ac0d2b3b5','再用韻謝王簿來詩褒借過當之意  其二','虞儔','宋','宋诗','song-poetry','','[]','旱魃爭攘袂，羣龍僅守龕。',48,'全唐诗/poet.song.153000.json','["旱魃爭攘袂，羣龍僅守龕。", "雲峯疑燎火，天色轉澄藍。", "甘露元同注，叢林莫遍參。", "新來焦渴甚，無夢到沉酣。"]'),
('c0123d1f-0fbc-4338-8186-3b80b1790213','過登源英濟廟祈雨','虞儔','宋','宋诗','song-poetry','','[]','古廟出靈響，吾儕非過求。',48,'全唐诗/poet.song.153000.json','["古廟出靈響，吾儕非過求。", "山田雖欠雨，陂水尚通溝。", "出郭漸無日，祈年望有秋。", "豚蹄真狹甚，明信或堪羞。"]'),
('910d531c-5b8f-4a77-8715-90daa2b69ec0','青山買舟','虞儔','宋','宋诗','song-poetry','','[]','落日千烏外，青山一望中。',48,'全唐诗/poet.song.153000.json','["落日千烏外，青山一望中。", "買舟羣僕喜，兀坐與誰同。", "旅店孤煙起，田家曲港通。", "鷗盟暫時乞，又踏軟塵紅。"]'),
('979b4966-e562-468a-802d-c1e19b410b5f','喜雨','虞儔','宋','宋诗','song-poetry','','[]','雨脚初鳴屋，風頭忽轉廊。',48,'全唐诗/poet.song.153000.json','["雨脚初鳴屋，風頭忽轉廊。", "餘凉生簟枕，好夢到池塘。", "黄嬭真三窟，青奴得兩忘。", "功名休恨晚，身世一藤床。"]'),
('734dddd3-2213-45c9-ada1-6c61fc417c69','七月初得雨後大有秋意','虞儔','宋','宋诗','song-poetry','','[]','好雨真無價，炎天不易求。',48,'全唐诗/poet.song.153000.json','["好雨真無價，炎天不易求。", "十全成稔歲，一上作凉秋。", "吏逭陂塘責，民寬溝壑憂。", "催科無奈拙，此去恐優游。"]'),
('1a56f7a5-2c25-4288-805c-d5c17a2df181','除夜書懷','虞儔','宋','宋诗','song-poetry','','[]','吳楚鄉風異，悲歡物態多。',48,'全唐诗/poet.song.153000.json','["吳楚鄉風異，悲歡物態多。", "歲華驚晚暮，吾道恐蹉跎。", "莫唱黄鷄曲，寧爲白石歌。", "明年六十一，不醉待如何。"]'),
('ae6de2bc-f1e3-4708-b079-bdee374bc777','葉大猷挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','月旦評猶在，題輿事已非。',48,'全唐诗/poet.song.153000.json','["月旦評猶在，題輿事已非。", "田園寧作計，鷗鷺本忘機。", "此地期相款，終天願忽違。", "西風送丹旐，老淚不禁揮。"]'),
('976b7e65-a105-44cc-adae-b0ab10d768c0','葉大猷挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','非意俱飄瓦，高懷只杜門。',48,'全唐诗/poet.song.153000.json','["非意俱飄瓦，高懷只杜門。", "誰云九地底，猶抱十年冤。", "未盡滄浪興，難招楚些魂。", "傷心追往事，愁極却無言。"]'),
('2154a1c4-d4e2-4ec8-91d8-279047a6d32e','淮西趙漕子固挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','疏抗廷臣右，經傳弟子行。',48,'全唐诗/poet.song.153000.json','["疏抗廷臣右，經傳弟子行。", "江淮歸德政，蠻貊誦文章。", "世路風波惡，仙家日月長。", "西林曾有約，楚挽莫凄凉。"]'),
('c6a946e1-e866-40a6-8202-7739fd77fee2','淮西趙漕子固挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','西帥予曾忝，無何馬首東。',48,'全唐诗/poet.song.153000.json','["西帥予曾忝，無何馬首東。", "計臺初不遠，交篆竟成空。", "夜壑移舟半，淮山落木中。", "堂堂寧復見，丹旐獵霜風。"]'),
('ef360563-989e-4f8c-9c4a-7637543d2f78','楊伯賢挽詩','虞儔','宋','宋诗','song-poetry','','[]','月記鄉評好，年推輩行尊。',48,'全唐诗/poet.song.153000.json','["月記鄉評好，年推輩行尊。", "巨山曾入夢，楚些莫招魂。", "太息馳駒隙，渾疑隠鹿門。", "他時耆舊傳，知有姓名存。"]'),
('2cef3c70-aaa8-4696-bde1-a3ef1a5b47d6','王彥謨挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','蚤歲游三舍，明經束九師。',48,'全唐诗/poet.song.153000.json','["蚤歲游三舍，明經束九師。", "聲名雖烜赫，科第竟差池。", "之子能傳業，興宗會有時。", "只今官冢地，看出印纍纍。"]'),
('7c6c5c6d-b734-4d4c-9337-7c276fa55a11','王彥謨挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','潤屋金千鋝，浮生黍一炊。',48,'全唐诗/poet.song.153000.json','["潤屋金千鋝，浮生黍一炊。", "里閭思長者，門戶托佳兒。", "華表終來鶴，支牀尚有龜。", "洗心元悟易，杯水漫勞持。"]'),
('5421d3ab-f27b-471d-8b12-8a2ecb07ffc0','章解元挽詩','虞儔','宋','宋诗','song-poetry','','[]','詩禮傳家舊，田園晚歲豐。',48,'全唐诗/poet.song.153000.json','["詩禮傳家舊，田園晚歲豐。", "月評猶未改，露挽遽成空。", "曲巷連桑蔭，幽巖長桂叢。", "南坡吾獨往，無復訪鄰翁。"]'),
('6b2548c5-c713-4b52-86e2-b585a99f19c6','楊仲才挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','孝友懷宗族，謙恭接里閭。',48,'全唐诗/poet.song.153000.json','["孝友懷宗族，謙恭接里閭。", "克家千樹橘，教子萬籤書。", "釀酒偏延客，能詩亦起予。", "天胡中不壽，埋玉恨何如。"]'),
('1a495b18-9dcf-4ddd-8870-e01a0d789cfb','楊仲才挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','別意經時序，音書缺置郵。',48,'全唐诗/poet.song.153000.json','["別意經時序，音書缺置郵。", "子來方問疾，傲吏已移舟。", "華屋生存處，佳城身後謀。", "望風懷執紼，老淚爲君流。"]'),
('0af410eb-1073-441f-bcde-8bda3e357fb2','和太守','虞儔','宋','宋诗','song-poetry','','[]','豈弟循良守，功成意益謙。',48,'全唐诗/poet.song.153000.json','["豈弟循良守，功成意益謙。", "尋求七字律，想見一生廉。", "活火烹茶蕊，消愁媚酒帘。", "南樓月華好，吹笛指須纖。"]'),
('e6bb3119-1c29-4b41-a390-9d741893fad8','寒食風雨呈林正甫','虞儔','宋','宋诗','song-poetry','','[]','不住風和雨，思歸日似年。',48,'全唐诗/poet.song.153000.json','["不住風和雨，思歸日似年。", "他鄉寒食淚，深院落花天。", "午枕飛蝴蝶，春山叫杜鵑。", "有誰憐趙壹，骯髒倚門邊。"]'),
('8a2f5851-b47e-4409-87d1-5e125fa51a61','春大閲望郡圃齊雲樓悼亡','虞儔','宋','宋诗','song-poetry','','[]','官事誰能了，浮生迹易陳。',48,'全唐诗/poet.song.153000.json','["官事誰能了，浮生迹易陳。", "齊雲連綠蔭，和淚送青春。", "緩带空凝月，憑欄不見人。", "只應曾到處，愁極倍精神。"]'),
('2dba7f47-e265-4fff-801d-9d9f8518a971','三月初一日晴色甚快人意晚宿撮石嶺陳氏書院','虞儔','宋','宋诗','song-poetry','','[]','昨晚雨不止，今朝天假晴。',48,'全唐诗/poet.song.153000.json','["昨晚雨不止，今朝天假晴。", "路乾里堠縮，人健板輿輕。", "父老驚相顧，親朋漸出迎。", "端知華表鶴，珍重故鄉情。"]'),
('733486ce-1025-4152-ba08-099dcfce5022','喜雨','虞儔','宋','宋诗','song-poetry','','[]','梅雨知時節，農家喜若何。',48,'全唐诗/poet.song.153000.json','["梅雨知時節，農家喜若何。", "積薪蠶下箔，鋤水稻分窠。", "綠有笋成竹，黄無麥作蛾。", "一春嘗苦旱，三日未云多。"]'),
('e90699be-43df-4978-b0d2-a88a9b20f8c4','次韻漢老弟對月滿飲','虞儔','宋','宋诗','song-poetry','','[]','鶴髮金桃母，蛾眉萼綠華。',48,'全唐诗/poet.song.153000.json','["鶴髮金桃母，蛾眉萼綠華。", "月圓香度桂，飲罷燭生花。", "何惜尊空酒，能令春滿家。", "更邀重九菊，醉裏墮烏紗。"]'),
('561e8c32-d259-4347-b371-fc947c8b9e0d','和孫尉登空翠堂鼓琴酌茗有懷冷令二首  其一','虞儔','宋','宋诗','song-poetry','','[]','樓畔晴嵐翠拂空，天教我輩一尊同。',64,'全唐诗/poet.song.153000.json','["樓畔晴嵐翠拂空，天教我輩一尊同。", "只愁楊柳歸來綠，却嘆桃花去後紅。", "春事又還觴詠裏，人生正墮別離中。", "不堪搔首東南望，獨立驚風嘆斷鴻。"]'),
('07955de8-db1e-43c9-961a-9c3cabfc4a33','和孫尉登空翠堂鼓琴酌茗有懷冷令二首  其二','虞儔','宋','宋诗','song-poetry','','[]','花滿芳洲月滿樓，留連從事到青州。',64,'全唐诗/poet.song.153000.json','["花滿芳洲月滿樓，留連從事到青州。", "巧分茗椀消磨睡，靜拂琴徽斷送愁。", "寒食烟花知有幾，上元燈火恰纔收。", "冷官已辦江頭費，爛醉春風典破裘。"]'),
('49a5c0c8-1fbd-4d07-86b3-e80ffc1ba912','絕市無糯旋挼青穗日熬以釀戲成','虞儔','宋','宋诗','song-poetry','','[]','種秫無多望歲穰，無功何日果還鄉。',64,'全唐诗/poet.song.153000.json','["種秫無多望歲穰，無功何日果還鄉。", "尚無彭澤五十畝，安得謫仙三萬場。", "挼穗昔聞今始見，撥醅未熟且先嘗。", "今年太歲還非酉，慚愧鄰家僅得漿。"]'),
('10ff802d-7dcc-4356-8528-7f1a1244ee54','十一月二十八日用後山詩韻','虞儔','宋','宋诗','song-poetry','','[]','日暮江東天一涯，孤雲飛處路何賒。',64,'全唐诗/poet.song.153000.json','["日暮江東天一涯，孤雲飛處路何賒。", "雪將入臘未破白，梅過先春競著花。", "過眼光陰渾是客，滿懷風雨政思家。", "何如醉裏都忘却，擬向窮途問麴車。"]'),
('abb99b41-45ab-430d-bbfc-eb308241e033','石芥','虞儔','宋','宋诗','song-poetry','','[]','杯酒流行四座傾，此君風味始崢嶸。',64,'全唐诗/poet.song.153000.json','["杯酒流行四座傾，此君風味始崢嶸。", "搗殘薑桂嫌無韻，掃盡茅柴不到酲。", "崖谷野人羞自薦，膏粱公子莫知名。", "攀蘿採擷天寒甚，誰念終朝掬不盈。"]'),
('15cde56b-c6e7-4e78-a4ed-e2cf4269c814','林正甫與子中春並命爲御史正甫按刑浙東道別去兼旬而予銜命按視宮陵經越上獲一再款語臨行有詩因次其韻  其一','虞儔','宋','宋诗','song-poetry','','[]','烏臺當日選名流，僉謂君才與我優。',64,'全唐诗/poet.song.153000.json','["烏臺當日選名流，僉謂君才與我優。", "公議略伸君便去，上恩未報我寧留。", "自憐秦緩難爲疾，豈意良霄尚有蕕。", "况是親年當喜懼，欲將歸計問扁舟。"]'),
('fd0ec14c-a498-4bd0-9db0-6f8b9cf4bdb7','林正甫與子中春並命爲御史正甫按刑浙東道別去兼旬而予銜命按視宮陵經越上獲一再款語臨行有詩因次其韻  其二','虞儔','宋','宋诗','song-poetry','','[]','銜命宮陵偶一回，山陰道上得徘徊。',64,'全唐诗/poet.song.153000.json','["銜命宮陵偶一回，山陰道上得徘徊。", "溟鵬好在思摶擊，乘鴈何嘗計去來。", "萬壑千巖况秋色，明珠白璧更塵埃。", "相逢未穩還爲別，一段詩愁費剪裁。"]'),
('cf51e3ae-56f5-471a-80d5-6b4020f07310','秋釋奠于學萬舍人示詩次韻以酬','虞儔','宋','宋诗','song-poetry','','[]','昔年泮水忽專城，文會何妨一再盟。',64,'全唐诗/poet.song.153000.json','["昔年泮水忽專城，文會何妨一再盟。", "已媿簿書成俗吏，却陳俎豆見諸生。", "一時同隊魚猶在，千載重來鶴更清。", "况有卞峯青眼舊，試登傑閣快雙明。"]'),
('01b5866f-e291-49fa-8b4c-3b6eae379b77','脚婆子','虞儔','宋','宋诗','song-poetry','','[]','此姥原無妬與嗔，平生氣類竹夫人。',64,'全唐诗/poet.song.153000.json','["此姥原無妬與嗔，平生氣類竹夫人。", "蛾眉漸遣溫柔夢，鴟腹猶疑見在身。", "包裹形模才一衲，薰蒸湯沸穩相親。", "承恩脚底非由貌，啟沃憐儂夜夜新。"]'),
('648de05d-77a9-41ae-8517-60d34e905222','三十日乃耘老弟生朝余護客舟行高郵道中不勝戀戀之情因賦鄙句以寄之','虞儔','宋','宋诗','song-poetry','','[]','愛日初看一線遲，門弧喜氣又相隨。',64,'全唐诗/poet.song.153000.json','["愛日初看一線遲，門弧喜氣又相隨。", "遥知綺席團欒處，正是蓬窗寂寞時。", "節愛堂中先遣信，富陽驛裏舊吟詩。", "生涯已是千奴辦，且泛新陽入壽巵。"]'),
('9d71346d-9125-4272-bb3a-e9c2c02ce37f','仲本別去才半月爾瞻戀不啻如隔歲奉此寄懷','虞儔','宋','宋诗','song-poetry','','[]','紛紛覆雨與翻雲，只有吳人不世情。',64,'全唐诗/poet.song.153000.json','["紛紛覆雨與翻雲，只有吳人不世情。", "窮迫每憐長袖舞，別離愁聽短歌行。", "春波碧草連南浦，朝雨垂楊拂渭城。", "絲竹未應陶寫得，向來肝膽爲渠傾。"]'),
('18db6f26-6acb-453e-8723-10328a165a66','仲本索歸甚遽前詩送行言之不足見示和篇覽之益用慨然再用前韻','虞儔','宋','宋诗','song-poetry','','[]','幸有綈袍戀故人，不應回棹遽忘情。',64,'全唐诗/poet.song.153000.json','["幸有綈袍戀故人，不應回棹遽忘情。", "相逢且話十年事，此別又成千里行。", "歸去我猶慚靖節，催科誰解恕陽城。", "黄堂今有仁人在，璧水當年蓋已傾。"]'),
('0012f30e-9423-405f-a7c3-a8014b9f2add','別後寄主簿','虞儔','宋','宋诗','song-poetry','','[]','塵埃襞積顔如甲，丹墨紛綸眼有花。',64,'全唐诗/poet.song.153000.json','["塵埃襞積顔如甲，丹墨紛綸眼有花。", "君去何人堪共語，秋來無夢不還家。", "飄零酒醆今真止，冷淡詩筒不復誇。", "莫使音書成斷絕，風前鴈字政橫斜。"]'),
('043bfa1c-694a-4e54-80d9-bf1557706e99','余假守是邦所幸今夏雨澤適中高下咸宜客有謂今秋一稔前此數歲未之有也果爾則幸矣因喜而賦豐年之詩','虞儔','宋','宋诗','song-poetry','','[]','騷人墨客可無詩，正值秋郊刈穫時。',64,'全唐诗/poet.song.153000.json','["騷人墨客可無詩，正值秋郊刈穫時。", "此日三登殊可樂，向來半菽亦堪悲。", "家家芋栗兒童喜，處處鷄豚父老期。", "負郭有田歸去晚，婆娑拙守不勞麾。"]'),
('f3e047ff-e662-4362-9ada-116c395b3df2','除兵部侍郎賜带趁朝參','虞儔','宋','宋诗','song-poetry','','[]','幸叨持橐侍甘泉，敢意恩榮慰暮年。',64,'全唐诗/poet.song.153000.json','["幸叨持橐侍甘泉，敢意恩榮慰暮年。", "紫綬金章光照地，絲鞭玉勒喜朝天。", "兒曹莫起無魚嘆，人世難爲跨鶴仙。", "報國無功還自愧，直須及早决歸田。"]'),
('22fc89c7-5642-462e-b5e1-c45b002e79c0','王誠之分惠卧龍新茶數語爲謝','虞儔','宋','宋诗','song-poetry','','[]','卧龍驤首奮輕雷，一一槍旗次第開。',64,'全唐诗/poet.song.153000.json','["卧龍驤首奮輕雷，一一槍旗次第開。", "遽浼春風歸七椀，寧容卯酒困三盃。", "森嚴莫訝先嘗苦，雋永方知後味回。", "不羨金釵候湯眼，可能蕭寺略追陪。"]'),
('8b61b91a-b156-40a4-bcd8-e7d9c1ff42e8','謝周睎顔寄惠新芽','虞儔','宋','宋诗','song-poetry','','[]','摘鮮分送細茸茸，知在春山第幾重。',64,'全唐诗/poet.song.153000.json','["摘鮮分送細茸茸，知在春山第幾重。", "包裹雅宜青箬篰，寵珍寧羨赤囊封。", "䃺驚雪落巖前石，烹訝風生澗底松。", "堆案文書吾欲睡，頼渠喚醒小從容。"]'),
('e6b44d6a-8e87-445d-839d-a067a923fb9b','以蓮心茶送鞏使君小詩將之  其一','虞儔','宋','宋诗','song-poetry','','[]','未雨餘寒力尚嚴，巖前蚤見摘纖纖。',64,'全唐诗/poet.song.153000.json','["未雨餘寒力尚嚴，巖前蚤見摘纖纖。", "初嘗似带蓮心苦，迴味寧輸崖蜜甜。", "渴想清香凝燕寢，更餘黄卷亂牙籤。", "一甌幸入春風手，微草從今價亦添。"]'),
('771d349a-35e3-4c11-b37e-6eeb3868dd45','以蓮心茶送鞏使君小詩將之  其二','虞儔','宋','宋诗','song-poetry','','[]','採得蓮心苦更嚴，青裙白面退尖纖。',64,'全唐诗/poet.song.153000.json','["採得蓮心苦更嚴，青裙白面退尖纖。", "竹軒旋碾香塵散，槐夢初回齒頰甜。", "况是澄泉元带錫，自應佳句合編籤。", "直須陪侍揮談麈，習習清風兩腋添。"]'),
('a40805cb-26af-4794-8f41-0702ed98d05a','以酥煎小龍茶因成','虞儔','宋','宋诗','song-poetry','','[]','水分石鼎暮江寒，灰撥磚爐白雪乾。',64,'全唐诗/poet.song.153000.json','["水分石鼎暮江寒，灰撥磚爐白雪乾。", "蟹眼已收魚眼出，酥花翻作乳花團。", "撐腸尚有書千卷，枵腹無憂食一簞。", "只欠綠珠煎點在，詩情寧使愧麤官。"]'),
('c1cabb70-e577-49d7-b59c-63ee82203105','有懷漢老弟  其一','虞儔','宋','宋诗','song-poetry','','[]','先自無聊懶出門，南坡一到一思君。',64,'全唐诗/poet.song.153000.json','["先自無聊懶出門，南坡一到一思君。", "松筠俱是栽培力，亭榭無非卜築勤。", "本約暮年栖息共，豈期中道死生分。", "風前試數當時鴈，一鴈今歸何處雲。"]'),
('f4641e4b-d141-4a80-8d19-7b5ff003576c','有懷漢老弟  其二','虞儔','宋','宋诗','song-poetry','','[]','缺落槿籬須補綴，稀疎菜甲欠鋤耘。',64,'全唐诗/poet.song.153000.json','["缺落槿籬須補綴，稀疎菜甲欠鋤耘。", "芙蓉泣露坡頭見，桂子飄香月下聞。", "策杖却愁成獨往，舉杯誰與醉濃芬。", "歡悰莫訝年來減，觸目無非是憶君。"]'),
('f26308b9-75fe-4783-a9c1-5d6700302304','有懷漢老弟  其三','虞儔','宋','宋诗','song-poetry','','[]','村童先遣掃柴門，檢校園芳待置尊。',64,'全唐诗/poet.song.153000.json','["村童先遣掃柴門，檢校園芳待置尊。", "叢菊稍斑漙露點，芙蓉已带著霜痕。", "詩篇縱好成孤諷，心事憑誰與共論。", "已是西風悲落木，那堪幽獨更銷魂。"]'),
('0db69c5c-be26-4daa-a1ce-62a66e61c9d4','有懷廣文俞同年  其一','虞儔','宋','宋诗','song-poetry','','[]','宦遊霜宿與風餐，環郭青山豈曰盤。',64,'全唐诗/poet.song.153000.json','["宦遊霜宿與風餐，環郭青山豈曰盤。", "餘暇每思親丈席，新凉政喜入中單。", "交情老去才方見，世事年來亦飽看。", "顔色想君如李白，却疑明月滿重欒。"]'),
('6a5f7e13-b8bf-403a-83aa-e13ac9d2e741','有懷廣文俞同年  其二','虞儔','宋','宋诗','song-poetry','','[]','客來愧乏牛心炙，茶罷空堆馬乳盤。',64,'全唐诗/poet.song.153000.json','["客來愧乏牛心炙，茶罷空堆馬乳盤。", "縱有詩篇慚和寡，了無心印可傳單。", "平生黄卷能忘味，晚歲青山未厭看。", "歸去吾廬吾亦愛，更須華屋羨雕欒。"]'),
('a8e771aa-1e67-4102-baae-01a516a39d2a','有懷廣文俞同年  其三','虞儔','宋','宋诗','song-poetry','','[]','祝君努力且加餐，世路羊腸政屈盤。',64,'全唐诗/poet.song.153000.json','["祝君努力且加餐，世路羊腸政屈盤。", "烹鯉何由問消息，割鷄政自困平單。", "書生說食真成癖，俗子疑人莫與看。", "搜攪枯腸有文字，玉州猶愛月團欒。"]'),
('feac4820-6763-4fab-9660-ca2bc7bcedcf','有懷廣文俞同年  其四','虞儔','宋','宋诗','song-poetry','','[]','萬山深處祇空餐，報贈慚無雙玉盤。',64,'全唐诗/poet.song.153000.json','["萬山深處祇空餐，報贈慚無雙玉盤。", "日晏僅餘晨粥半，夜凉更覺夏衾單。", "憐渠許國丹心在，付與窮途白眼看。", "它日鷄豚燕同社，不煩父老見思欒。"]'),
('72a9656d-cf80-4925-be41-3511d6b836be','旅懷上石似之郎中  其一','虞儔','宋','宋诗','song-poetry','','[]','妄意彈冠不作疎，向來曾是曳長裾。',64,'全唐诗/poet.song.153000.json','["妄意彈冠不作疎，向來曾是曳長裾。", "倚門慈母須微祿，當路羣公亦薦書。", "杜曲詩成還蹭蹬，河東賦在有吹噓。", "上林不敢棲高樹，斗水何妨置腐魚。"]'),
('8f749dd7-8177-436f-a4a3-4e3b62e3b2e9','旅懷上石似之郎中  其二','虞儔','宋','宋诗','song-poetry','','[]','騷人先自不禁秋，風雨相將作許愁。',64,'全唐诗/poet.song.153000.json','["騷人先自不禁秋，風雨相將作許愁。", "尚有壯懷因酒到，苦無佳思慕詩休。", "故鄉音信新來鴈，盡日笙歌誰氏樓。", "滿目黄花笑憔悴，未應回首沒江鷗。"]'),
('a4e23912-231a-4c32-8c1d-dd354f2de8f1','旅懷上石似之郎中  其三','虞儔','宋','宋诗','song-poetry','','[]','暮鵲投林意自深，向來一諾抵千金。',64,'全唐诗/poet.song.153000.json','["暮鵲投林意自深，向來一諾抵千金。", "面看逆旆有歸色，足望窮途無好音。", "歲晚更憐霜點鬢，夜寒除是月知心。", "政應老死何須惜，或有遺書備訪尋。"]'),
('3e50d8d1-cb36-4acd-b958-85086ca24179','余秋初離庭闈冬至猶未得歸夜讀宛丘先生秋日憶家詩輒次韻以述旅懷','虞儔','宋','宋诗','song-poetry','','[]','屈指西風閲歲華，半年行役苦思家。',64,'全唐诗/poet.song.153000.json','["屈指西風閲歲華，半年行役苦思家。", "綵衣歸去親闈好，畫角吹殘客夢賒。", "病裏中秋慵見月，醉中九日强簪花。", "朅來又過書雲候，節物催人一可嗟。"]'),
('0072fad2-0763-4243-a372-2d7894b36f77','初八日早出洪澤閘泛淮','虞儔','宋','宋诗','song-poetry','','[]','乾道年中再講和，當時議者厭干戈。',64,'全唐诗/poet.song.153000.json','["乾道年中再講和，當時議者厭干戈。", "長淮不管蛟龍怒，巨艦寧容鵝鸛過。", "歲晚民方愁道路，天寒我亦困風波。", "中流擊楫非無志，時運相違奈若何。"]'),
('bafc863a-5275-4fab-b185-0b72f0996e77','和俞孚仲遊南坡  其一','虞儔','宋','宋诗','song-poetry','','[]','列岫崢嶸棟宇連，平欄曲砌俯氓廛。',64,'全唐诗/poet.song.153000.json','["列岫崢嶸棟宇連，平欄曲砌俯氓廛。", "坐談風月三千里，直傍雲烟咫尺天。", "栗里尚懷陶靖節，竹林還想杜樊川。", "冷官幸有田園樂，笑謝蘇公乞酒錢。"]'),
('8d071574-9915-49a3-bc0a-06f017ba5c3b','和俞孚仲遊南坡  其二','虞儔','宋','宋诗','song-poetry','','[]','平昔相期汗漫遊，杖藜還肯訪林丘。',64,'全唐诗/poet.song.153000.json','["平昔相期汗漫遊，杖藜還肯訪林丘。", "君來便覺客不惡，我醉無言山自幽。", "柏子乍燃香拂袖，酪奴初試雪浮甌。", "慈親眉壽閒居好，誰道周南嘆滯留。"]'),
('0f8bc998-860b-4c88-be5d-b2e44ca06657','秋懷  其一','虞儔','宋','宋诗','song-poetry','','[]','登樓何處不陳詩，况是秋高木落時。',64,'全唐诗/poet.song.153000.json','["登樓何處不陳詩，况是秋高木落時。", "極目但隨歸鴈遠，老懷猶作故鄉悲。", "毋寧觴詠須前輩，有底功名亦後期。", "試問沈郎那得瘦，此心元不慕州麾。"]'),
('08b5f827-f70c-46b3-a0c3-73f2f4b54f8b','秋懷  其二','虞儔','宋','宋诗','song-poetry','','[]','結髮從來數亦奇，人言猿臂不遭時。',64,'全唐诗/poet.song.153000.json','["結髮從來數亦奇，人言猿臂不遭時。", "詩成杜曲何多興，賦舊蘭臺只浪悲。", "松菊不關年少事，冰霜曾與歲寒期。", "君看昨日凉風起，瓜上青蠅豈待麾。"]'),
('d86bff40-355c-4da4-b524-d11e4a0c13d9','余護客至盱眙忽有召命應廣文有詩相慶因用韻以謝','虞儔','宋','宋诗','song-poetry','','[]','尺一西來喚我歸，扁舟正是泛淮時。',64,'全唐诗/poet.song.153000.json','["尺一西來喚我歸，扁舟正是泛淮時。", "功名不復平生夢，物色能銷幾首詩。", "去國九年嗟已老，暮途雙節偶然持。", "一丘一壑真吾事，慚愧夔龍集鳳池。"]'),
('5f1a1eb1-a99c-487d-b84e-92a0864c8b1c','九日南坡兄弟同集','虞儔','宋','宋诗','song-poetry','','[]','曳杖携壺意頗長，了無風雨破重陽。',64,'全唐诗/poet.song.153000.json','["曳杖携壺意頗長，了無風雨破重陽。", "團欒飣座橙方綠，蓓蕾扶籬菊未黄。", "醉裏茱萸須遍插，尊前鴻鴈政成行。", "持盃快嚼誇强健，只恨雙螯未著霜。"]'),
('0d1d3836-288d-40a4-b426-d37557b39c27','和九日南坡小集','虞儔','宋','宋诗','song-poetry','','[]','風雨年時政不佳，山翁無酒向誰賒。',64,'全唐诗/poet.song.153000.json','["風雨年時政不佳，山翁無酒向誰賒。", "又還九日看黄菊，却喜晴天映碧紗。", "有底尊前悲節物，只應醉裏送生涯。", "明年徧插茱萸處，目斷西飛雁影斜。"]'),
('0d23bb43-1968-4fe6-b1d5-f4b4466a5f22','九日雨','虞儔','宋','宋诗','song-poetry','','[]','滿城風雨不禁秋，寧是先生懶出遊。',64,'全唐诗/poet.song.153000.json','["滿城風雨不禁秋，寧是先生懶出遊。", "採菊未成三徑約，看囊尚有一錢留。", "催租有底關詩思，落帽何妨付酒舟。", "今歲重陽還是客，湖山信美豈吾州。"]'),
('2d58239c-27dd-467a-869f-c145b744f8dd','和安撫王誠之給事重九日登高詩韻  其一','虞儔','宋','宋诗','song-poetry','','[]','登臨興引越山高，醉眼何曾識二豪。',64,'全唐诗/poet.song.153000.json','["登臨興引越山高，醉眼何曾識二豪。", "戲馬向來誇勝餞，卧龍此去記吾曹。", "風前短髮還羞杜，筆底新詩欲和陶。", "頼有蛤蜊風味在，固應居士笑盧遨。"]'),
('a711ed99-ad18-4c02-b0e4-072278c4cecc','和安撫王誠之給事重九日登高詩韻  其二','虞儔','宋','宋诗','song-poetry','','[]','秋鴈初飛幾點高，卧龍送目十分豪。',64,'全唐诗/poet.song.153000.json','["秋鴈初飛幾點高，卧龍送目十分豪。", "且容司馬吹紗帽，莫向參軍問騎曹。", "飲吸百川從酩酊，詩驅萬象入甄陶。", "菊花開日重陽是，有暇何妨更一遨。"]'),
('0991ea70-004e-47cd-9416-2d5f2b16bca4','和安撫王誠之給事重九日登高詩韻  其三','虞儔','宋','宋诗','song-poetry','','[]','眼橫秦望接雲高，不獨詩豪酒亦豪。',64,'全唐诗/poet.song.153000.json','["眼橫秦望接雲高，不獨詩豪酒亦豪。", "豈是過呼韓吏部，未應輕比漢功曹。", "尊空北海懷文舉，菊繞東籬念老陶。", "只恐詔歸天尺五，直須秉燭與公遨。"]'),
('50c5a0f9-b410-47c4-970f-0b88b82aa2eb','吳守相邀壯觀登高坐中出示佳篇因繼韻以酬','虞儔','宋','宋诗','song-poetry','','[]','壯觀登臨引興長，黄花亭下未經霜。',64,'全唐诗/poet.song.153000.json','["壯觀登臨引興長，黄花亭下未經霜。", "江平鴈到涵秋影，野曠鴉歸带夕陽。", "佳節欲酬須酩酊，今年在處說豐穰。", "楚雲不動淮山碧，且緩笙歌釂羽觴。"]'),
('2f14f0c3-96e0-41a4-bbc3-2096236b8377','吳守置酒壯觀爲登高之集因賦數語','虞儔','宋','宋诗','song-poetry','','[]','九日登高作勝遊，使君携客此遲留。',64,'全唐诗/poet.song.153000.json','["九日登高作勝遊，使君携客此遲留。", "天連楚觀風吹帽，木落淮山菊滿頭。", "何處臺前猶戲馬，幾人江上不驚鷗。", "年來只有身窮健，莫把茱萸浪自愁。"]'),
('d2a2ad19-fd1b-4bba-8a22-3edca32120a5','有懷南坡蓋雪阻旬日不到','虞儔','宋','宋诗','song-poetry','','[]','催年節物太頻頻，不涉南坡又一旬。',64,'全唐诗/poet.song.153000.json','["催年節物太頻頻，不涉南坡又一旬。", "蒼檜風前應强項，玉梅雪裏想精神。", "後車同載有名酒，折簡欲呼無可人。", "說似阿連須早計，鶑花休擬負青春。"]'),
('a7d4b963-9f67-4b10-9779-a2317133bb56','使北宿留盱眙','虞儔','宋','宋诗','song-poetry','','[]','浩蕩春風吹客愁，誰教楊柳繫行舟。',64,'全唐诗/poet.song.153000.json','["浩蕩春風吹客愁，誰教楊柳繫行舟。", "燕然有約終須到，淮水無情只漫流。", "蝶弄風光還草草，鴈傳消息底悠悠。", "梨花寒食無多日，且傍南山作勝遊。"]'),
('107f44c0-e441-43d8-8f90-899f2473c233','林正甫寺簿舉似所和判院徐同年詠所居詩且俾同賦','虞儔','宋','宋诗','song-poetry','','[]','二妙詩情僕命騷，戲驅萬象入甄陶。',64,'全唐诗/poet.song.153000.json','["二妙詩情僕命騷，戲驅萬象入甄陶。", "三休亭上頻回首，八節灘中穩著篙。", "巢幕祇應憐乳燕，戴山誰復笑靈鼇。", "也知廊廟須公等，寧羨華堂數仞高。"]'),
('fc2494ba-9da7-40d0-976a-290d841cb505','謝廣文俞同年惠䱥魚','虞儔','宋','宋诗','song-poetry','','[]','朝朝粗糲腐儒餐，清坐焚香篆印盤。',64,'全唐诗/poet.song.153000.json','["朝朝粗糲腐儒餐，清坐焚香篆印盤。", "早計何嘗爲溫飽，倦遊誰復念羈單。", "甕頭社酒欣方熟，籬下秋英漸可看。", "更寄拈魚君有味，鼎烹曾覆晉之欒。"]'),
('b841ae16-9883-4c16-8547-21692da12ca8','杜門絕俸呈陳倅','虞儔','宋','宋诗','song-poetry','','[]','家食年來嘆不充，支離受粟信無功。',64,'全唐诗/poet.song.153000.json','["家食年來嘆不充，支離受粟信無功。", "白頭慈母須微祿，青眼何人到寓公。", "未辦殺鷄留郭泰，更能給俸助盧仝。", "半生畫餠真堪笑，已戒奴星好送窮。"]'),
('4c15a4ce-a34c-4b15-b5ac-7f68e7196691','學錄李詩翁以詩訪予于乳溪之上且求縣學積俸偶值窘匱恨不能滿其意漫以數語送之第饑來不堪煮耳','虞儔','宋','宋诗','song-poetry','','[]','二月江南花氣昏，錦囊詩話喜重溫。',64,'全唐诗/poet.song.153000.json','["二月江南花氣昏，錦囊詩話喜重溫。", "百篇換去東湖骨，一醉招來北海魂。", "投老黄塵真左計，半生青眼向誰論。", "學宮乞俸能多少，驥子憐渠蚤候門。"]'),
('7293fa0d-0cdd-47ee-8b33-e7860dfb25b1','勸漢老弟飲酒','虞儔','宋','宋诗','song-poetry','','[]','尊前一醉莫辭頻，三萬場當歲十旬。',64,'全唐诗/poet.song.153000.json','["尊前一醉莫辭頻，三萬場當歲十旬。", "况有好詩能泣鬼，寧無妙畫可通神。", "快呼左手持螯客，莫著傾身障鹿人。", "綠漲大江渾是酒，蒲萄波面已生春。"]'),
('fb5deec5-98d9-449b-b531-33ed53391673','送林子長赴姑孰泮宮','虞儔','宋','宋诗','song-poetry','','[]','綠波風駛引征帆，九萬扶摇入羽翰。',64,'全唐诗/poet.song.153000.json','["綠波風駛引征帆，九萬扶摇入羽翰。", "詩句最憐雲不定，宦情况與月同寒。", "襟期莫作別時惡，出處須留晚歲看。", "漫道江東懷李白，清才應合在金鑾。"]'),
('869d5087-a528-4388-bc60-c5a89a82f64f','和鮑倅暴雨大水之作','虞儔','宋','宋诗','song-poetry','','[]','坳堂方笑芥爲舟，驟雨俄驚匯衆流。',64,'全唐诗/poet.song.153000.json','["坳堂方笑芥爲舟，驟雨俄驚匯衆流。", "天漏不知何處補，地卑轉覺此生浮。", "會須擊水扶摇上，政想乘風汗漫遊。", "宦海陸沉聊爾耳，詩人休詠白蘋洲。"]'),
('7ba062e4-7ab2-4e6b-85de-8b76b9d545a6','以新米作撈飯有感','虞儔','宋','宋诗','song-poetry','','[]','老矣何妨受一廛，笑渠楊惲强歌田。',64,'全唐诗/poet.song.153000.json','["老矣何妨受一廛，笑渠楊惲强歌田。", "驚心赤地三年旱，慰眼黄雲八月天。", "他日江船來白粲，暫時水碓搗紅鮮。", "軟炊香飯憐脾病，從此長齋繡佛前。"]'),
('5679b3c4-ece9-4ba9-a13b-00507a680e10','自嘆  其一','虞儔','宋','宋诗','song-poetry','','[]','落落高才豈晚收，枉將歲月送菟裘。',64,'全唐诗/poet.song.153000.json','["落落高才豈晚收，枉將歲月送菟裘。", "未能鵬擊三千里，空費龍驤萬斛舟。", "明月有珠誰按劍，珊瑚作網漫沉鈎。", "求田問舍非吾事，豪氣元龍死不休。"]'),
('72731286-af35-4eac-ad08-bacf8a588671','自嘆  其二','虞儔','宋','宋诗','song-poetry','','[]','明經青史不難收，怪底依然處士裘。',64,'全唐诗/poet.song.153000.json','["明經青史不難收，怪底依然處士裘。", "誰謂封侯安事筆，我聞定霸必焚舟。", "驥騰夷路須聯轡，鼇負三山好擲鈎。", "對策清時看第一，未應藴藉愧裴休。"]'),
('827d4e8a-3819-4049-8517-b4ebae52f70e','冬至後五日夜雪復作再用韻  其一','虞儔','宋','宋诗','song-poetry','','[]','燈火黄昏漸漸收，烏薪已盡典輕裘。',64,'全唐诗/poet.song.153000.json','["燈火黄昏漸漸收，烏薪已盡典輕裘。", "自篘浮螘床頭甕，誰鱠新鱸江上舟。", "卧聽玉霙驚淅瀝，起看瓊樹怪聯鈎。", "多應武仲添詩興，下筆翩翩更不休。"]'),
('307c29d9-e7c1-4be0-b71c-326e72317aa8','冬至後五日夜雪復作再用韻  其二','虞儔','宋','宋诗','song-poetry','','[]','綠野功名一戰收，何如危坐擁狐裘。',64,'全唐诗/poet.song.153000.json','["綠野功名一戰收，何如危坐擁狐裘。", "歌兒解咤銷金帳，酒子能添藥玉舟。", "莫爲溫柔尋伐斧，免勞服餌到懸鈎。", "誰言柳絮渾相似，惱亂春風恐未休。"]'),
('0eeaa67c-5a31-4258-901f-d99a8c779a2a','冬至後五日夜雪復作再用韻  其三','虞儔','宋','宋诗','song-poetry','','[]','銀燭生花香霧收，中堂密坐促貂裘。',64,'全唐诗/poet.song.153000.json','["銀燭生花香霧收，中堂密坐促貂裘。", "羊羔兒酒浮瓊斝，牛尾狸酥映玉舟。", "扶醉緩歌金縷曲，怕寒催下畫簾鈎。", "紛紛擾擾成何事，且鬭尊前一笑休。"]'),
('e97af5e0-d2bb-4be5-bca0-5e338f6ee400','移守吳門酌別姜總管','虞儔','宋','宋诗','song-poetry','','[]','宦遊蹤跡一浮萍，末路從公蓋已傾。',64,'全唐诗/poet.song.153000.json','["宦遊蹤跡一浮萍，末路從公蓋已傾。", "方喜溪山來入社，忽驚絃管作離聲。", "河梁戀戀看雲別，剡棹看看載雪行。", "從此江東還渭北，莫因契闊負詩盟。"]'),
('c189764a-4c36-4c13-b1ac-0dc9c93adc76','黄仲本自浙西漕幕得倅臨安暫往寓居德清遽然話別詩以送之','虞儔','宋','宋诗','song-poetry','','[]','外臺賓幕始知名，見說君王念老成。',64,'全唐诗/poet.song.153000.json','["外臺賓幕始知名，見說君王念老成。", "此去監州真有命，向來相國詎忘情。", "吾儕老矣難爲別，世路悠然莫計程。", "强說從來還信否，一篙春水片帆輕。"]'),
('26cc3864-7c3f-4063-a9f6-f506fa1dfb32','得旨與郡歸自浙東余成卿王貫之葉德遠追送至于震澤舟中款語數日而後別','虞儔','宋','宋诗','song-poetry','','[]','懷抱連宵得好開，莫愁波浪與塵埃。',64,'全唐诗/poet.song.153000.json','["懷抱連宵得好開，莫愁波浪與塵埃。", "中年已是難離別，此地何妨數往來。", "送我扁舟寧作遠，喚人歸鳥苦相催。", "邈然後會知何處，更欲臨分把一杯。"]'),
('5cc48f3d-2f24-45c8-bb2d-7f3ada297724','和湯倅留別','虞儔','宋','宋诗','song-poetry','','[]','官冷門前可設羅，高軒多謝肯相過。',64,'全唐诗/poet.song.153000.json','["官冷門前可設羅，高軒多謝肯相過。", "別離漸近那堪說，觴詠從今莫厭多。", "風月平分聊爾耳，雲霄咫尺奈君何。", "漢庭行且迎枚乘，南浦從教恨綠波。"]'),
('c80af9e3-03fa-4d8b-a5bc-4d4e0f6cc60b','端午日用韻','虞儔','宋','宋诗','song-poetry','','[]','今朝端午懶吟詩，此意兒曹莫遣知。',64,'全唐诗/poet.song.153000.json','["今朝端午懶吟詩，此意兒曹莫遣知。", "萱草著花空有恨，菖蒲稱壽永無時。", "遠途日暮休回首，近事風傳只皺眉。", "角黍堆盤何處奠，沉湘千古使人悲。"]'),
('d99376a5-0411-45ff-9404-128c87405c0b','無眠','虞儔','宋','宋诗','song-poetry','','[]','蛩吟砌下豈知時，我亦無眠有所思。',64,'全唐诗/poet.song.153000.json','["蛩吟砌下豈知時，我亦無眠有所思。", "夜永只憐燈作伴，秋凉最許簟先知。", "十年擾擾夢中事，一笑悠悠世上兒。", "數盡更籌窗送曙，起來贏得鬢成絲。"]'),
('271b651d-c60f-452b-8ad4-87141406b286','拒霜','虞儔','宋','宋诗','song-poetry','','[]','纖枝綠葉競成叢，誰障西來落木風。',64,'全唐诗/poet.song.153000.json','["纖枝綠葉競成叢，誰障西來落木風。", "霞散纏頭千丈綺，春回醉面一番紅。", "伶俜欲嫁還羞晚，梳洗隨宜不愛工。", "况是秋高花已少，對花莫放酒杯空。"]'),
('b562a6ee-45ab-4050-868e-0aa886dab8e5','聖龍長老資公求修佛殿疏余不暇作也昔丹霞燒木佛院主墮落鬚眉普賢勸修古佛末後童子證果居士舉此公案二段以問聖龍若下得一轉語則佛殿一時修了其或未然定又去聒擾檀施矣因作山偈奉送只此大勝作疏頭勸緣也','虞儔','宋','宋诗','song-poetry','','[]','風雨飄摇紺宇摧，百身古佛盡莓苔。',64,'全唐诗/poet.song.153000.json','["風雨飄摇紺宇摧，百身古佛盡莓苔。", "政須豪士修檀施，定自諸天打供來。", "向晚鐘魚猶短氣，只今龍象亦生哀。", "道人莫憚朱門去，會有清蓮一朵開。"]'),
('4d06977e-802a-44e2-bbf5-ccea47392c18','烏程宰十三日往龍洞禱晴歸言見田家兩岸車水其聲如雷兼刈穫甚忙若得旬日晴則農事濟矣因作田家歎一首','虞儔','宋','宋诗','song-poetry','','[]','慚愧田家趁好晴，鴉鴉兩岸水車鳴。',64,'全唐诗/poet.song.153000.json','["慚愧田家趁好晴，鴉鴉兩岸水車鳴。", "畦丁露宿腰鐮健，饁婦泥行脚板輕。", "作苦僅能供伏臘，有年何處不昇平。", "只愁官裏催租動，里正敲門沸似羹。"]'),
('a7b640cb-5b40-41f1-a4ca-f67681fdfc62','千秋嶺','虞儔','宋','宋诗','song-poetry','','[]','輕陰漠漠雨班班，嶺上風來一解顔。',64,'全唐诗/poet.song.153000.json','["輕陰漠漠雨班班，嶺上風來一解顔。", "已是去天才尺五，却令緩步有躋攀。", "飛泉百道縈羅带，列岫千峰擁翠鬟。", "應是北堂春正滿，幾回回首望家山。"]'),
('a9355c7c-9a6f-4326-8d2e-32aaa53e57f7','用韻賦歲暮田家歎聞之者足以戒也','虞儔','宋','宋诗','song-poetry','','[]','催科里正莫頻頻，望麥登場更浹旬。',64,'全唐诗/poet.song.153000.json','["催科里正莫頻頻，望麥登場更浹旬。", "紈袴向來無餓死，黄冠此去罷迎神。", "田間作苦誰憐汝，天上調元合有人。", "自歎農家消底物，百金斗米便回春。"]'),
('29a51b82-7f37-4074-9ca2-1a33658974b8','枕上偶得數語呈林子長','虞儔','宋','宋诗','song-poetry','','[]','碧梧翠竹日相高，懷想家山魂夢勞。',64,'全唐诗/poet.song.153000.json','["碧梧翠竹日相高，懷想家山魂夢勞。", "鐘鼎故知非我事，箕裘猶可冀兒曹。", "眼中誰是真犀角，池上君今有鳳毛。", "直探牛心屠獪耳，能安貧賤乃英豪。"]'),
('d663c99d-5016-447a-ad2e-fab9c70270f6','再用韻呈林子長','虞儔','宋','宋诗','song-poetry','','[]','癡兒誰識坐談高，撫字年來亦漫勞。',64,'全唐诗/poet.song.153000.json','["癡兒誰識坐談高，撫字年來亦漫勞。", "簿領何妨聊爾耳，湖山正是屬吾曹。", "百年心事空三歎，五馬人生却二毛。", "欲作報章還自笑，郊寒寧解敵韓豪。"]'),
('e2282fb0-7761-4259-bf81-e7b48f2e8605','據案偶得數語錄呈簿尉','虞儔','宋','宋诗','song-poetry','','[]','昔年官冷欲無氈，製錦如今又不然。',64,'全唐诗/poet.song.153000.json','["昔年官冷欲無氈，製錦如今又不然。", "老去幾遭官長駡，書來却有故人憐。", "敢期翠羽還池上，漸喜黄衣減目前。", "欲學催科無奈拙，直須天假一豐年。"]'),
('84483f1f-d731-40d6-aec4-76b2b1cf7079','呈吳守','虞儔','宋','宋诗','song-poetry','','[]','風流正始孰追回，沈謝曹劉豈乏才。',64,'全唐诗/poet.song.153000.json','["風流正始孰追回，沈謝曹劉豈乏才。", "詩律恢長憐我老，吟編端的頼君開。", "秋懷拍拍須千首，世事悠悠付一杯。", "已是醉吟輸白傅，雪霜頭上更相催。"]'),
('4cb0fa14-8a8f-4bc7-a4b1-c8e4892037f8','贈潘接伴','虞儔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淮海相逢便說詩，新來匡鼎解人頤。',64,'全唐诗/poet.song.153000.json','["淮海相逢便說詩，新來匡鼎解人頤。", "句中有眼人誰識，絃上無聲我獨知。", "每見朋遊談警策，偶因王事得追隨。", "西湖近報梅花約，歸趁東風第一枝。"]'),
('3a2de51e-630e-4172-95e9-f61cfaf94e65','再用難字韻簡潘接伴','虞儔','宋','宋诗','song-poetry','','[]','當年名下無虛士，此日詩中有二難。',64,'全唐诗/poet.song.153000.json','["當年名下無虛士，此日詩中有二難。", "方駕飯山何太瘦，拍肩東野不言寒。", "來章只好先呈佛，屬和何當勝得官。", "珍重牛腰成巨軸，丁寧莫與俗人看。"]'),
('dc08c258-8aae-4ff8-b45b-24f4a54877b1','和潘接伴韻','虞儔','宋','宋诗','song-poetry','','[]','久矣聞名忻識面，哦詩一字果何難。',64,'全唐诗/poet.song.153000.json','["久矣聞名忻識面，哦詩一字果何難。", "筆端風月窺天巧，句裏冰霜飽歲寒。", "自昔登壇須老將，祇今握節愧粗官。", "相逢忽有新篇贈，病眼摩挲得細看。"]'),
('4ead0fd9-61f0-4521-ba6b-50d2e2897881','和探菊南坡','虞儔','宋','宋诗','song-poetry','','[]','春來自分菊成坡，秋晚何妨日一過。',64,'全唐诗/poet.song.153000.json','["春來自分菊成坡，秋晚何妨日一過。", "喜色忽看眉上見，霜華應向掌中多。", "一枝須索蟻浮甕，三徑從教雀可羅。", "坡下有泉唯可飲，西風吹鬢未應皤。"]'),
('8eacb140-6988-45f2-839c-355e1799ac61','出郊迓倅車暮歸二首  其一','虞儔','宋','宋诗','song-poetry','','[]','簿書叢裏得抽身，豈是將迎不厭頻。',64,'全唐诗/poet.song.153000.json','["簿書叢裏得抽身，豈是將迎不厭頻。", "何處鷄豚燕同社，有時鷗鷺喜相親。", "山頭落日催歸騎，陌上豐年見醉人。", "更羨柴門無限好，今宵相對月華新。"]'),
('7381d572-bda0-4e91-8a24-cc113463263a','出郊迓倅車暮歸二首  其二','虞儔','宋','宋诗','song-poetry','','[]','軋軋籃輿迫暮歸，前村燈火漸依稀。',64,'全唐诗/poet.song.153000.json','["軋軋籃輿迫暮歸，前村燈火漸依稀。", "溪邊默數黄牛過，烟際遥看白鳥飛。", "把酒無人風落帽，荷鋤有客露沾衣。", "關門山寺知何許，忽聽鐘聲度翠微。"]'),
('c9ea9bd3-cf00-4adb-a9ca-0b29bca8c43e','和陶學長雪詩','虞儔','宋','宋诗','song-poetry','','[]','寒侵病骨笑支離，爐撥通紅小放圍。',64,'全唐诗/poet.song.153000.json','["寒侵病骨笑支離，爐撥通紅小放圍。", "風運六花侵几席，雲移萬杵碎瓊璣。", "從渠窮巷回車轍，休羨朱門點舞衣。", "造物想憐爲學苦，分光先許到書帷。"]'),
('3a2dc53d-2e32-4dc8-91bd-b594fd3b71be','賦雪  其一','虞儔','宋','宋诗','song-poetry','','[]','風緊靈犀怯鎮帷，曉來白盡遠山眉。',64,'全唐诗/poet.song.153000.json','["風緊靈犀怯鎮帷，曉來白盡遠山眉。", "石蹲錯認鹽形虎，地煖應知穴處狸。", "色混江梅無眼目，潤添隴麥有膏脂。", "朱門酒肉嗟遺臭，藍縷樵夫不掩肌。"]'),
('d1d12f5d-7e8b-44d3-9b23-3e1f80b8b873','賦雪  其二','虞儔','宋','宋诗','song-poetry','','[]','風回雪急巧穿帷，黄竹歌殘更斂眉。',64,'全唐诗/poet.song.153000.json','["風回雪急巧穿帷，黄竹歌殘更斂眉。", "燕集幾家尋鵠鷺，獵圍何處問狐狸。", "長饑政自愁黄獨，高卧誰能管竊脂。", "頼有寒梅爲老伴，也應凍減一分肌。"]'),
('aedc9e2e-7955-4a15-8f46-1c7450b10f9e','立春日雪','虞儔','宋','宋诗','song-poetry','','[]','占候農祥恰正晨，一天遽有散花人。',64,'全唐诗/poet.song.153000.json','["占候農祥恰正晨，一天遽有散花人。", "飄揚柳絮猶疑早，點綴梅花欲亂真。", "但愛千峰如立鵠，誰憐百結有懸鶉。", "玄冥珍重豐年意，分付東皇作好春。"]'),
('b0e5677c-e15a-4678-ac5a-2ece3827361e','和漢老弟雪詩','虞儔','宋','宋诗','song-poetry','','[]','大皞行春未有聞，六花連夜舞繽紛。',64,'全唐诗/poet.song.153000.json','["大皞行春未有聞，六花連夜舞繽紛。", "落梅未曉驚三弄，宿麥先秋定十分。", "飛上綵幡憐我老，映來書幌慰兒勤。", "四時代謝從來事，造物何心更策勳。"]'),
('6b90d7e5-6353-4055-95d1-2adbbd857624','漢老弟寄示雪詩倡和已成軸矣因次韻  其一','虞儔','宋','宋诗','song-poetry','','[]','臘盡冰花墮渺茫，詩來爽氣想清揚。',64,'全唐诗/poet.song.153000.json','["臘盡冰花墮渺茫，詩來爽氣想清揚。", "潤添隴麥知年熟，影浸溪梅見月將。", "閉戶誰能呼白墮，迴風却笑舞紅粧。", "小橋夢入南坡路，並轡騎馿賦短章。"]'),
('eaf07471-07bc-4dcc-871b-2e92979914c9','漢老弟寄示雪詩倡和已成軸矣因次韻  其二','虞儔','宋','宋诗','song-poetry','','[]','衡門雖設晝常關，人在瓊樓玉宇間。',64,'全唐诗/poet.song.153000.json','["衡門雖設晝常關，人在瓊樓玉宇間。", "一笑眼青餘老檜，相看頭白祇高山。", "携壺索共梅花醉，著屐扶行竹杖斑。", "此興此時吾不忘，倦飛深羨鳥知還。"]'),
('60c2dd43-e12d-43f8-8620-d9cadacafcdc','漢老弟寄示雪詩倡和已成軸矣因次韻  其三','虞儔','宋','宋诗','song-poetry','','[]','飛灑羞明不肯朝，徘徊待伴未全消。',64,'全唐诗/poet.song.153000.json','["飛灑羞明不肯朝，徘徊待伴未全消。", "將花著袂元無跡，認柳吹綿別有條。", "璧月半規開水面，玉龍千丈轉山腰。", "玄冥已自呈三白，青帝何須又一飄。"]'),
('c769a2ba-be50-450f-8fe1-e4d9fe2f7564','一冬無雪立春後九日始有之次湯倅韻','虞儔','宋','宋诗','song-poetry','','[]','冰花何事太遲開，肯傍春風脚底來。',64,'全唐诗/poet.song.153000.json','["冰花何事太遲開，肯傍春風脚底來。", "飛絮漫天輕認柳，落英滿地錯憐梅。", "玄冥莫恨空歸去，青帝從教倒載迴。", "官冷無氈須一醉，可能來共即時杯。"]'),
('29b83e32-ad5e-4c00-87f0-a3eebfbc2be7','和子長縣尉林同年立春後十日風雪大作訪客不值','虞儔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一束烏薪抵百金，外間風雪政愁陰。',64,'全唐诗/poet.song.153000.json','["一束烏薪抵百金，外間風雪政愁陰。", "履穿東郭先生病，梅老西湖處士吟。", "青帝未教春滿目，玄冥還有歲寒心。", "蹇馿不踏長安道，恐落泥塗跡愈深。"]'),
('cbe3d4e6-b623-411c-beed-a88b2b2ea622','和湯倅春雪','虞儔','宋','宋诗','song-poetry','','[]','雪瑞元來竟不空，豐年消息喜潛通。',64,'全唐诗/poet.song.153000.json','["雪瑞元來竟不空，豐年消息喜潛通。", "故憐梅老扶衰白，未放桃夭嫁小紅。", "夜動簷花猶带雨，晴看隴麥待摇風。", "强顔追逐新年事，倍費天人剪水工。"]'),
('74431d3a-aeb6-4ae5-acfc-777b0dcbc2f6','十二月二十六日早起雪已三寸許夜來初不覺也','虞儔','宋','宋诗','song-poetry','','[]','曉來眼界忽然新，一色瓊瑶與爛銀。',64,'全唐诗/poet.song.153000.json','["曉來眼界忽然新，一色瓊瑶與爛銀。", "人事乖時空請禱，天心迴後只逡巡。", "不教三白孤殘臘，要與千家作好春。", "宿麥連雲雖入望，路傍猶有翳桑人。"]'),
('527f02be-72c5-43f3-b343-a6aa14798d79','和耘老弟慶太安人恩封','虞儔','宋','宋诗','song-poetry','','[]','天上恩榮逮我親，日邊消息趁蕤賓。',64,'全唐诗/poet.song.153000.json','["天上恩榮逮我親，日邊消息趁蕤賓。", "光生花誥宜多壽，喜動萊衣別有春。", "須信慶源能衮衮，故教樂事愈頻頻。", "明年不但郊封止，八秩重看寵渥新。"]'),
('372252d3-f191-4c46-8c86-ddc347a28690','和耘老弟喜雪','虞儔','宋','宋诗','song-poetry','','[]','天憐好景付君收，一笑春生紫綺裘。',64,'全唐诗/poet.song.153000.json','["天憐好景付君收，一笑春生紫綺裘。", "賦就兔園爭授簡，酒酣鯨海快吞舟。", "怪來柳絮穿簾額，舞上花裀襯襪鈎。", "畫餠豐年賒一醉，臘前三白詎應休。"]'),
('0200edfd-02b6-4110-b672-e08797a559f1','和漢老弟雪下不聚','虞儔','宋','宋诗','song-poetry','','[]','剪水飛花散又收，天人袖手翠雲裘。',64,'全唐诗/poet.song.153000.json','["剪水飛花散又收，天人袖手翠雲裘。", "待滋宿麥須連隴，政慮流民醉覆舟。", "村店浪誇沽酒旆，寒窗誰上釣詩鈎。", "玄冥豈是癡兒子，且與天工了事休。"]'),
('6a190259-6192-4582-b94d-668eab168116','雪晴後書懷  其一','虞儔','宋','宋诗','song-poetry','','[]','爛銀白璧遣誰收，米盡家家典破裘。',64,'全唐诗/poet.song.154000.json','["爛銀白璧遣誰收，米盡家家典破裘。", "應爲溪橋添曉溜，豈憐野渡有橫舟。", "侵凌蓬鬢霜千丈，浮動梅梢月一鈎。", "歲晚風光天必相，未甘亭上話三休。"]'),
('c8d7be49-fdce-470e-87fb-e5892ab7f43c','雪晴後書懷  其二','虞儔','宋','宋诗','song-poetry','','[]','明堂杞梓必兼收，未信英雄老一裘。',64,'全唐诗/poet.song.154000.json','["明堂杞梓必兼收，未信英雄老一裘。", "彭澤不妨聊束带，巴東何事嘆孤舟。", "會須取印大如斗，寧羨封侯曲似鈎。", "咄咄那庸如許事，尊前且食蛤蜊休。"]'),
('9a9e4bd5-7992-4e93-8f4d-0a49e4a0e9cc','因次郊行韻眷然懷歸','虞儔','宋','宋诗','song-poetry','','[]','杖藜何日返林坰，夢想西山幾草亭。',64,'全唐诗/poet.song.154000.json','["杖藜何日返林坰，夢想西山幾草亭。", "叢菊暫爲三徑別，垂楊又見兩番青。", "宦遊知己雲中月，市道交情水上萍。", "多事不煩漁父問，餔糟久矣忘偏醒。"]'),
('d9f79fc3-9a16-4ce2-9a90-cf663d080718','連日大雪獨坐有感  其一','虞儔','宋','宋诗','song-poetry','','[]','低唱誰家帳縷金，何如短棹泛山陰。',64,'全唐诗/poet.song.154000.json','["低唱誰家帳縷金，何如短棹泛山陰。", "天邊鴈斷無留影，泓下龍寒亦懶吟。", "著柳便隨風作態，欺梅除有月知心。", "晴光却喜前村動，春事從今日日深。"]'),
('09193d2d-e0b5-4000-9138-4ecb97c14715','連日大雪獨坐有感  其二','虞儔','宋','宋诗','song-poetry','','[]','呼得蒼頭數橐金，旋沽村酒過牆陰。',64,'全唐诗/poet.song.154000.json','["呼得蒼頭數橐金，旋沽村酒過牆陰。", "焦琴不鼓知音斷，凍筆頻呵作意吟。", "擾擾漫天空眩目，看看出日爲寒心。", "憑君試向江邊問，又漲晴波幾尺深。"]'),
('98a72575-1a97-4394-abef-5a75080504f9','吳使君置酒見邀坐間雪作有詩即席和韻','虞儔','宋','宋诗','song-poetry','','[]','漁蓑江上晚垂鈎，艇子何如喚莫愁。',64,'全唐诗/poet.song.154000.json','["漁蓑江上晚垂鈎，艇子何如喚莫愁。", "相伴梅花開庾嶺，寧將斗酒博梁州。", "夜歸深巷聞驚犬，歲稔無人見佩牛。", "明日樓前增偉觀，試看銀海戲羣鷗。"]'),
('007fc1af-27eb-4358-a88c-0658723dc2c5','被旨暫攝四明已具舟而雪作王誠之有詩相餞次韻','虞儔','宋','宋诗','song-poetry','','[]','剡溪風雪正紛紛，暗想清遊已目存。',64,'全唐诗/poet.song.154000.json','["剡溪風雪正紛紛，暗想清遊已目存。", "頗怪扁舟遽乘興，應緣坐席不容溫。", "海圻聊爾誇千騎，帳底何如具一尊。", "回首兔園吟賞地，從今授簡致頻頻。"]'),
('81d79c4e-83c9-4579-991b-40695663cbe7','和漢老弟喜雪','虞儔','宋','宋诗','song-poetry','','[]','爲瑞雖多却不宜，誰憐孤坐撥灰時。',64,'全唐诗/poet.song.154000.json','["爲瑞雖多却不宜，誰憐孤坐撥灰時。", "興添竹葉蛆浮甕，瘦損梅花雀抱枝。", "閉戶從教行跡斷，裹裘猶怯暮寒欺。", "天工似欲還三白，冷淡家風合有詩。"]'),
('a130bf16-961d-4b9c-a3a8-aabd454988ed','劇暑出局徑歸打睡踰月不奉正甫談緒且頓寒詩盟有詩見問輒次韻謝不敏','虞儔','宋','宋诗','song-poetry','','[]','早歸伏日莫躊躇，晝寢從教笑宰予。',64,'全唐诗/poet.song.154000.json','["早歸伏日莫躊躇，晝寢從教笑宰予。", "奠枕清風招我老，攬衣閲月向人疎。", "寧無酒共公榮飲，亦有詩成阿買書。", "須待雨凉尋舊約，只今旱火况焚如。"]'),
('1f99b667-2597-40a9-9306-b4ec927de4ec','太學秋試封彌夜深獨坐懷考試諸友','虞儔','宋','宋诗','song-poetry','','[]','衡鑒高懸已自公，修嚴官禁不通風。',64,'全唐诗/poet.song.154000.json','["衡鑒高懸已自公，修嚴官禁不通風。", "樊牆便有河山隔，夢寐猶疑笑語同。", "離索暫應疎酒醆，往來爭敢遞詩筒。", "燈花預報楊園約，端的釵頭綴玉蟲。"]'),
('ee9ef81f-3bf6-4736-83b8-b48ee835d804','西歸有期喜而復作','虞儔','宋','宋诗','song-poetry','','[]','懶于塵土踏京華，張翰西風久憶家。',64,'全唐诗/poet.song.154000.json','["懶于塵土踏京華，張翰西風久憶家。", "江上魚肥應可鱠，田家酒熟未容賒。", "狂蹤泛泛渾猶梗，病眼昏昏祇欲花。", "爲報王孫早歸矣，莫憑芳草浪咨嗟。"]'),
('fafee89b-3df3-4215-b4ea-07b45d4b422f','十二月初六日抵儀真廨舍次日即出護使客天氣嚴寒裏河冰合有厚一二尺者打凍峻急不免取山路徑走都梁','虞儔','宋','宋诗','song-poetry','','[]','王式當年本不來，那堪歲晚犯塵埃。',64,'全唐诗/poet.song.154000.json','["王式當年本不來，那堪歲晚犯塵埃。", "淮分南北誰爲梗，路適東西意自哀。", "錦纜千艘分玉帛，冰河萬處碎瓊瑰。", "只消一夜東風力，一一船頭盡撥開。"]'),
('56fac1ec-1c94-4411-8c52-d125b2eda1af','和耘老弟得銅龜韻','虞儔','宋','宋诗','song-poetry','','[]','神龜又復化頑銅，塊處潭心智莫窮。',64,'全唐诗/poet.song.154000.json','["神龜又復化頑銅，塊處潭心智莫窮。", "豈悔刳腸遊夢裏，還羞曳尾向塗中。", "波摇金色連山赤，星動瑶光徹夜紅。", "網送吾家占瑞應，向來左顧與今同。"]'),
('11f53bdf-bba5-4fcf-8639-2e937c1db792','冬至之二日兄弟兒姪偕過西山道院歸而微雪','虞儔','宋','宋诗','song-poetry','','[]','忽然薄暮暗江天，衝面凉風馬不前。',64,'全唐诗/poet.song.154000.json','["忽然薄暮暗江天，衝面凉風馬不前。", "五色書雲占昨日，六花瑞雪應明年。", "向來水旱民何罪，此去流移天盍憐。", "逗曉陽烏升若木，摧頹病鶴亦蹁躚。"]'),
('dbd94f80-9e6d-4bb0-a944-c09470d97a0a','雪後過南坡  其一','虞儔','宋','宋诗','song-poetry','','[]','南坡千樹總瓊瑶，走馬來看及未消。',64,'全唐诗/poet.song.154000.json','["南坡千樹總瓊瑶，走馬來看及未消。", "短鬢風前愁素領，衰顔酒後借紅潮。", "松饒蒼鬣猶能奮，梅耿香魔苦費招。", "此景此時無我共，新詩吟罷獨長謠。"]'),
('4400e9e1-4a9c-4afa-8516-4443bcccec6c','雪後過南坡  其二','虞儔','宋','宋诗','song-poetry','','[]','扶桑暖翅接金烏，韝上饑鷹待一呼。',64,'全唐诗/poet.song.154000.json','["扶桑暖翅接金烏，韝上饑鷹待一呼。", "懸滴梅梢珠璀璨，墮花檜頂粉模糊。", "明年翠浪麥須好，何處青帘酒可酤。", "萬里江山誰畫得，天開新樣雪晴圖。"]'),
('24ba7b8a-ad10-4d2e-8883-55245dc76240','回程泗州道中','虞儔','宋','宋诗','song-poetry','','[]','淮北燕南昔混同，相望却恨馬牛風。',64,'全唐诗/poet.song.154000.json','["淮北燕南昔混同，相望却恨馬牛風。", "往來未省誰爲伴，言語從來自不通。", "百歲遺民愁緒外，數聲羌笛夢魂中。", "徑須爭渡長淮去，三月烟塵一洗空。"]'),
('d4a04f12-8886-46c8-bba4-18ee27c50e0f','挽新安恭榮王詩  其一','虞儔','宋','宋诗','song-poetry','','[]','安僖折派慶源長，憲靖猗蘭奕葉芳。',64,'全唐诗/poet.song.154000.json','["安僖折派慶源長，憲靖猗蘭奕葉芳。", "可但詞章誇華白，更餘政事說龔黄。", "兩宮密侍清閒燕，三事榮分衮繡光。", "生死哀榮難得似，宸綸一品贈真王。"]'),
('c2b30034-d6d6-4a1d-a029-b817fd238d7e','挽新安恭榮王詩  其二','虞儔','宋','宋诗','song-poetry','','[]','弁峯苕水挽將歸，北第南園自一時。',64,'全唐诗/poet.song.154000.json','["弁峯苕水挽將歸，北第南園自一時。", "過眼浮名真是夢，回頭樂事總成悲。", "荆蘭膝下同黄壤，鴻鴈行中失白眉。", "曾是汝陽門下客，凄凉空咏八哀詩。"]'),
('011c3456-5cbc-416c-aa6d-fe64eec81978','挽崇憲靖王詩  其一','虞儔','宋','宋诗','song-poetry','','[]','襲慶安僖八十春，綿綿僊李更蟠根。',64,'全唐诗/poet.song.154000.json','["襲慶安僖八十春，綿綿僊李更蟠根。", "王封一品身尤貴，位冠三師德愈尊。", "華萼樓邊空墮淚，白蘋洲上重銷魂。", "哀榮終始公何憾，節鉞貂蟬萃一門。"]'),
('be693279-08e6-4e2b-89eb-88062b63607c','挽崇憲靖王詩  其二','虞儔','宋','宋诗','song-poetry','','[]','詔書催喚衮衣歸，富貴誰知已息機。',64,'全唐诗/poet.song.154000.json','["詔書催喚衮衣歸，富貴誰知已息機。", "北闕恩榮寧久戀，東山雅志肯相違。", "傷心水月人安在，回首湖山事亦非。", "他日蘇公堤畔路，祇愁老淚不勝揮。"]'),
('46c24eaa-78f7-4780-b4e3-e9f44c37dbc1','余居太夫人憂三年淚枯老眼既除喪頗理故書似覺有味矣數日眼疾作此事又廢殊無聊頼唯有思索詩句可以度日耳','虞儔','宋','宋诗','song-poetry','','[]','三年涕淚劇懸河，斷簡殘編奈若何。',64,'全唐诗/poet.song.154000.json','["三年涕淚劇懸河，斷簡殘編奈若何。", "縱使相看青眼在，故應添得黑花多。", "衰遲把酒元無分，冷淡觀書亦有魔。", "掩卷相吁心自了，莫將文字問維摩。"]'),
('d64ab151-ae6b-4a2e-ae07-0e93d9481e51','前詩謂思索詩句可以度日第恐終無益再賦一首以廣之','虞儔','宋','宋诗','song-poetry','','[]','年來世味一毫輕，宿契詩書尚有情。',64,'全唐诗/poet.song.154000.json','["年來世味一毫輕，宿契詩書尚有情。", "魔事從教雙眼赤，內觀還覺寸心明。", "思量詩句嗟無補，檢校醫方恐未精。", "俗學可憐誇口耳，何如默坐息營營。"]'),
('f11a2043-ce9f-44ad-aad9-358c5e5f7708','挽吏部石似之  其一','虞儔','宋','宋诗','song-poetry','','[]','四海聲名桂一枝，流年僅及手中蓍。',64,'全唐诗/poet.song.154000.json','["四海聲名桂一枝，流年僅及手中蓍。", "康成未免龍蛇厄，翁子寧酬富貴期。", "天上玉樓須好記，人間金谷漫遺詩。", "宦途落寞知音絕，三撫朱絃只自悲。"]'),
('628caf2b-8404-418b-886f-b4ecf5a01f9e','挽吏部石似之  其二','虞儔','宋','宋诗','song-poetry','','[]','憂國囊封豈是疎，有才無命信何如。',64,'全唐诗/poet.song.154000.json','["憂國囊封豈是疎，有才無命信何如。", "風迴冊府三山遠，星殞郎牆一位虛。", "賈誼自傷終太傅，薛收若在必中書。", "哀哉埋玉今何地，却返當年處士廬。"]'),
('41053ac6-1517-4481-9021-b77d92ce31d9','挽吏部石似之  其三','虞儔','宋','宋诗','song-poetry','','[]','期公簪橐侍甘泉，底是上天不假年。',64,'全唐诗/poet.song.154000.json','["期公簪橐侍甘泉，底是上天不假年。", "才大難爲當世用，文高猶有後人傳。", "魂銷閩檄千山路，淚挽銀河七月天。", "會葬誰歟銘郭泰，固應無愧翠珉鎸。"]'),
('884350c2-7381-4add-b833-2f75fe0318b1','和紹興錢參政貢院落成','虞儔','宋','宋诗','song-poetry','','[]','能爲君王獵雋英，區區循吏笑西京。',64,'全唐诗/poet.song.154000.json','["能爲君王獵雋英，區區循吏笑西京。", "忽看廣厦千間闢，蚤覺先春萬木榮。", "有客囊中來露穎，何人壟上去傭耕。", "知公造化無遺物，咫尺龍門雷電生。"]'),
('3110c0ef-e3e8-4209-adfd-c1d21ef6297e','挽水東吳主簿詩','虞儔','宋','宋诗','song-poetry','','[]','當年投筆過淮山，油幕談兵故不凡。',64,'全唐诗/poet.song.154000.json','["當年投筆過淮山，油幕談兵故不凡。", "老去功名空白髮，向來簿領愧青衫。", "龍龕內典超金界，鴻寶遺編付玉函。", "况有諸孫振門戶，不須留恨黯松杉。"]'),
('6216e46e-09b6-4d85-a384-7bc636d8e59d','挽主簿楊仲遠詩','虞儔','宋','宋诗','song-poetry','','[]','居士胸懷壑與丘，琴山懷抱枕清流。',64,'全唐诗/poet.song.154000.json','["居士胸懷壑與丘，琴山懷抱枕清流。", "一區宅好真揚子，萬卷書多似鄴侯。", "好客亦嘗陪俎豆，諸郎殊不廢箕裘。", "人間俯仰成千古，痛念吾鄉馬少游。"]'),
('cf28ce8f-a524-4023-82ea-725117cad4ba','挽仙尉黄公詩','虞儔','宋','宋诗','song-poetry','','["\u592a\u6e56"]','平生懷抱欲凌雲，元祐名家蓋有君。',64,'全唐诗/poet.song.154000.json','["平生懷抱欲凌雲，元祐名家蓋有君。", "况是生兒勝武子，何須不第歎劉蕡。", "傷哉未作河西尉，已矣還空冀北羣。", "從此太湖風月夜，一聲漁笛不堪聞。"]'),
('a63494f9-bf24-4a57-a74a-eb3b9726f9d8','除日失步詩以自解','虞儔','宋','宋诗','song-poetry','','[]','雙脚平生不踏空，誰教仰面看飛鴻。',64,'全唐诗/poet.song.154000.json','["雙脚平生不踏空，誰教仰面看飛鴻。", "娛親正要同萊子，爛醉何曾過阿戎。", "已分折腰營五斗，恐因折臂作三公。", "妻孥不用閒惆悵，得失從來塞上翁。"]'),
('3fbd7d40-9727-477c-aafb-d99e9d7f576e','丁未禮部貢院監門次張伯子判院韻兼簡正甫判院三詩  其一','虞儔','宋','宋诗','song-poetry','','[]','金門誤喜綴朝班，猶自塵勞債未還。',64,'全唐诗/poet.song.154000.json','["金門誤喜綴朝班，猶自塵勞債未還。", "曉漏驚催門外鵠，春蠶空想管中斑。", "羣公神遇無全目，老我旁觀只汗顔。", "安得僊人修月斧，與君携手到中間。"]'),
('e5bb57d3-4249-4b1b-904a-85358de60cea','丁未禮部貢院監門次張伯子判院韻兼簡正甫判院三詩  其二','虞儔','宋','宋诗','song-poetry','','[]','禹鑿門高競化龍，桃花浪暖百川通。',64,'全唐诗/poet.song.154000.json','["禹鑿門高競化龍，桃花浪暖百川通。", "圖南俱運雲鵬翼，逐北誰收汗馬功。", "鎖鑰僅能防宿弊，權衡正好變文風。", "抱關碌碌真吾事，竊喜清朝取士公。"]'),
('f87f5daf-2944-4b88-9dc5-fbf2d7abb43b','丁未禮部貢院監門次張伯子判院韻兼簡正甫判院三詩  其三','虞儔','宋','宋诗','song-poetry','','[]','槐市同登弟子員，虀鹽燈火記初年。',64,'全唐诗/poet.song.154000.json','["槐市同登弟子員，虀鹽燈火記初年。", "尋春紫陌風流在，通籍金閨步武聯。", "眼底要觀新事業，筆端猶著舊山川。", "夜窗細話行藏處，始信于君有厚緣。"]'),
('49f07a59-6362-4e17-b0ed-c72c8a1e97f8','林正甫察院出示送劉德修都運殿院詩并德修和章人事好乖置之勿復道也第一見傾蓋如平昔而萬里遠別又不能一面得非皆有不偶然者存乎勉强繼韻一寫胸中磊塊而結戀之懷又有詩所不能盡者  其一','虞儔','宋','宋诗','song-poetry','','[]','吾道艱難孰使然，憂來真欲問諸天。',64,'全唐诗/poet.song.154000.json','["吾道艱難孰使然，憂來真欲問諸天。", "方看驄馬避桓典，遽爲蝦蟆賦玉川。", "去國身輕寧絜絜，愛君意在故卷卷。", "瞿塘灧澦風波惡，百丈孤騫上瀨船。"]'),
('7b8bd9c2-56cf-4d5c-aabf-e276065dc609','林正甫察院出示送劉德修都運殿院詩并德修和章人事好乖置之勿復道也第一見傾蓋如平昔而萬里遠別又不能一面得非皆有不偶然者存乎勉强繼韻一寫胸中磊塊而結戀之懷又有詩所不能盡者  其二','虞儔','宋','宋诗','song-poetry','','[]','彈劾生風筆有神，天教末路得相親。',64,'全唐诗/poet.song.154000.json','["彈劾生風筆有神，天教末路得相親。", "從來名下無虛士，今見朝端第一人。", "銷印不知誰發難，投珠那得謂無因。", "何妨弭節潼江上，我亦歸歟伴隠淪。"]'),
('cc1cf647-832d-40b6-b87e-8e5e2ed248a7','思歸','虞儔','宋','宋诗','song-poetry','','[]','風雨連朝作伴牢，只堪痛飲讀離騷。',64,'全唐诗/poet.song.154000.json','["風雨連朝作伴牢，只堪痛飲讀離騷。", "誰知老境侵腰脚，早是多情惜鬢毛。", "杖屨出門還有礙，簿書堆案敢辭勞。", "年來俯仰終無補，尚欠歸田一著高。"]'),
('d1dc3f6c-ed55-417c-8ce6-d4dea0eec53b','中書邵舍人挽詩','虞儔','宋','宋诗','song-poetry','','[]','璧池鼓篋歲庚辰，蟾窟分枝癸未春。',64,'全唐诗/poet.song.154000.json','["璧池鼓篋歲庚辰，蟾窟分枝癸未春。", "夾侍螭坳司記注，同升鳳掖演絲綸。", "靖言交契從來厚，追想音塵不復親。", "拘綴無由陪執拂，招魂楚些爲沾襟。"]'),
('93dc9261-eb5a-42bc-b906-d4eda1e0dbb6','春大閲呈郡僚','虞儔','宋','宋诗','song-poetry','','[]','青油談笑坐生風，便覺湖山氣象雄。',64,'全唐诗/poet.song.154000.json','["青油談笑坐生風，便覺湖山氣象雄。", "霽色喜浮旌旆上，歡聲爭入鼓鼙中。", "中軍合用詩書帥，上馬空慙矍鑠翁。", "橫槊賦詩君等事，何妨寓目此時同。"]'),
('6f613cf8-7317-43b5-a45e-6261f6e705bb','秋大閲呈郡僚','虞儔','宋','宋诗','song-poetry','','[]','橫槊何人解賦詩，東方千騎出郊時。',64,'全唐诗/poet.song.154000.json','["橫槊何人解賦詩，東方千騎出郊時。", "天高霽色旌旗上，地迥秋聲鼓角悲。", "漫授一編黄石老，相從千載赤松期。", "據鞍矍鑠非吾事，慙愧江湖把一麾。"]'),
('69289749-593c-4197-8e6b-0dd4bbea774b','和使君鞏大監秋閲','虞儔','宋','宋诗','song-poetry','','[]','金鉦鼙鼓肅秋聲，畫㦸油幢照座明。',64,'全唐诗/poet.song.154000.json','["金鉦鼙鼓肅秋聲，畫㦸油幢照座明。", "千騎夾營橫槊氣，六花簇隊煥新晴。", "雍容壇上看儒將，潦倒尊前愧老兵。", "橫槊賦詩豪傑事，澄江休數謝宣城。"]'),
('bfb01680-f470-476b-b7fa-1d2e9c75224e','和吳守賦秋閲之什','虞儔','宋','宋诗','song-poetry','','[]','秋郊小隊暫徘徊，誰信儒門出將才。',64,'全唐诗/poet.song.154000.json','["秋郊小隊暫徘徊，誰信儒門出將才。", "千騎控弦吳月滿，一聲鳴角楚天開。", "賦詩已是誇橫槊，看劍何妨更引杯。", "收取中原報明主，凌烟事業正相催。"]'),
('718397ed-c0dd-4b04-85f2-e23376438a6d','送鄧舍人將漕西淮用舍人坐上詩韻  其一','虞儔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖烟柳勝陽關，遮斷淮南大小山。',64,'全唐诗/poet.song.154000.json','["西湖烟柳勝陽關，遮斷淮南大小山。", "詩好固應傾座上，酒行猶喜到花間。", "君王納諫寧容去，風雨愁予豈坐慳。", "未用疾驅催上道，鋒車有詔徑須還。"]'),
('7e41b472-3289-4ba6-82e7-a4d6bacc868a','送鄧舍人將漕西淮用舍人坐上詩韻  其二','虞儔','宋','宋诗','song-poetry','','[]','醉裏誰分主與賓，離觴到手莫辭頻。',64,'全唐诗/poet.song.154000.json','["醉裏誰分主與賓，離觴到手莫辭頻。", "感懷今日知何日，屈指三春破二春。", "北郭忍教風送客，江湖猶頼雨留人。", "晚晴依舊山光好，穩穩移舟傍玉津。"]'),
('06569ff4-8a5a-4f73-843e-535620ae8f58','送別王誠之給事','虞儔','宋','宋诗','song-poetry','','[]','嫋嫋酸風吹客衣，冥冥芳樹攬愁思。',64,'全唐诗/poet.song.154000.json','["嫋嫋酸風吹客衣，冥冥芳樹攬愁思。", "誰教宦路分南北，自是人生足別離。", "送岸飛花何太急，留人夜雨故來遲。", "眼前他日鳬鴻墮，莫作情疎不寄詩。"]'),
('99bef8e8-f51c-4961-869c-7bda7857a7c0','挽俞君任通判詩','虞儔','宋','宋诗','song-poetry','','[]','鄉評月旦尚依然，旁郡人稱別駕賢。',64,'全唐诗/poet.song.154000.json','["鄉評月旦尚依然，旁郡人稱別駕賢。", "邂逅宦途同晚歲，游從太學記當年。", "誰憐冷落堪爲地，我欲吹噓送上天。", "薦墨未乾君已矣，漫憑楚挽慰重泉。"]'),
('7e695da8-99df-400a-889e-a45d23dfb7c8','日來歡意頓減幸秋雨既足中秋定晴預約南坡小集觀月且屬耘老弟董其事','虞儔','宋','宋诗','song-poetry','','[]','酒熟床頭已聖清，吟詩窗下莫悲鳴。',64,'全唐诗/poet.song.154000.json','["酒熟床頭已聖清，吟詩窗下莫悲鳴。", "故人明月從來共，今歲中秋定好晴。", "雨脚已隨荷蓋盡，風頭還逐桂花生。", "試謀一笑君須會，誰道尊前笑不成。"]'),
('f75f80b1-c64f-402c-91ec-28941474fd30','十一月一日早起','虞儔','宋','宋诗','song-poetry','','[]','悵望淮山落木風，楚天雲霧更重重。',64,'全唐诗/poet.song.154000.json','["悵望淮山落木風，楚天雲霧更重重。", "粵從西路來東路，倏見三冬過一冬。", "貂敝人誰憐季子，樓高吾豈下元龍。", "求田問舍今良策，自覺歸歟興頗濃。"]'),
('60d54a0d-e623-4a7c-88c6-79769d4f1570','離都下','虞儔','宋','宋诗','song-poetry','','[]','經年不踏軟紅塵，偶入修門事事新。',64,'全唐诗/poet.song.154000.json','["經年不踏軟紅塵，偶入修門事事新。", "本爲湖山尋舊約，却愁風雨送行人。", "多情黄菊空搔首，無伴芳醪可入唇。", "今歲重陽殊草草，南坡歸夢夜來頻。"]'),
('273cc028-f815-4f26-bc46-0ef2a11085bf','十七夜待月','虞儔','宋','宋诗','song-poetry','','[]','青天遥望片雲無，坐待冰輪出海隅。',64,'全唐诗/poet.song.154000.json','["青天遥望片雲無，坐待冰輪出海隅。", "沆瀣已垂梧葉重，嬋娟猶惜桂華孤。", "夜闌紅燭休更秉，春滿香醪不用沽。", "且放虛簷歌緩轉，恐驚三匝未棲烏。"]'),
('15d687bd-f5dd-486c-af42-aa8982d35a1c','是夜三鼓後睡起月色滿庭','虞儔','宋','宋诗','song-poetry','','[]','幽人睡起已三更，始信今宵不浪晴。',64,'全唐诗/poet.song.154000.json','["幽人睡起已三更，始信今宵不浪晴。", "天宇元來如許浄，月華別是一般明。", "風前鴈斷應無信，露下蛩吟豈不平。", "無頼姮娥肯留照，疾驅蟾魄度前榮。"]'),
('0652d01a-09db-475d-a701-515310b160bd','九月八日遊報本寺','虞儔','宋','宋诗','song-poetry','','[]','詩翁懷抱十分秋，探借重陽作勝遊。',64,'全唐诗/poet.song.154000.json','["詩翁懷抱十分秋，探借重陽作勝遊。", "蓮社政須陶靖節，竹林未羨阮陳留。", "逢僧應說無生話，顧我何如不繫舟。", "明日黄花須斗酒，莫將容易換凉州。"]'),
('d81b678c-f47b-4a21-8046-45d9feb4a117','連日禱雨猶未應也數語漫述皇恐之意呈簿尉  其一','虞儔','宋','宋诗','song-poetry','','[]','誰令旱魃逞神姦，悵望西疇一雨慳。',64,'全唐诗/poet.song.154000.json','["誰令旱魃逞神姦，悵望西疇一雨慳。", "日永六龍方緩轡，天高九虎政當關。", "不論賦入今難辦，見說流移昔未還。", "地上小臣真蟣蝨，禱祈無效祇慚顔。"]'),
('63701c11-75cf-438d-aa46-ab9b60acca14','連日禱雨猶未應也數語漫述皇恐之意呈簿尉  其二','虞儔','宋','宋诗','song-poetry','','[]','小兒曼倩儘狂姦，試掉雷車與破慳。',64,'全唐诗/poet.song.154000.json','["小兒曼倩儘狂姦，試掉雷車與破慳。", "慰我農民須早計，憐渠歲事頗相關。", "齋盂并日渾忘味，詩債如山只欠還。", "謝令冥頑推不去，毫絲無補亦胡顔。"]'),
('8deee5a1-acf5-4c36-a2c3-4603707e5025','政在簿書叢中王簿示二詩推案漫述數語','虞儔','宋','宋诗','song-poetry','','[]','文書堆案汗如洗，鴈鶩滿庭聲甚喧。',64,'全唐诗/poet.song.154000.json','["文書堆案汗如洗，鴈鶩滿庭聲甚喧。", "縱有可人來眼底，了無佳思到吟邊。", "翠眉對我何曾展，白眼逢渠不受憐。", "上策從來三十六，就中除有一歸田。"]'),
('53b4fa8f-7d66-4c6f-9e29-011546eb974f','新糊小室明簾戲書','虞儔','宋','宋诗','song-poetry','','[]','先生丈室浄無塵，白紙糊簾莫笑貧。',64,'全唐诗/poet.song.154000.json','["先生丈室浄無塵，白紙糊簾莫笑貧。", "夜靜風嚴褰不動，朝來雪積欲爭新。", "圍爐只用深藏火，隠几還應煖似春。", "紙帳一床餘紙被，不妨更作獨眠人。"]'),
('4176f4b0-b926-4293-9313-e168d71d7975','宿巢縣地藏寺枕上偶成','虞儔','宋','宋诗','song-poetry','','[]','年來蹤跡漫奔波，其奈功名有命何。',64,'全唐诗/poet.song.154000.json','["年來蹤跡漫奔波，其奈功名有命何。", "畫虎向人無好手，飯牛憐我有悲歌。", "丹心永夜燈前苦，白髮明朝鏡裏多。", "却謝前村鷄唱好，呼兒起舞肯蹉跎。"]'),
('be106bf7-72f9-46fe-9d7f-300878640872','家書送白額因賦','虞儔','宋','宋诗','song-poetry','','[]','虎踞南山孰敢樵，盜渠名字却深逃。',64,'全唐诗/poet.song.154000.json','["虎踞南山孰敢樵，盜渠名字却深逃。", "誰能雪裏窮三窟，縛送尊前慰老饕。", "試喚玉纖揎碧袖，笑看霜片落金刀。", "族庖堪恨無風味，紅暈蒸花更藉糟。"]'),
('554f3398-272c-45b6-932e-a6d941dedb29','丙辰二月上丁釋奠致齋于經史閣呈郡僚','虞儔','宋','宋诗','song-poetry','','[]','泮水分明記舊遊，上丁祠事得重修。',64,'全唐诗/poet.song.154000.json','["泮水分明記舊遊，上丁祠事得重修。", "音遺金石疑猶在，菜有蘋蘩信可羞。", "老我今慚郡文學，諸生試覓汜鄉侯。", "緬懷安定規模遠，傑閣城西最上頭。"]'),
('c7c255d8-b4fe-465a-b506-622bd3069034','和鞏使君釋奠韻','虞儔','宋','宋诗','song-poetry','','[]','疇昔東家一畝宮，推尊昭代比天崇。',64,'全唐诗/poet.song.154000.json','["疇昔東家一畝宮，推尊昭代比天崇。", "絃歌未輟文斯在，俎豆親陪獻有終。", "采藻載歌思泮水，浴沂行詠舞雩風。", "自慚謬玷詩書走，未羨諸儒舍蓋公。"]'),
('116f6486-cd10-4a32-af7e-aa61fbd167d5','宿臨安童縣尉庵童尉送酒','虞儔','宋','宋诗','song-poetry','','[]','深深松竹隠禪房，更渡溪橋暫解裝。',64,'全唐诗/poet.song.154000.json','["深深松竹隠禪房，更渡溪橋暫解裝。", "但喜還家無數日，不知行路過重陽。", "白衣送酒勞相問，黄菊依人未肯芳。", "珍重山僧能會意，殷勤掃榻爲燒香。"]'),
('c761193b-3923-494e-991d-5ad2b3550f8d','次林正甫韻','虞儔','宋','宋诗','song-poetry','','[]','湖山夢想阻登臨，柳色門前綠未深。',64,'全唐诗/poet.song.154000.json','["湖山夢想阻登臨，柳色門前綠未深。", "老去青衫誰著眼，向來白戰尚寒心。", "澆愁可欠杯中物，遣興聊爲洛下吟。", "倒指啟關春已暮，直須修禊繼山陰。"]'),
('a1e408df-f227-4170-b803-8d87b90cdd2d','護客高郵道中舟中讀簡齋十月詩因和其韻','虞儔','宋','宋诗','song-poetry','','[]','莫莫休休興已闌，滿頭塵土更彈冠。',64,'全唐诗/poet.song.154000.json','["莫莫休休興已闌，滿頭塵土更彈冠。", "鴈從北到傳書易，淮界中流遣恨難。", "篷底吟哦詩有味，胸中磊磈酒無歡。", "故人莫枉綈袍意，范叔猶能忍一寒。"]'),
('076765b8-0607-46d9-872c-900fe96305b3','王貫之有詩留別因次其韻','虞儔','宋','宋诗','song-poetry','','[]','檣頭語燕底匆匆，滿幅蒲帆送客風。',64,'全唐诗/poet.song.154000.json','["檣頭語燕底匆匆，滿幅蒲帆送客風。", "合與仇謀從此逝，病兼貧至向來同。", "紛紛時事愁眉上，咄咄人情醉眼中。", "頗覺田園歸去好，固應馬首未渠東。"]'),
('aa5dde76-f03a-4d3e-9688-c8912e3cdc34','林子長見訪泊舟姑蘇臺下有詩因次其韻','虞儔','宋','宋诗','song-poetry','','[]','懷人玉樹向風前，明月中秋動隔年。',64,'全唐诗/poet.song.154000.json','["懷人玉樹向風前，明月中秋動隔年。", "勝處盃中忘爾汝，幾回紙上落雲烟。", "已能命駕來吳苑，未許回舟指霅川。", "顧我從來無此客，漁蓑那得戀江邊。"]'),
('e94464f3-d591-44a0-8304-5dce4a27ef06','朱天永示僕二詩蓋有激而云者因用其韻以廣之  其一','虞儔','宋','宋诗','song-poetry','','[]','是非得喪一毫輕，蠻觸何勞角上爭。',64,'全唐诗/poet.song.154000.json','["是非得喪一毫輕，蠻觸何勞角上爭。", "未可輕量天下士，渠知不是彀中英。", "平生我亦輕餘子，到處君安得此名。", "勿對秋花歎憔悴，春風回首又欣榮。"]'),
('a33c1721-9e8e-45aa-875b-fbfe5893f8c3','朱天永示僕二詩蓋有激而云者因用其韻以廣之  其二','虞儔','宋','宋诗','song-poetry','','[]','彈鋏悲歌莫浪嗟，筆耕心織是生涯。',64,'全唐诗/poet.song.154000.json','["彈鋏悲歌莫浪嗟，筆耕心織是生涯。", "區區子豈癡摹虎，事事吾猶錯畫蛇。", "不分縮頭幾類鼈，苦嫌怒目幾遭蛙。", "憑君試讀山君傳，鶴豈能言爲嫉邪。"]'),
('52e2da07-c62a-424e-87f1-befb9b7cb8bd','漢老弟近書云欲看文字無暇作詩再用韻','虞儔','宋','宋诗','song-poetry','','[]','脫粟羹藜未厭餐，何心華屋薦金盤。',64,'全唐诗/poet.song.154000.json','["脫粟羹藜未厭餐，何心華屋薦金盤。", "風前覓句巾常岸，月下揮觴影亦單。", "懶拙不堪當世用，行藏留與後人看。", "也知妍醜初無定，馬面相憐亦突欒。"]'),
('2d405e2a-dd30-4f6b-a0ce-bb7c17dd3e03','太守送酒  其一','虞儔','宋','宋诗','song-poetry','','[]','拜捧雙壺急破封，蓬廬驚怪閙兒童。',64,'全唐诗/poet.song.154000.json','["拜捧雙壺急破封，蓬廬驚怪閙兒童。", "歡生和氣薰蒸外，春在先生醖釀中。", "枯涸詩腸偏借潤，飄零酒醆不憂空。", "更看小隊尋花柳，太守風流似醉翁。"]'),
('8b05cf19-e0ae-4069-84d6-ece92b37cb35','太守送酒  其二','虞儔','宋','宋诗','song-poetry','','[]','黄堂還復念酸寒，餘瀝分來玉斚寬。',64,'全唐诗/poet.song.154000.json','["黄堂還復念酸寒，餘瀝分來玉斚寬。", "遽遣茅柴羞避席，快呼苜蓿彊登盤。", "步兵勝處輕劉子，北海狂言迕阿瞞。", "何似老虔春夜酌，簷花細雨洗愁端。"]'),
('b791efeb-5c79-4ae9-80d9-9aa1916c9155','以郡醖十斗送林子長','虞儔','宋','宋诗','song-poetry','','[]','我友溪堂愛說詩，兵厨况有酒如池。',64,'全唐诗/poet.song.154000.json','["我友溪堂愛說詩，兵厨况有酒如池。", "留髠一石從來慣，訪戴扁舟莫太遲。", "已辦鴟夷陪後乘，姑令從事作先馳。", "憑君試向松江望，綠漲蒲萄正渺瀰。"]'),
('d43364f8-fabb-42a1-9b4c-44e56bac589a','郁簿行年四十有九讀李太白潯陽感秋詩慨懷有作次韻勉之','虞儔','宋','宋诗','song-poetry','','[]','清德如公畏四知，流光底事感圓蓍。',64,'全唐诗/poet.song.154000.json','["清德如公畏四知，流光底事感圓蓍。", "日邊丹鳳聊棲棘，月下驚鴻尚揀枝。", "五十知非慚漏盡，百年彊半怪駒馳。", "買臣富貴猶堪待，莫誦潯陽落魄詩。"]'),
('8d29e148-8618-4469-aa29-20e2b1d4a80b','用山門記遊韻賦酴醾簡林子長不蒙寵和豈不復作書生調度耶因以詩督之','虞儔','宋','宋诗','song-poetry','','[]','嬝娜柔條不自持，鎖窗深處最相宜。',64,'全唐诗/poet.song.154000.json','["嬝娜柔條不自持，鎖窗深處最相宜。", "試教纖手簪雙鬢，莫遣新愁上兩眉。", "子建洛神空有賦，樂天楊柳可無詩。", "爲君喚起溫柔夢，春草池塘日正遲。"]'),
('4da96087-8f0e-4144-b509-7523f78ab558','戲簡林子長  其一','虞儔','宋','宋诗','song-poetry','','[]','溪上園亭處處新，想君屢費橐中銀。',64,'全唐诗/poet.song.154000.json','["溪上園亭處處新，想君屢費橐中銀。", "鶑窺繡戶煩三請，蝶遶花梢知幾巡。", "恨不即時謀載酒，恐因暇日得尋春。", "只愁又隔同年面，却欠尊前似主人。"]'),
('8dda6a8b-4418-4176-9955-c8bb77c7d8cd','戲簡林子長  其二','虞儔','宋','宋诗','song-poetry','','[]','崇桃積李巧爭新，紅勝臙脂白勝銀。',64,'全唐诗/poet.song.154000.json','["崇桃積李巧爭新，紅勝臙脂白勝銀。", "車騎每勞鶑命喚，藥欄聊伴蝶遊巡。", "何須歌舞留連夜，漫與詩篇慰藉春。", "珍重海棠煩問訊，肯教空谷老佳人。"]'),
('1495fdfc-fbf6-4a13-a0e4-83c840ca739f','簡蕭東夫','虞儔','宋','宋诗','song-poetry','','[]','向來一瓣爲南豐，縱使能詩也坐窮。',64,'全唐诗/poet.song.154000.json','["向來一瓣爲南豐，縱使能詩也坐窮。", "千里望中同夜月，五言城裏带春風。", "人言止酒今直止，君自中書豈不中。", "莫道天工全憒憒，滿頭白髮亦何公。"]'),
('e29551b2-eace-4849-98c6-fd37a985b518','遊虎丘再用韻','虞儔','宋','宋诗','song-poetry','','[]','虎丘欲到幾年華，靈運何妨不在家。',64,'全唐诗/poet.song.154000.json','["虎丘欲到幾年華，靈運何妨不在家。", "風艇也遭新壩阨，芒鞋可憚去途賒。", "禪心默會點頭石，幻化應羞解語花。", "憶昔吳王舊池館，一堪行樂一堪嗟。"]'),
('ef287b54-148f-4859-b1db-00a56fe4e98e','揚州司理章公挽詩','虞儔','宋','宋诗','song-poetry','','[]','宦遊曾記舊桐川，泮水淒涼愧鄭虔。',64,'全唐诗/poet.song.154000.json','["宦遊曾記舊桐川，泮水淒涼愧鄭虔。", "怪得儒流有師法，知從鄉老得心傳。", "未酬龍伯連鼇手，遽作維揚跨鶴仙。", "太息孔門空用賦，不教一柱果擎天。"]'),
('f5cf6714-fe93-4d72-b5ce-7292c500563d','章樞密挽詩  其一','虞儔','宋','宋诗','song-poetry','','[]','當年抗疏動宸旒，騎省烏臺許遍遊。',64,'全唐诗/poet.song.154000.json','["當年抗疏動宸旒，騎省烏臺許遍遊。", "穩穩樞庭方緩步，駸駸揆路却回頭。", "空餘榮錦開三徑，猶有甘棠蔽兩州。", "浮世功名俱一夢，不須夜壑怪移舟。"]'),
('f6d01c9b-b686-410b-a296-bf7d0c3ffce7','章樞密挽詩  其二','虞儔','宋','宋诗','song-poetry','','[]','引年歸老十星霜，養素遺榮道愈光。',64,'全唐诗/poet.song.154000.json','["引年歸老十星霜，養素遺榮道愈光。", "可但蒼生思謝傅，未應白首愧馮唐。", "龍光方慶千齡遇，鳳誥俄嗟一鑑亡。", "前輩風流磨滅盡，後生無復見堂堂。"]'),
('a63d399f-1584-47ce-a79c-bde0cf4be485','正卿不見累日聞十二日與鄭丈舍人遊何山書此爲寄','虞儔','宋','宋诗','song-poetry','','[]','剩欲從公朝暮閒，一溪留我未容還。',64,'全唐诗/poet.song.154000.json','["剩欲從公朝暮閒，一溪留我未容還。", "極思談笑三秋隔，相望林泉數里間。", "詩絕一時同鄭老，書堂終日憩何山。", "報來定有吳門信，快矣黄嘉明月灣。"]'),
('d52b259c-ed9f-4146-984f-001935d7a78b','次張安國舍人讀王侍郎詩有懷其人韻','虞儔','宋','宋诗','song-poetry','','[]','蓋世聲名紫府仙，平生襟袖著山川。',64,'全唐诗/poet.song.154000.json','["蓋世聲名紫府仙，平生襟袖著山川。", "一麾管領秋江月，千首憑陵杜曲天。", "疇昔風雲餘感慨，歸來文字带芳鮮。", "和韓何限驚人句，應有門人李漢編。"]'),
('bcd8308b-3f5f-4100-8d39-77226e1c9c00','書懷  其一','虞儔','宋','宋诗','song-poetry','','[]','丘山何必萬牛回，櫟杜從來貴不才。',64,'全唐诗/poet.song.154000.json','["丘山何必萬牛回，櫟杜從來貴不才。", "無事飲多惟日醉，有聲畫好亦天開。", "欲謀松菊園三徑，翻訝文章水一杯。", "未免無衣憂卒歲，籬根慚愧候蟲催。"]'),
('e910873b-d228-4ab9-b355-c49914d9134a','書懷  其二','虞儔','宋','宋诗','song-poetry','','[]','宦路侵尋已倦遊，功名何敢望前修。',64,'全唐诗/poet.song.154000.json','["宦路侵尋已倦遊，功名何敢望前修。", "謬紆州組三宜去，回視儒冠一忍羞。", "疇昔嘗窺循吏傳，只今誰是富民侯。", "夜來好雨催歸棹，春水茫茫漲鴨頭。"]'),
('6a6c4d94-0789-48ec-a3c3-c3f8dc924590','夜坐書懷  其一','虞儔','宋','宋诗','song-poetry','','[]','看鏡功名不用頻，醉鄉境界幾由旬。',64,'全唐诗/poet.song.154000.json','["看鏡功名不用頻，醉鄉境界幾由旬。", "何妨走馬來爲問，縱未成龍亦有神。", "生計一絲寧掛眼，閒居百事不如人。", "驚鴻亦有高飛意，姑傍花前過却春。"]'),
('0720ea75-29e7-4dde-a7ec-654929ac13d4','夜坐書懷  其二','虞儔','宋','宋诗','song-poetry','','[]','夢覺誰呼小玉頻，分燈魔女笑波旬。',64,'全唐诗/poet.song.154000.json','["夢覺誰呼小玉頻，分燈魔女笑波旬。", "暮年禪悅渾知味，少日文章豈有神。", "赤脚玉川容老婢，綠珠金谷漫佳人。", "玄冥不是梅花主，開盡南枝付與春。"]'),
('12fffecd-96d1-446f-9cce-f41a9554afea','春日書懷','虞儔','宋','宋诗','song-poetry','','[]','吳興太守也堪憐，十日齋厨九不烟。',64,'全唐诗/poet.song.154000.json','["吳興太守也堪憐，十日齋厨九不烟。", "索漠清懷寒食夜，顛狂風雨落花天。", "流鶑百囀還求友，化鶴重來不是僊。", "待得麥秋民足食，君恩萬一許歸田。"]'),
('720518f5-c3ec-4380-acf4-ed5f09929cd2','用韻約宋宰諸公爲尋梅之行','虞儔','宋','宋诗','song-poetry','','[]','澹烟寒雨洗輕埃，千樹江頭探借開。',64,'全唐诗/poet.song.154000.json','["澹烟寒雨洗輕埃，千樹江頭探借開。", "莫倚風流貪畫柳，直須火急去尋梅。", "可能卯酒三盃罷，索取冰姿一笑回。", "好手河陽教落後，紛紛桃李滿輿臺。"]'),
('6da2b38a-e3d5-44ff-9b4a-05439aec3616','玉溪梅株柯殊絕宣和間用事者嘗圖以進竟不報今乃棄置蔬畦摧折憔悴有可憐之態昨陪諸公往觀共歎其不遇且約盛開時携壺酒爲醉賞之適因循又不果因用韻弔之','虞儔','宋','宋诗','song-poetry','','[]','玉溪得得探芳期，孤負詩人盡醉歸。',64,'全唐诗/poet.song.154000.json','["玉溪得得探芳期，孤負詩人盡醉歸。", "消息向來空驛使，畫圖老去惜明妃。", "香魂月墮驚春夢，翠袖天寒怯暮暉。", "蜂蝶卑凡渾省識，良迷桃李趁狂飛。"]'),
('b1ec779d-1565-42d4-b9af-e11ce6fdb708','歲除','虞儔','宋','宋诗','song-poetry','','[]','除日催人不奈頻，那堪月小不圓旬。',64,'全唐诗/poet.song.154000.json','["除日催人不奈頻，那堪月小不圓旬。", "誰能椒頌花如錦，自寫桃符筆有神。", "通夕留連分歲客，明朝多少賀年人。", "壽觴舉處慈顔喜，却是萱堂賸得春。"]'),
('20952707-7a95-47c9-9e53-87b9d2ee7501','述情','虞儔','宋','宋诗','song-poetry','','[]','間闊忻逢諸葛豐，不應阮籍哭途窮。',64,'全唐诗/poet.song.154000.json','["間闊忻逢諸葛豐，不應阮籍哭途窮。", "擬留重客傾家釀，更喜賢郎有父風。", "詩思憑陵烟雨上，宦情抖擻簿書中。", "擊鮮下舍聊乘興，未許黄堂舍蓋公。"]'),
('4ff1b059-16a9-4860-a762-8095fed39e11','真情','虞儔','宋','宋诗','song-poetry','','[]','魏紫姚黄次第榮，政須親戚話真情。',64,'全唐诗/poet.song.154000.json','["魏紫姚黄次第榮，政須親戚話真情。", "樓臺是處增詩興，羅綺叢中放酒行。", "下榻能留黄叔度，高齋端有謝宣城。", "却憐老令卑栖甚，目送歸鴻意自傾。"]'),
('6b0a6f62-746e-43af-b799-6bb338ff7c45','春晴  其一','虞儔','宋','宋诗','song-poetry','','[]','萬里陰雲一戰收，怪生和氣襲兼裘。',64,'全唐诗/poet.song.154000.json','["萬里陰雲一戰收，怪生和氣襲兼裘。", "崑山龍過初銜燭，暘谷烏飛不傍舟。", "曝背爬搔疑挾纊，凍軀傴僂快伸鈎。", "老農扶杖閒相過，一味豐年說不休。"]'),
('51c043b5-85aa-47f0-8a97-7cfae9361a04','春晴  其二','虞儔','宋','宋诗','song-poetry','','[]','結習已空摩詰袂，苦寒聊解拾遺裘。',64,'全唐诗/poet.song.154000.json','["結習已空摩詰袂，苦寒聊解拾遺裘。", "梅花已負先驅弩，竹葉隨牽下瀨舟。", "門外有誰驚剝啄，林間何處叫鈎輈。", "詩人莫費雕肝腎，付與晴窗茗椀休。"]'),
('791e90dd-ab94-40e4-936e-e38494dc8693','祈晴','虞儔','宋','宋诗','song-poetry','','[]','何許龍蟠雨應求，參天老木古靈湫。',64,'全唐诗/poet.song.154000.json','["何許龍蟠雨應求，參天老木古靈湫。", "投誠已自刲鵝頸，激怒寧煩擲虎頭。", "南畝有人朝負耒，絕潢無客夜行舟。", "寄言神物須終惠，爲挽天河使倒流。"]'),
('cb05fc64-b8b3-4459-930d-e3ce0d3750be','過西山遇雨晚晴乘凉以歸','虞儔','宋','宋诗','song-poetry','','[]','巖前垂溜忽涓涓，疑是池龍肯看鞭。',64,'全唐诗/poet.song.154000.json','["巖前垂溜忽涓涓，疑是池龍肯看鞭。", "千嶂黑雲纔過雨，一番白水又平田。", "潤添秔稻翻凉葉，喜入樵蘇爨晚烟。", "馬上歸來聞好語，荷鋤相對說豐年。"]'),
('b35fecb8-5db4-4896-84f2-7eea421d9b83','休日欲報謁林子長值雨不能前用小詩以謝不敏','虞儔','宋','宋诗','song-poetry','','[]','朝雨城南柳色新，溪光溶漾宛如銀。',64,'全唐诗/poet.song.154000.json','["朝雨城南柳色新，溪光溶漾宛如銀。", "地偏心遠開三徑，風引船回欠一巡。", "二月欲來正月盡，三分已過一分春。", "鶑啼燕舞非吾事，管領韶華自有人。"]'),
('0aa35f56-78bd-4af3-90cc-3c0695320417','駕御带欲載糯米入城先以詩敘情因次韻只此便當執狀也','虞儔','宋','宋诗','song-poetry','','[]','種秫詩人也未窮，百篇欲就醉顔紅。',64,'全唐诗/poet.song.154000.json','["種秫詩人也未窮，百篇欲就醉顔紅。", "却思白墮相逢晚，不分青銅一笑空。", "卧甕更須防吏部，抱琴應不問新豐。", "何當乞與青田核，聖處時時任一中。"]'),
('c289076a-2844-4ec9-aebe-4ab599163e14','伯兄挽詩','虞儔','宋','宋诗','song-poetry','','[]','鄰雞催曉破秋天，一枕邯鄲便脫蟬。',64,'全唐诗/poet.song.154000.json','["鄰雞催曉破秋天，一枕邯鄲便脫蟬。", "應了世間如夢幻，况於酒裏得天全。", "鴻陂曩昔聞謠鵠，下舍凄凉念擊鮮。", "誰遣驚風吹鴈序，不堪雪涕望新阡。"]'),
('73a31ccb-4284-47bf-904d-ddba0beb4f25','曉晴','虞儔','宋','宋诗','song-poetry','','[]','屋角勃姑時自喚，籬根絡緯競先鳴。',64,'全唐诗/poet.song.154000.json','["屋角勃姑時自喚，籬根絡緯競先鳴。", "刈禾政想頳肩重，揚粃那愁瞇目輕。", "考滿我應書下下，賑荒人謂策平平。", "回思舊歲民情惡，不但中山有啜羹。"]'),
('35dae9b1-90df-4572-bbec-8f5e4d6e85cd','丁欽夫來宰吾縣幾三年清德美政茲不復道二詩送行意之所寓欽夫固已默喻他日見東夫告出似之發數百里一笑  其一','虞儔','宋','宋诗','song-poetry','','[]','明月從來忌暗投，污渠尤忌映清溝。',64,'全唐诗/poet.song.154000.json','["明月從來忌暗投，污渠尤忌映清溝。", "上書未辦誅屠伯，束带何曾問督郵。", "袒裼直前當暴虎，善刀那見有全牛。", "區區三仕并三已，喜慍眉間了不留。"]'),
('ce9eb43a-7358-41a5-8bc0-733b53ee1546','丁欽夫來宰吾縣幾三年清德美政茲不復道二詩送行意之所寓欽夫固已默喻他日見東夫告出似之發數百里一笑  其二','虞儔','宋','宋诗','song-poetry','','[]','綠漲春波到白蘋，高懷寧便憶鱸蓴。',64,'全唐诗/poet.song.154000.json','["綠漲春波到白蘋，高懷寧便憶鱸蓴。", "緣誰一笑理歸棹，爲我千巖訪古人。", "已狎風波浮宦海，可能霄漢隔通津。", "割鷄却嘆非吾事，况是勞觀亦損神。"]'),
('c78e63ce-1f5e-48df-85ab-bebace69734a','送朱宰  其一','虞儔','宋','宋诗','song-poetry','','[]','疇昔鳴琴子賤堂，至今絃誦尚悠揚。',64,'全唐诗/poet.song.154000.json','["疇昔鳴琴子賤堂，至今絃誦尚悠揚。", "農桑樂歲千家足，桃李春風幾度芳。", "疾惡政緣同伯厚，愛民何止一桐鄉。", "烏臺此去真朝夕，劍履還須去尚方。"]'),
('9a73da09-d8b2-4bb4-b689-c46b2ed62bd7','送朱宰  其二','虞儔','宋','宋诗','song-poetry','','[]','一識荆州已是榮，二年尤足慰平生。',64,'全唐诗/poet.song.154000.json','["一識荆州已是榮，二年尤足慰平生。", "從來東粵輕公子，只有臨邛貴長卿。", "慘別翻令詩句鈍，臨行重把酒壺傾。", "故人聞道開東閣，拭目雲霄九萬程。"]'),
('9f9a93af-302b-4750-9fed-ec7258b8da52','和汪倅','虞儔','宋','宋诗','song-poetry','','[]','城頭杖屨恣延緣，終日看山也自賢。',64,'全唐诗/poet.song.154000.json','["城頭杖屨恣延緣，終日看山也自賢。", "浮蟻釀來堪把醆，飛鴻送盡且揮絃。", "捲殘簾幕千家雨，倚遍闌干四角天。", "渭北江東何處是，謫仙詩興政飄然。"]'),
('97b8428a-9a30-45c0-a39a-703df4214834','寄同年林子長郎中','虞儔','宋','宋诗','song-poetry','','[]','功名雖結少年場，看鏡空驚兩鬢蒼。',64,'全唐诗/poet.song.154000.json','["功名雖結少年場，看鏡空驚兩鬢蒼。", "我已青冥甘蹭蹬，君今列宿倍輝光。", "寸心祇自懷三徑，尺素何妨枉一行。", "多謝南宮故人報，日邊消息想能詳。"]'),
('74f242ff-f89c-4726-b084-a31327ce6511','苦雨','虞儔','宋','宋诗','song-poetry','','[]','經時梅熟雨翻盆，老我無聊正杜門。',64,'全唐诗/poet.song.154000.json','["經時梅熟雨翻盆，老我無聊正杜門。", "日焙衣巾留白醭，年侵腰脚倦黄昏。", "掃除雲霧風無力，點滴軒楹漏有痕。", "入市乘船雖未驗，溪流已漲幾番渾。"]'),
('eb2faf45-8d3e-4102-ba1d-c26776e640c2','漢老弟生朝','虞儔','宋','宋诗','song-poetry','','[]','風流曼倩碧雲仙，慣見兒嬉壽母前。',64,'全唐诗/poet.song.154000.json','["風流曼倩碧雲仙，慣見兒嬉壽母前。", "莫訝科名後餘子，要教富貴出長年。", "鵝黄新釀香浮甕，鴈翅橫秋影接天。", "端的姮娥消息近，南坡丹桂已開先。"]'),
('e5e478c9-8c40-4fe6-8a9f-667b9c8e5c3d','元宵不出','虞儔','宋','宋诗','song-poetry','','[]','東風摇蕩玉奩冰，車馬從人喚不譍。',64,'全唐诗/poet.song.154000.json','["東風摇蕩玉奩冰，車馬從人喚不譍。", "頼有麴生來入座，了無魔女與分燈。", "夜深月色明如洗，寒在梅梢瘦不勝。", "却笑少年行樂地，華胥枕上太瞢騰。"]'),
('e6bc12aa-e10a-4518-aa53-ad0188de5edd','出郊勸耕因游吳山清隠','虞儔','宋','宋诗','song-poetry','','[]','第一林泉得縱觀，春風隨步著欄干。',64,'全唐诗/poet.song.154000.json','["第一林泉得縱觀，春風隨步著欄干。", "山園梅雪千株在，門納湖光十里寬。", "水上濕紅雲片段，亭前鮮碧玉檀欒。", "主人才調渾相稱，題柱詩篇一一刊。"]'),
('43c6a0e1-200c-47b8-bc52-23173f9c85e8','中秋不見月寄耘老弟','虞儔','宋','宋诗','song-poetry','','[]','舉盃邀月且留殘，覆雨翻雲意未闌。',64,'全唐诗/poet.song.154000.json','["舉盃邀月且留殘，覆雨翻雲意未闌。", "自是陰晴難準擬，莫將懷抱逐悲歡。", "燈前白髮驚秋半，鏡裏清光有歲寒。", "玉斧祇應修未就，素娥寧許等閒看。"]'),
('d3f24e88-d842-48c0-9f10-c698099c1290','和郡人湯倅中秋月','虞儔','宋','宋诗','song-poetry','','[]','怪底今宵眼界寬，銀潢不動蘸金盤。',64,'全唐诗/poet.song.154000.json','["怪底今宵眼界寬，銀潢不動蘸金盤。", "未應天上追時好，無奈人間別樣看。", "酒醆飄零驚鶴唳，笛聲哀怨起龍蟠。", "經年不復南樓夢，且作三人取次歡。"]'),
('49313686-90e5-4e43-a8a4-afd36d8ef936','和鮑倅同湯歐二倅春日郊行','虞儔','宋','宋诗','song-poetry','','[]','別駕聯鑣喜在坰，不妨修禊繼蘭亭。',64,'全唐诗/poet.song.154000.json','["別駕聯鑣喜在坰，不妨修禊繼蘭亭。", "雅知社結池蓮白，况復詩成水荇青。", "問訊梅花才半樹，漸看柳絮又浮萍。", "風光流轉須時賞，爛醉從今莫放醒。"]'),
('9f84d6cf-719c-4b37-845a-b848419d1509','閏二月二十九日早離廣德大雨日午晚晴又雨宿黄蘗坊','虞儔','宋','宋诗','song-poetry','','[]','家山入望更貪程，造物無心雨與晴。',64,'全唐诗/poet.song.154000.json','["家山入望更貪程，造物無心雨與晴。", "今日莫愁明日近，一程但作兩程行。", "生須快意何嘗夢，久不還鄉亦自驚。", "親戚固應情話在，爭先僮僕已歡迎。"]'),
('6756741b-cc65-478a-9ef1-c4a214d7a7a8','赴吳興初入境','虞儔','宋','宋诗','song-poetry','','[]','詔書催發太頻頻，千騎東來喜望塵。',64,'全唐诗/poet.song.154000.json','["詔書催發太頻頻，千騎東來喜望塵。", "不爲尋芳寧較晚，固應入境便頒春。", "風和漸覺旌旗轉，野曠遥聞鉦鼓新。", "千里嗷嗷方待哺，自慙何以慰斯民。"]'),
('b1167479-eac5-42cc-90d7-42535f460c54','耘老弟五月十三日親往新亭種竹喜而賦詩','虞儔','宋','宋诗','song-poetry','','[]','移竹應須竹醉時，不妨带笋一時移。',64,'全唐诗/poet.song.154000.json','["移竹應須竹醉時，不妨带笋一時移。", "清陰且障東西日，碧色還分上下池。", "歲晚雪霜成老伴，夜凉風月得新知。", "朅來便有親親意，玉立無言似索詩。"]'),
('a86fdb61-a635-4a4a-b779-52e9c3623ffd','曾守譙樓既成邀賓從同登議闢雙門以復舊觀從士子請也  其一','虞儔','宋','宋诗','song-poetry','','[]','樓下遺蹤宛可尋，尚須賓從一來臨。',64,'全唐诗/poet.song.154000.json','["樓下遺蹤宛可尋，尚須賓從一來臨。", "三峯嵂崒渾依舊，雙闕岧嶢復見今。", "麻麥向來迷綠野，簪纓久矣負儒林。", "使君不惜褰帷問，慰我邦人望望心。"]'),
('c9a0d567-ab76-49a7-95de-26bacb5d289c','曾守譙樓既成邀賓從同登議闢雙門以復舊觀從士子請也  其二','虞儔','宋','宋诗','song-poetry','','[]','傑閣危欄不許尋，境環千里望中臨。',64,'全唐诗/poet.song.154000.json','["傑閣危欄不許尋，境環千里望中臨。", "古桃風物寧非舊，甲子規模廼到今。", "堪笑折腰趨府事，何如長嘯入山林。", "故園猿鶴休驚怨，出岫孤雲豈有心。"]'),
('6295af87-528c-49dd-bdce-00e88e77dc97','和聞鶑','虞儔','宋','宋诗','song-poetry','','[]','度柳穿花故故遲，黄金新刷羽毛奇。',64,'全唐诗/poet.song.154000.json','["度柳穿花故故遲，黄金新刷羽毛奇。", "驚回午夢花梢日，啼破春愁柳絮時。", "老去上林空好語，向來幽谷有誰知。", "紛紛雲雨成翻覆，求友唯君慰我思。"]'),
('f1546855-033e-4dce-a50f-e603cf422721','清平閣','虞儔','宋','宋诗','song-poetry','','[]','律身端合勵冰清，蒞政尤須稱物平。',64,'全唐诗/poet.song.154000.json','["律身端合勵冰清，蒞政尤須稱物平。", "知是夫君深寓意，雅宜斯閣遂安名。", "池幽自足龜魚樂，林靜休教蟲鳥鳴。", "况復官閒州似斗，不妨時此濯塵纓。"]'),
('897eea0d-e06e-4819-b691-d5de857f0b7a','用韻和仲兄','虞儔','宋','宋诗','song-poetry','','[]','鼯鼠相將五技窮，東來歲月太匆匆。',64,'全唐诗/poet.song.154000.json','["鼯鼠相將五技窮，東來歲月太匆匆。", "冷官敢恨知音少，直道難教與俗同。", "翻憶對牀聽夜雨，不堪舉扇障西風。", "詩來喚起還家夢，目斷成行天際鴻。"]'),
('fef2f070-4e3d-4833-80ca-b3a444c2494c','遊宦十年于外歸自浙東覩西山先塋周圍林木氣象大非昔比蓋緣藩籬既徹本家樵採不以時外人侵盜復無禁理勢固應爾也今春憂居遂協謀兄弟傚先君舊來規橅創夾籬界庶外人知吾輩用意所在有所忌憚不肆侵盜而本家樵採亦有時云耳因以詩識歲月','虞儔','宋','宋诗','song-poetry','','[]','萬畝墳山遍野陰，幾年樵採到如今。',64,'全唐诗/poet.song.154000.json','["萬畝墳山遍野陰，幾年樵採到如今。", "藩籬有限重加護，斤斧無端免見侵。", "缺處更須頻檢校，暇時何惜一登臨。", "先君暗裏應傾倒，方信流長源更深。"]'),
('99da52cb-f87c-44ed-953c-fcce491a8214','讀白樂天詩集','虞儔','宋','宋诗','song-poetry','','[]','詳觀白傅一篇詩，長日何須一局碁。',64,'全唐诗/poet.song.154000.json','["詳觀白傅一篇詩，長日何須一局碁。", "字細縱然勞眼力，理長尤是契心期。", "誇張歌酒渾相似，消遣窮愁亦自知。", "大節更思公出處，寥寥千載是吾師。"]'),
('7c82d868-8280-4062-838d-658445dfd711','喜晴  其一','虞儔','宋','宋诗','song-poetry','','[]','黄堂通夕聽簷聲，去謁靈湫及未明。',64,'全唐诗/poet.song.154000.json','["黄堂通夕聽簷聲，去謁靈湫及未明。", "畫鷁破寒收宿靄，老龍擎日獻新晴。", "何須厭勝驅黄帽，况復精誠却衛兵。", "盡道使君能撫字，歸途爭看古陽城。"]'),
('d556d528-c681-40b9-8e95-080c7cc7a472','喜晴  其二','虞儔','宋','宋诗','song-poetry','','[]','洞中龍亦讋先聲，韜斂雲陰放日明。',64,'全唐诗/poet.song.154000.json','["洞中龍亦讋先聲，韜斂雲陰放日明。", "久雨也知田父苦，十分端爲使君晴。", "但令渤海捐刀劍，不用天河洗甲兵。", "昨夜鈴齋詩欲就，鬼神聞已泣蒲城。"]'),
('5c131e69-11b3-41fe-8b4d-db6169b16fcb','喜晴  其三','虞儔','宋','宋诗','song-poetry','','[]','雨占甲子向來頻，誰道開晴必換旬。',64,'全唐诗/poet.song.154000.json','["雨占甲子向來頻，誰道開晴必換旬。", "雲過陽臺空有夢，雪消姑射漫凝神。", "林間却喜鳩呼婦，簷外何妨鵲噪人。", "可怕西郊泥一尺，徑須躍馬去尋春。"]'),
('dc7998f0-481d-4a75-926c-9c0ac099fe77','喜晴  其四','虞儔','宋','宋诗','song-poetry','','[]','連宵驟雨喜初晴，何處殘蟬不亂鳴。',64,'全唐诗/poet.song.154000.json','["連宵驟雨喜初晴，何處殘蟬不亂鳴。", "晚熟豈妨秔秫好，秋聲先傍竹梧輕。", "紛紛雲散心安在，隠隠雷收氣未平。", "半蔌驚魂猶未定，老農那得不懲羹。"]'),
('72d84377-348e-43f0-84d6-0bf476a93029','喜晴  其五','虞儔','宋','宋诗','song-poetry','','[]','雨餘天宇十分清，到處官蛙噤不鳴。',64,'全唐诗/poet.song.154000.json','["雨餘天宇十分清，到處官蛙噤不鳴。", "殘點喜聞簷溜斷，新凉更覺葛衣輕。", "飛揚楚觀人無夢，畜縮胥濤怒已平。", "滿眼秋風歸未得，却慚千里話蓴羹。"]'),
('32e5ed07-60c3-46a4-b585-dbbc96fd201c','喜晴  其六','虞儔','宋','宋诗','song-poetry','','[]','西風有意作新晴，不遣中宵鶴鸛鳴。',64,'全唐诗/poet.song.154000.json','["西風有意作新晴，不遣中宵鶴鸛鳴。", "紅袂行雲仙夢斷，青燈對酒客愁輕。", "起看壠首禾無害，見說溪頭水已平。", "蓴菜鱸魚秋正美，誰能分我一杯羹。"]'),
('67319f02-615c-438f-84a1-8c893822614f','諸公妓飲問政堂有誚予不來者借韻呈司戶同志  其一','虞儔','宋','宋诗','song-poetry','','[]','廣文官舍自蕭然，好事何人與酒錢。',64,'全唐诗/poet.song.154000.json','["廣文官舍自蕭然，好事何人與酒錢。", "慣伴諸生甘寂寞，倦從獧子醉妖妍。", "靜揮綠綺心逾適，渴飲門冬手自煎。", "疇昔東山懷雅尚，未須輕鄙笑臞仙。"]'),
('f201988e-3469-4a12-b0cf-cce73169b1ff','諸公妓飲問政堂有誚予不來者借韻呈司戶同志  其二','虞儔','宋','宋诗','song-poetry','','[]','生涯冷淡我胡然，客裏空囊愧一錢。',64,'全唐诗/poet.song.154000.json','["生涯冷淡我胡然，客裏空囊愧一錢。", "已負酒杯同笑語，彊排詩句鬭清妍。", "官閒祇起樊籠嘆，內熱真猶膏火煎。", "試問聚蚊成一餉，何如高枕夢遊仙。"]'),
('d1220717-3b90-43b3-8efd-c6a177cad548','諸公妓飲問政堂有誚予不來者借韻呈司戶同志  其三','虞儔','宋','宋诗','song-poetry','','[]','幾日齋厨愧索然，信君高會拚金錢。',64,'全唐诗/poet.song.154000.json','["幾日齋厨愧索然，信君高會拚金錢。", "邇來此樂城中少，况有今宵座上妍。", "連放酒杯浮瀲灧，須防更漏解催煎。", "閉門獨坐何由羨，漫攪枯腸賦八仙。"]'),
('fb1782e8-0788-4701-93b1-4e2d6198fce1','諸公妓飲問政堂有誚予不來者借韻呈司戶同志  其四','虞儔','宋','宋诗','song-poetry','','[]','孤遊冷宦嘆徒然，安得通神十萬錢。',64,'全唐诗/poet.song.154000.json','["孤遊冷宦嘆徒然，安得通神十萬錢。", "南北阮家何似富，東西施子廼爭妍。", "歌筵憐我應無分，詩債憂君苦太煎。", "却憶金明年少事，春風得意醉羣仙。"]'),
('30f7079b-f52a-4c5f-8f13-a01f32a604d5','諸公妓飲問政堂有誚予不來者借韻呈司戶同志  其五','虞儔','宋','宋诗','song-poetry','','[]','東家誰念我纍然，慚愧何曾十萬錢。',64,'全唐诗/poet.song.154000.json','["東家誰念我纍然，慚愧何曾十萬錢。", "病骨那禁三伏熱，長眉空負十分妍。", "睡凉喜有青奴伴，藥瞑頻呼赤脚煎。", "閣束簞瓢緣少味，非關辟穀要求仙。"]'),
('b7d61d3a-4f94-4085-9c27-32cd264c0d32','鞏使君一新社稷壇宇次汪倅韻','虞儔','宋','宋诗','song-poetry','','[]','巋然壇宇俯清流，須信規摹跨別州。',64,'全唐诗/poet.song.154000.json','["巋然壇宇俯清流，須信規摹跨別州。", "端爲苴茅崇屏翰，要知束楚貴綢繆。", "治聾有酒煩分饋，宰肉何人嘆滯留。", "天欲吾公安社稷，未宜小試羨三休。"]'),
('5d17bafe-daba-4c9d-b7b9-0cb40d9fb1de','食洞庭橘有感','虞儔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭霜橘偶明珠，磊落堆盤照坐隅。',64,'全唐诗/poet.song.154000.json','["洞庭霜橘偶明珠，磊落堆盤照坐隅。", "九頌固應原取友，千頭寧與李爲奴。", "佳名自昔南邦貴，丹實由來北地無。", "此日滿懷三嘆息，惸然天地一身孤。"]'),
('544b2d67-ec13-41af-be60-ad9892d43e9c','詠打扇','虞儔','宋','宋诗','song-poetry','','[]','腕脫何須問小童，汗流聊復慰衰農。',64,'全唐诗/poet.song.154000.json','["腕脫何須問小童，汗流聊復慰衰農。", "聯翩天下一輪月，簸蕩人間萬竅風。", "螢火招來還自照，蚊雷揮去覺羣空。", "散仙未辦朝閶闔，乞與羲皇笑傲中。"]'),
('da51e6f1-11a9-4e5e-8190-b2e090a815dc','春晚漢老弟不來有懷南坡','虞儔','宋','宋诗','song-poetry','','[]','如麻密雨不收脚，妬花惡風常打頭。',64,'全唐诗/poet.song.154000.json','["如麻密雨不收脚，妬花惡風常打頭。", "那無一日好天氣，只有千山供客愁。", "垂楊未繫金嬝娜，隔葉倦聽黄栗留。", "南坡是處堪欣賞，把酒還曾酹我不。"]'),
('beb8ff02-56e8-409a-b3b4-410f761b40a9','和耘老弟南坡芙蓉','虞儔','宋','宋诗','song-poetry','','[]','簇簇坡頭錦繡叢，幾番消息問來鴻。',64,'全唐诗/poet.song.154000.json','["簇簇坡頭錦繡叢，幾番消息問來鴻。", "素商未遣先驚綠，青女何妨更染紅。", "向日壅培曾覆簣，有時灌溉亦連筒。", "年來羈宦成離索，却欠看花一醉同。"]'),
('8a792c87-7642-49be-b467-3d6e483ab039','夏芙蓉  其一','虞儔','宋','宋诗','song-poetry','','[]','四月池邊見拒霜，園丁驚問此何祥。',64,'全唐诗/poet.song.154000.json','["四月池邊見拒霜，園丁驚問此何祥。", "花如雲錦翻新樣，葉似宮袍染御香。", "病不能陪花酒伴，詩猶堪譟鼓旗傍。", "諸君筆力迴元化，努力先春壓衆芳。"]'),
('6222e4d9-0ce3-457c-8715-5bcdef9a6153','夏芙蓉  其二','虞儔','宋','宋诗','song-poetry','','[]','老子而今兩鬢霜，未應癡絕泥禨祥。',64,'全唐诗/poet.song.154000.json','["老子而今兩鬢霜，未應癡絕泥禨祥。", "不能木末搴朝露，爭免籬邊嗅晚香。", "便合折來書卷畔，詎宜簪向寶釵傍。", "漫山千樹方芽甲，肯信人間有早芳。"]'),
('bbe684b6-9e03-4183-b3af-b59bb2baefcb','勸農','虞儔','宋','宋诗','song-poetry','','[]','平生憂國願年豐，荒政那知技已窮。',64,'全唐诗/poet.song.154000.json','["平生憂國願年豐，荒政那知技已窮。", "千里農桑千里雨，一番桃李一番風。", "宦遊老去春强半，勸相歸來日過中。", "自媿活人無好手，只將水旱禱天公。"]'),
('42894cf5-35a2-454c-bcd8-601a5bb7a305','石照勸農晚歸有雨','虞儔','宋','宋诗','song-poetry','','[]','疎林拂拂見旌旗，短鐙翩翩度翠微。',64,'全唐诗/poet.song.154000.json','["疎林拂拂見旌旗，短鐙翩翩度翠微。", "十里好山供客醉，一犁春雨勸農歸。", "水流花出紅成隊，麥雨天連綠打圍。", "投老田園今晚矣，不須五十始知非。"]'),
('04086a3f-9e5d-4adf-93f1-58b06ee358cc','虎丘勸農  其一','虞儔','宋','宋诗','song-poetry','','[]','春事三分破二分，山郊勸相豈虛文。',64,'全唐诗/poet.song.154000.json','["春事三分破二分，山郊勸相豈虛文。", "通宵已過臺前雨，破曉誰耕隴上雲。", "士女携壺方雜遝，老癃扶杖亦歡欣。", "迂疎爲郡渾無補，只把豐年答聖君。"]'),
('dadf8478-acc7-4af6-9ab2-0028e8dc9201','虎丘勸農  其二','虞儔','宋','宋诗','song-poetry','','[]','風月聯翩別駕分，雙鳬飛舄總能文。',64,'全唐诗/poet.song.154000.json','["風月聯翩別駕分，雙鳬飛舄總能文。", "苔痕點綠山頭石，花影浮紅水面雲。", "一舸鴟夷聊爾爾，千巖啼鳥自欣欣。", "徘徊斗粟歸田緩，堪笑癡頑老使君。"]'),
('3dbe420c-4d50-4db2-ac2f-a8c8c29f5ebf','五月四日過西山道院田間記老農語','虞儔','宋','宋诗','song-poetry','','[]','偶從野叟問耕桑，說到春來日日忙。',64,'全唐诗/poet.song.154000.json','["偶從野叟問耕桑，說到春來日日忙。", "老盡吾蠶桑自綠，化殘胡蝶麥猶黄。", "迎梅已過三旬雨，秧稻初齊五月凉。", "天上何人調玉燭，但知擊壤樂時康。"]'),
('f2afb3a5-4386-4981-8dac-2b852e7537b1','次韻古梅','虞儔','宋','宋诗','song-poetry','','[]','怪底昌園一種梅，老枝强項獨遲開。',64,'全唐诗/poet.song.154000.json','["怪底昌園一種梅，老枝强項獨遲開。", "伶俜鶴膝翻嫌瘦，皴皵龍鱗不受摧。", "羞把冰肌混桃李，故將粉面映莓苔。", "廣平鐵石心猶在，寧有詩情似玉臺。"]'),
('5de6556b-81fe-4581-8cc0-6639e8966862','二十三日被旨再往天目謝雨留數語壁間','虞儔','宋','宋诗','song-poetry','','[]','萬山深處得重來，天目晴雲未放開。',64,'全唐诗/poet.song.154000.json','["萬山深處得重來，天目晴雲未放開。", "盡喜山田秧䆉䅉，那愁石徑濕莓苔。", "鐵冠道士今安在，玉局仙翁去不回。", "唯有洞中龍應禱，果能因旱起風雷。"]'),
('42a01927-c291-4829-aea0-c41b7239058c','和耘老弟冬夜聞雨有懷','虞儔','宋','宋诗','song-poetry','','[]','蒲團睡思欲濛濛，珍重賢人酒一中。',64,'全唐诗/poet.song.154000.json','["蒲團睡思欲濛濛，珍重賢人酒一中。", "夜靜喜聽懸霤雨，寒多更怯戰窗風。", "簷花細落渾疑夢，詩句頻催政未工。", "雪擁紅爐愁不寐，此時懷抱想君同。"]'),
('5a85ae0b-1bd4-407f-9c80-58bbf981dc62','夜來四鼓枕上聞雨聲喜而不寐','虞儔','宋','宋诗','song-poetry','','[]','雨聲天外倒銀潢，枕上才聞喜欲狂。',64,'全唐诗/poet.song.154000.json','["雨聲天外倒銀潢，枕上才聞喜欲狂。", "鼓吹不須教兩部，稻粱行慶有千倉。", "青缸照影花無睡，紅袂行雲夢有香。", "最好空階瀉簷溜，却疑並舍壓糟床。"]'),
('93e98071-290f-4fdc-b67e-77589fdbd586','和七月初五日夜得雨','虞儔','宋','宋诗','song-poetry','','[]','一尊情話向南榮，好雨知時盆樣傾。',64,'全唐诗/poet.song.154000.json','["一尊情話向南榮，好雨知時盆樣傾。", "且喜黍苗饒歲事，莫愁梧竹作秋聲。", "簷花夜永燈前落，池草詩成夢裏驚。", "端的對床尋舊約，韋郎曾賦五言城。"]'),
('dbeb95dc-2942-4e26-a2f7-fc26d49a38a3','道中雨','虞儔','宋','宋诗','song-poetry','','[]','晨光欲動尚熹微，漠漠春陰未解圍。',64,'全唐诗/poet.song.154000.json','["晨光欲動尚熹微，漠漠春陰未解圍。", "霧掩前村迷酒旆，風吹寒色著征衣。", "功名底許妨行樂，出處年來果是非。", "一笑南坡歸夢裏，滿山桃李政芳菲。"]'),
('d0f938bd-f860-446b-852f-5ee2933a1047','龍池禱雨','虞儔','宋','宋诗','song-poetry','','[]','御府金奩出寶薰，爇來池上定知聞。',64,'全唐诗/poet.song.154000.json','["御府金奩出寶薰，爇來池上定知聞。", "龍應覆手能爲雨，岫豈無心漫出雲。", "秧插高田猶未遍，泉流幽澗恐難分。", "奉常典禮吾方與，毋作神羞視秩文。"]'),
('17c10871-7107-4ea7-a67d-3e5720b23b29','過登源英濟廟祈雨','虞儔','宋','宋诗','song-poetry','','[]','連年因旱禱叢祠，未免斯民有怨咨。',64,'全唐诗/poet.song.154000.json','["連年因旱禱叢祠，未免斯民有怨咨。", "擬學催科今晚矣，不能引去更何之。", "下田敢有百車望，好雨猶寬三日期。", "慚愧農家私水利，桔槔雖巧不容施。"]'),
('b131590f-aeea-4f52-8e6f-bd85ad26f429','和湯倅梅花韻','虞儔','宋','宋诗','song-poetry','','[]','玉奴端不負花期，乞得東皇一笑歸。',64,'全唐诗/poet.song.154000.json','["玉奴端不負花期，乞得東皇一笑歸。", "淡掃娥眉憐虢國，半勻粧面妬徐妃。", "有情立馬留新恨，無頼啼禽送落暉。", "金鉉政須和鼎實，莫嫌笛裏浪驚飛。"]'),
('9a8537b9-ce4c-41aa-966a-6fe1d4d03cd4','蠟梅  其一','虞儔','宋','宋诗','song-poetry','','[]','龍麝濃薰總不宜，幽香細細忽聞時。',64,'全唐诗/poet.song.154000.json','["龍麝濃薰總不宜，幽香細細忽聞時。", "蜜脾懸磬無餘味，鶴膝橫陳有老枝。", "玉蕊檀心還得似，蠟言梔貌有誰欺。", "却疑不是人間物，三嗅慇懃與賦詩。"]'),
('2bcb92ef-6371-408d-9ae1-f1eba8be6f15','蠟梅  其二','虞儔','宋','宋诗','song-poetry','','[]','冰霜元不與花宜，頗怪梅花亦後時。',64,'全唐诗/poet.song.154000.json','["冰霜元不與花宜，頗怪梅花亦後時。", "庾嶺別來無驛使，少林忽見有橫枝。", "化工真幻知誰辨，詩老題評豈我欺。", "世味飽諳渾似蠟，對花不飲漫賡詩。"]'),
('ce103587-c89e-48a3-a58a-c568bfa234aa','和萬舍人折贈蠟梅韻  其一','虞儔','宋','宋诗','song-poetry','','[]','問訊江梅意未回，少林橫出不知裁。',64,'全唐诗/poet.song.154000.json','["問訊江梅意未回，少林橫出不知裁。", "爭先頼有園夫報，折贈空驚驛使來。", "疎影暗香寧是伴，蠟言梔貌未須媒。", "主人聞說歸朝近，且趁眉間喜色開。"]'),
('da7f866c-9dca-4876-96f1-775e4e22a1d2','和萬舍人折贈蠟梅韻  其二','虞儔','宋','宋诗','song-poetry','','[]','蠟綴枝頭春來回，緗羅休用剪刀裁。',64,'全唐诗/poet.song.154000.json','["蠟綴枝頭春來回，緗羅休用剪刀裁。", "直須浮蟻相携去，應有遊蜂錯認來。", "暈紫檀心真似假，嬌黄粧額自能媒。", "年來世味渾如此，嚼蕊吹香一笑開。"]'),
('986265c1-1919-49d8-8ab3-7e9c497668ed','和萬舍人折贈蠟梅韻  其三','虞儔','宋','宋诗','song-poetry','','[]','步遶名園日幾回，司花著意巧能裁。',64,'全唐诗/poet.song.154000.json','["步遶名園日幾回，司花著意巧能裁。", "影疎雅稱燈籠映，香細疑從酒面來。", "破白江梅羞月妬，黏紅僊杏待春媒。", "何如新樣龍山種，却在京都占早開。"]'),
('73fb20e3-0bf2-4c3c-b169-85a5145798c5','夜讀邵堯夫詩戲效其體再賦蠟梅','虞儔','宋','宋诗','song-poetry','','[]','紛紛蜂子競生涯，每到花時輒放衙。',64,'全唐诗/poet.song.154000.json','["紛紛蜂子競生涯，每到花時輒放衙。", "懸室盡將花作蠟，何人翻以蠟爲花。", "姑從凡卉論先後，若比江梅有等差。", "弄假像真真像假，小兒造物未須誇。"]'),
('40bdd760-b01f-4718-9c53-74f43365db12','中秋夜微雨','虞儔','宋','宋诗','song-poetry','','[]','醉張白眼望層空，作意中秋一笑同。',64,'全唐诗/poet.song.154000.json','["醉張白眼望層空，作意中秋一笑同。", "忽訝微雲得急雨，縱妨明月有清風。", "連宵桂近姮娥惜，盡日槐忙舉子工。", "勿指凉天云即是，且須傾盡玉西東。"]'),
('57a667bf-c010-48c1-af03-ee9ac8f3e651','十六日雲氣薄陰晚有雨微甚夜間頗凉恐明日未必有雨也','虞儔','宋','宋诗','song-poetry','','[]','誰與天公沃亢陽，灑塵微雨僅毫芒。',64,'全唐诗/poet.song.154000.json','["誰與天公沃亢陽，灑塵微雨僅毫芒。", "只憂南畝頻年旱，敢愛北窗通夕凉。", "何物興雲須蜴蜥，幾時舞野定商羊。", "會當直入雷霆室，戲掉狂車下大荒。"]'),
('f539f7a2-b57f-4831-97d9-60ef0ce9849a','蚊  其一','虞儔','宋','宋诗','song-poetry','','[]','床前蠟紙一燈明，殷殷聞雷數震驚。',64,'全唐诗/poet.song.154000.json','["床前蠟紙一燈明，殷殷聞雷數震驚。", "忽去青天無鳥跡，驟來紅樹有鶑聲。", "噆膚噬血寧甘死，投隙穿帷太巧生。", "爲爾通宵愁不寐，幾回枕上又詩成。"]'),
('944f7521-d7db-4126-a7b1-61aa366f2147','蚊  其二','虞儔','宋','宋诗','song-poetry','','[]','青奴良夜偶相依，斑扇團團亦倦揮。',64,'全唐诗/poet.song.154000.json','["青奴良夜偶相依，斑扇團團亦倦揮。", "我自蒙頭還引睡，渠應皤腹不能飛。", "多愁白髮三千丈，無分紅綃十幅圍。", "安得西風來一掃，固知么麽未勝威。"]'),
('874918f9-81b3-41c0-a737-e73e8a8b70bf','王簿不憚暑途親扣石金祈雨蓋有志乎民者也以小詩簡之','虞儔','宋','宋诗','song-poetry','','[]','饑饉憂渠欲洊臻，大田不雨已生塵。',64,'全唐诗/poet.song.154000.json','["饑饉憂渠欲洊臻，大田不雨已生塵。", "何人有力能鞭石，老令無能漫積薪。", "諸佛未嘗違衆願，上蒼寧不憫斯民。", "誠煩仇覽登山履，爲扣巖前彼上人。"]'),
('352d857e-7ec6-4a75-afb4-37e8d405c166','委長洲趙丞禱雨陽山龍祠有應','虞儔','宋','宋诗','song-poetry','','[]','不向龍祠小乞靈，連宵那得雨冥冥。',64,'全唐诗/poet.song.154000.json','["不向龍祠小乞靈，連宵那得雨冥冥。", "勢方聚處中心喜，聲漸微時側耳聽。", "便覺田頭秧稻綠，更誇隴首麥苗青。", "豐登自此無公事，只有棠陰蔽廣庭。"]'),
('ea1b09ec-b25c-4000-a898-b7be12682e5f','再委趙丞陽山送龍禱雨  其一','虞儔','宋','宋诗','song-poetry','','[]','傳聞神姥産英靈，雷電當時亦晦冥。',64,'全唐诗/poet.song.154000.json','["傳聞神姥産英靈，雷電當時亦晦冥。", "好雨固宜隨禱應，夜窗曾誤幾番聽。", "關心病守頭空白，失喜農夫眼倍青。", "水溢旱乾寧有數，人間無路叩天庭。"]'),
('cfcf1c90-6f00-4378-8da4-9b586df62bdb','再委趙丞陽山送龍禱雨  其二','虞儔','宋','宋诗','song-poetry','','[]','老龍高卧復何求，韜斂風雷自一湫。',64,'全唐诗/poet.song.154000.json','["老龍高卧復何求，韜斂風雷自一湫。", "不恨如麻無雨脚，却愁生耳有禾頭。", "向來河內慚移粟，此去江邊欲具舟。", "龍若有靈須早計，霖霪莫待火西流。"]'),
('7cc79c44-9ebc-4702-b573-dbb8656d098a','昨夜雨又作方此祈禱輒得數語述懷','虞儔','宋','宋诗','song-poetry','','[]','淫雨天公不肯晴，區區香火屢哀鳴。',64,'全唐诗/poet.song.154000.json','["淫雨天公不肯晴，區區香火屢哀鳴。", "兩年苦潦民何罪，千里分憂責匪輕。", "已幸早禾方露積，正憐秋稼與雲平。", "蓱號莫敗西成好，捩手從來易覆羹。"]'),
('1fee2ec2-e3ec-4249-a0db-a12782a1fc8d','七月十四日夜大雨徹曉方止田家云早晚禾自此不憂矣喜而爲詩','虞儔','宋','宋诗','song-poetry','','[]','夜雨傾盆擣瓦溝，簷聲洶湧碎江流。',64,'全唐诗/poet.song.154000.json','["夜雨傾盆擣瓦溝，簷聲洶湧碎江流。", "安眠一枕西窗曉，飽飯十分南畝秋。", "老火熏天已無跡，頻年赤地更誰憂。", "起來喜撥床頭甕，却待今宵月滿樓。"]'),
('d2467ea6-a501-4725-a78b-fa0acd17aa03','五月二十七日夜大雨前三日熱甚','虞儔','宋','宋诗','song-poetry','','[]','雷車誰喚阿香推，釀雨雲頭簇不開。',64,'全唐诗/poet.song.154000.json','["雷車誰喚阿香推，釀雨雲頭簇不開。", "猛熱急掀江漢立，先聲偏上竹梧來。", "高唐賦就何曾夢，杜曲詩成不費催。", "頗欲燈前同夜酌，却愁牢落餽無臺。"]'),
('a91218a1-852e-42d9-8ae0-36ddd10d3cda','七月三十日大雨連宵  其一','虞儔','宋','宋诗','song-poetry','','[]','徹夜盆翻天井潢，迴瀾誰障百川狂。',64,'全唐诗/poet.song.154000.json','["徹夜盆翻天井潢，迴瀾誰障百川狂。", "鯤方怒翼思溟海，鼠已摇牙伺太倉。", "秋著屏山驚客枕，潤添衣籠費鑪香。", "惠連應記池塘夢，近有書來說對床。"]'),
('b6319724-aa59-4e58-89bd-fb32f3e49504','七月三十日大雨連宵  其二','虞儔','宋','宋诗','song-poetry','','[]','乘槎有客泛仙潢，咋指泥塗悔我狂。',64,'全唐诗/poet.song.154000.json','["乘槎有客泛仙潢，咋指泥塗悔我狂。", "此去不煩推謝令，向來寧是尼臧倉。", "愁驚過雁鄉心碎，喜溢浮蛆甕面香。", "金井老梧秋色重，時翻危葉墮銀床。"]'),
('699a5e38-0fbd-4652-a29d-3e761f379140','十七日乘馬過草堂已而驟雨','虞儔','宋','宋诗','song-poetry','','[]','此邦旱暵已連年，民亦何辜欲籲天。',64,'全唐诗/poet.song.154000.json','["此邦旱暵已連年，民亦何辜欲籲天。", "鳩拙林間時自喚，龍慵潭底敢安眠。", "忽看注雨如車軸，便覺流泉滿稻田。", "我亦駕言隨霹靂，一瓢傾倒馬鞍前。"]'),
('7ff943db-899d-4f2e-b4a5-397c1a77c3f7','下山雨驟  其一','虞儔','宋','宋诗','song-poetry','','[]','下山雖幸免顛躋，驟雨冥冥步轉迷。',64,'全唐诗/poet.song.154000.json','["下山雖幸免顛躋，驟雨冥冥步轉迷。", "白馬已翻青嶂去，黄鸝猶戀綠林啼。", "人皆有路通霄漢，我獨無橋渡澗溪。", "且傍田塍欹側過，從教甲子混塗泥。"]'),
('f124a614-21bc-4149-a2d4-7a059a725fcb','下山雨驟  其二','虞儔','宋','宋诗','song-poetry','','[]','連宵風雨太飄颻，頗訝龍吟意氣豪。',64,'全唐诗/poet.song.154000.json','["連宵風雨太飄颻，頗訝龍吟意氣豪。", "三座危橋過不易，一溪湍水漲能高。", "棲遲王事嗟何及，咫尺威顔敢告勞。", "袖取豐年天上去，洗泥準擬醉香醪。"]'),
('d226eb94-dce8-40de-9d0d-94caa8a87148','下山雨驟  其三','虞儔','宋','宋诗','song-poetry','','[]','寶熏降自九重天，再款龍祠禮亦專。',64,'全唐诗/poet.song.154000.json','["寶熏降自九重天，再款龍祠禮亦專。", "謝雨歸來還得雨，今年必定作豐年。", "彌天膏潤人皆喜，連日奔馳我獨賢。", "回首家山今不遠，固應慚恨不歸田。"]'),
('10111aa2-2e4d-4b94-8e75-0ba8448e0dc4','久雨','虞儔','宋','宋诗','song-poetry','','[]','秋到天公日日陰，林間厭聽鵓鳩鳴。',64,'全唐诗/poet.song.154000.json','["秋到天公日日陰，林間厭聽鵓鳩鳴。", "向來南畝頻憂旱，此去西成只欠晴。", "簷有漏痕看菌出，徑無行跡認苔生。", "夜窗細誦秋陽賦，才謝坡仙和不成。"]'),
('efe5388d-bd21-4ed9-9b53-71cd0a4aa53e','和漢老弟久雨','虞儔','宋','宋诗','song-poetry','','[]','簷聲點滴送愁頻，夢雨連江遽一旬。',64,'全唐诗/poet.song.154000.json','["簷聲點滴送愁頻，夢雨連江遽一旬。", "杜老多情還動酌，坡公何事却傷神。", "渭城官柳難留客，巫峽行雲不見人。", "可是蓱號工灑道，東郊準備要迎春。"]'),
('c17fed0a-e551-4c1f-aa57-903c64feac72','喜雨呈太守','虞儔','宋','宋诗','song-poetry','','[]','精禱能令天意回，猖狂旱魃敢爲災。',64,'全唐诗/poet.song.154000.json','["精禱能令天意回，猖狂旱魃敢爲災。", "龍眠熟處雷呼覺，蟻戰酣時雨趁來。", "耕父荷鋤歌召杜，腐儒秉筆愧鄒枚。", "太平知有三登象，從此官租不費催。"]'),
('5cc3dfd2-c982-4a3b-a90f-6424133cf808','和廣德宋宰喜雨','虞儔','宋','宋诗','song-poetry','','[]','一雨豐年兆可探，全勝雪瑞白成三。',64,'全唐诗/poet.song.154000.json','["一雨豐年兆可探，全勝雪瑞白成三。", "偏憐令尹關心切，喜對農夫洗汗慚。", "秔稻秀畦欣綠潤，芙蓉依水媚紅酣。", "詞源頓遣如泉湧，酒量懸知似海涵。"]'),
('05e7f7d5-2a52-4f22-97e6-27aca23e0116','和主簿喜雨二首  其一','虞儔','宋','宋诗','song-poetry','','[]','龍眠熟處雷呼醒，蟻戰酣時雨趁來。',64,'全唐诗/poet.song.154000.json','["龍眠熟處雷呼醒，蟻戰酣時雨趁來。", "凉入稻雲青漠漠，潤添田水白皚皚。", "但期家給皆紅腐，莫管庭空長綠苔。", "老令催科知自拙，推擠不法謂何哉。"]'),
('f5d69b22-2773-4f63-9b6a-ff93ebdfe06e','和主簿喜雨二首  其二','虞儔','宋','宋诗','song-poetry','','[]','年來事事與心違，墨綬塵勞莫我知。',64,'全唐诗/poet.song.154000.json','["年來事事與心違，墨綬塵勞莫我知。", "慷慨歸田雖有賦，殷勤喜雨漫賡詩。", "誰憐飯顆山頭瘦，却想松江水面肥。", "一笑桑榆收已暮，向來膏潤太踰時。"]'),
('e700a5d0-fb44-441d-b9c4-668a27cd2e64','卧病枕上再用韻  其一','虞儔','宋','宋诗','song-poetry','','[]','文書堆案眼慵開，客有可人今雨來。',64,'全唐诗/poet.song.154000.json','["文書堆案眼慵開，客有可人今雨來。", "說劍丹心空耿耿，岸巾雪鬢欲皚皚。", "山田漸喜滋香稻，客位從教長紫苔。", "涸轍窮鱗頼濡沫，未宜曷月詠歸哉。"]'),
('c57bf25f-4190-4c46-8601-412e9aebfd29','卧病枕上再用韻  其二','虞儔','宋','宋诗','song-poetry','','[]','領邑西來物物違，只應松竹舊相知。',64,'全唐诗/poet.song.154000.json','["領邑西來物物違，只應松竹舊相知。", "寬心雨意濃如酒，滿眼秋懷總是詩。", "慚愧不才勞撫字，平生何意羨輕肥。", "飄然儻遂歸田賦，食蘗毋忘在莒時。"]'),
('d9b5954f-b9ea-43db-959d-4f6457c8c8b2','再用韻簡王簿  其一','虞儔','宋','宋诗','song-poetry','','[]','山雲潑墨度牆隈，信道鳴鳩喚雨來。',64,'全唐诗/poet.song.154000.json','["山雲潑墨度牆隈，信道鳴鳩喚雨來。", "驟瀉竹梢青羃羃，亂翻荷蓋白皚皚。", "尊前花落愁賒酒，地上錢流錯認苔。", "更願公家寬賦斂，斯民卒歲亦悠哉。"]'),
('899b1539-7264-4eb7-998f-772f666a490e','再用韻簡王簿  其二','虞儔','宋','宋诗','song-poetry','','[]','當面論交背面違，此心叔向幾人知。',64,'全唐诗/poet.song.154000.json','["當面論交背面違，此心叔向幾人知。", "喜君一見便傾蓋，過我相從唯說詩。", "別後梅花看太瘦，向來瓠白不應肥。", "何如且緩東歸策，共醉橙黄橘綠時。"]'),
('a99d17a9-4650-451a-a6c9-0047c41bf824','徽州績溪縣六月二十五日迎汪王於縣廳祈雨未之應也七月三日率同官再禱焉酌獻方畢陰雲四合甘霔大霈因以小詩紀實','虞儔','宋','宋诗','song-poetry','','[]','何須禱旱必桑林，試扣叢祠丐一臨。',64,'全唐诗/poet.song.154000.json','["何須禱旱必桑林，試扣叢祠丐一臨。", "再拜爐烟方裛裛，四周雲氣已駸駸。", "田龜向去亡凶兆，垤鸛新來有好音。", "多謝神靈憐老令，肯傾膏澤慰民心。"]'),
('7cc81f30-fc14-4317-bb6e-37f2c5d9a322','和主簿王伯倫喜雨','虞儔','宋','宋诗','song-poetry','','[]','電幟摇摇眩目光，雷車殷殷訝空腸。',64,'全唐诗/poet.song.154000.json','["電幟摇摇眩目光，雷車殷殷訝空腸。", "咄嗟有底千峯雨，珍重無多一瓣香。", "秔稻氣蘇南畝喜，芭蕉聲到北窗凉。", "恭惟英濟綱維是，併遣炎官理去艎。"]'),
('5d31ac32-bd10-4dbe-834e-ff4e4f5dac7b','喜雨','虞儔','宋','宋诗','song-poetry','','[]','鼎來雨喜動吟牋，頓遣醯雞舞甕天。',64,'全唐诗/poet.song.154000.json','["鼎來雨喜動吟牋，頓遣醯雞舞甕天。", "傅野要觀新事業，巫山莫學短因緣。", "碧筩便好浮家釀，紅粉還羞著老年。", "此意自佳君自會，將詩不必衆人傳。"]'),
('2acf44b1-432c-4e05-86e5-328cd6d0cf7a','憶友人','虞儔','宋','宋诗','song-poetry','','[]','紫鸞栖棘乳溪邊，不羨羣飛漫刺天。',64,'全唐诗/poet.song.154000.json','["紫鸞栖棘乳溪邊，不羨羣飛漫刺天。", "一見交情真我輩，更將詩句洗塵緣。", "寧唯刮目須三日，恨不從公蚤十年。", "只恐秋風趣分袂，尺書儻有鴈能傳。"]'),
('b52ca1d3-5a37-4d60-a4e5-8ef8a98e7235','主簿昨示喜雨之作末章用李文饒故事非所敢聞用韻回納','虞儔','宋','宋诗','song-poetry','','[]','朝來一穗看爐烟，遽挽銀河下九天。',64,'全唐诗/poet.song.154000.json','["朝來一穗看爐烟，遽挽銀河下九天。", "東海不冤私自幸，南陽高卧且隨緣。", "佳名德雨聞前代，尺字商霖證昔年。", "老子婆婆那辨此，兩翁心印有人傳。"]'),
('e68019a1-4233-436a-b001-ad43a62c21f5','初夏凹沼獨坐','虞儔','宋','宋诗','song-poetry','','[]','牆隈綠裊風前竹，池上青橫雨後峯。',64,'全唐诗/poet.song.154000.json','["牆隈綠裊風前竹，池上青橫雨後峯。", "森然便有濠濮想，若者曾吞雲夢胸。", "杳無碧澗來鸂鶒，安得舊水藏蛟龍。", "我今齒髮亦自料，回首家山歸興濃。"]'),
('aaa31615-009e-43a5-bf7d-7c57ed36fe55','俯江樓','虞儔','宋','宋诗','song-poetry','','[]','異鄉王粲懶登樓，腸斷淮山落木秋。',64,'全唐诗/poet.song.154000.json','["異鄉王粲懶登樓，腸斷淮山落木秋。", "塞上陰雲空漠漠，江邊艇子故悠悠。", "悲凉只怕聞孤鴈，浩蕩那堪沒白鷗。", "莫怪楚囚頻下淚，何人談話到神州。"]'),
('c55c31d9-a830-4c35-ab00-a2dbf857a249','十一月三十日乃耘老弟生朝余是日也宿留富陽驛中念之殊不勝情因賦一詩俟到吳門有便寄去','虞儔','宋','宋诗','song-poetry','','[]','玉琯新陽七日來，天將風月賦詩才。',64,'全唐诗/poet.song.154000.json','["玉琯新陽七日來，天將風月賦詩才。", "別來又喜逢初度，相望何由把一杯。", "霜後不凋門外柳，春前已折隴頭梅。", "團欒今夜華堂燕，應念三州數往回。"]'),
('5cbc1ea5-3951-4648-8114-490a7fb90199','和湯倅七夕','虞儔','宋','宋诗','song-poetry','','[]','目斷銀河婉孌期，綵雲香霧轉馡馡。',64,'全唐诗/poet.song.154000.json','["目斷銀河婉孌期，綵雲香霧轉馡馡。", "天孫無頼能專巧，世俗由來亦妄祈。", "穉子喚人占蟢網，老妻憐我泣牛衣。", "客星若就君平卜，更問金穰與木饑。"]'),
('f63f6d8c-3395-4693-b18f-354e0c5e594a','和總管姜知閣','虞儔','宋','宋诗','song-poetry','','[]','下筆梅山漫不休，詩筒倏寄置書郵。',64,'全唐诗/poet.song.154000.json','["下筆梅山漫不休，詩筒倏寄置書郵。", "分符我亦慙銅虎，問俗人誰忍佩牛。", "已洗圜扉亡久繫，更教彩棒息羣偷。", "年來况是催科拙，聚斂平生笑冉求。"]'),
('f0be8c26-724f-4715-ba86-1bf6042b5f62','和楊仲才歸途秋郊即事','虞儔','宋','宋诗','song-poetry','','[]','馬上西風著面凉，翩翩烏帽更低昂。',64,'全唐诗/poet.song.154000.json','["馬上西風著面凉，翩翩烏帽更低昂。", "晚晴是處鴉聲喜，秋熟連阡禾穗香。", "穉子候門應自語，征夫指路未渠忙。", "歇鞍野店誰爲伴，自買村醪一舉觴。"]'),
('5a4bb3cf-b981-49c3-85a4-3909f2a4ece2','頃嘗將漕淮東林子長今膺是選因以小詩述懷庶幾古人贈言之意云  其一','虞儔','宋','宋诗','song-poetry','','[]','德星天遣出淮濆，玉節光華委十分。',64,'全唐诗/poet.song.154000.json','["德星天遣出淮濆，玉節光華委十分。", "可但籌邊專餽餉，直須曠土盡耕耘。", "向來我已慚無效，此去君當勉策勳。", "尚有龜山風浪惡，得無遺恨雁離羣。"]'),
('f6a1c19f-1a90-47a5-a567-4daebc7b43ea','頃嘗將漕淮東林子長今膺是選因以小詩述懷庶幾古人贈言之意云  其二','虞儔','宋','宋诗','song-poetry','','[]','淮邊陳迹試重論，走遍西途落木村。',64,'全唐诗/poet.song.154000.json','["淮邊陳迹試重論，走遍西途落木村。", "依舊江山連北固，承平池館羨東園。", "中原入望堪垂涕，古汴無情尚有痕。", "歲漕東南六百萬，云何異域得遊魂。"]'),
('cc48d986-6f47-415a-ac8c-637cd8e501a6','送萬舍人將漕江東','虞儔','宋','宋诗','song-poetry','','[]','左螭玉立聳朝端，底事飄然便掛冠。',64,'全唐诗/poet.song.154000.json','["左螭玉立聳朝端，底事飄然便掛冠。", "簡記起家千載遇，光華持節萬人看。", "溪山好處寧終戀，鷗鷺盟前莫遽寒。", "已是詔書催上道，却煩尺鯉問平安。"]'),
('17cd7e18-1ee0-44ca-aa89-fd733bde6794','余壬子秋丁太夫人憂因取藏經看閲至甲寅春以病眼且止然將及一半矣尚期晚歲畢此志願但兩年來有煩主藏上人昕公取送良勞因以一偈謝之','虞儔','宋','宋诗','song-poetry','','[]','五千經卷乃吾心，眼力年來却不勝。',64,'全唐诗/poet.song.154000.json','["五千經卷乃吾心，眼力年來却不勝。", "且學趙州看半藏，從教舍利說三乘。", "循行數字難成佛，兀坐焚香也似僧。", "此法本來無所得，多生受記有燃燈。"]'),
('8452ef80-a8b7-4454-b6fe-9a950069c1a8','耘老弟於新廳之後起樓名之曰疊翠有詩因次韻','虞儔','宋','宋诗','song-poetry','','[]','樓成疊翠相奇奇，不羨圍屏錦繡機。',64,'全唐诗/poet.song.154000.json','["樓成疊翠相奇奇，不羨圍屏錦繡機。", "卜築又新王粲宅，登臨莫下董生帷。", "高吟得助添新卷，清賞何須貯舞衣。", "問舍却憐吾未就，歸心長與落霞飛。"]'),
('0b0aa8d4-66fa-43fa-8d8b-75f32252c892','求楊仲才芍藥','虞儔','宋','宋诗','song-poetry','','[]','見說江都一騎來，筠籃坏土带春回。',64,'全唐诗/poet.song.154000.json','["見說江都一騎來，筠籃坏土带春回。", "不堪羈宦思金谷，寧有詩情似玉臺。", "綸閣翻階無復夢，乳溪臨檻想傳杯。", "殷勤分贈須聞早，社後重陽政好培。"]'),
('1f2e58cf-8810-40fc-8624-9f8d1df007d5','收漢老弟近書知十全遂勿藥之喜慰可知也但未卜來期詩以見意','虞儔','宋','宋诗','song-poetry','','[]','一日思君一度年，家山好在落霞邊。',64,'全唐诗/poet.song.154000.json','["一日思君一度年，家山好在落霞邊。", "飛鴻日去情何限，黄耳書來病已痊。", "欹枕池塘春草夢，閉門風雨落梅天。", "南坡政恐春留住，過我何時果著鞭。"]'),
('031bbf95-af13-42ad-af74-76b264de01e8','和聞杜鵑','虞儔','宋','宋诗','song-poetry','','[]','萬里歸飛怪底遲，豈緣鳥道嶮而奇。',64,'全唐诗/poet.song.154000.json','["萬里歸飛怪底遲，豈緣鳥道嶮而奇。", "尚懷舊國初來日，偏恨羣芳欲盡時。", "回首暮山寧久住，論心殘月漫相知。", "何人遠道長爲客，爲爾聲聲勞夢思。"]'),
('5f99d2ba-977a-440a-848c-f3efd1358d26','宿祠山報恩寺枕上聞杜鵑有感','虞儔','宋','宋诗','song-poetry','','[]','此去家山僅兩程，不煩鳥語苦丁寧。',64,'全唐诗/poet.song.154000.json','["此去家山僅兩程，不煩鳥語苦丁寧。", "烟花三月忙中過，風雨連宵夢裏聽。", "問鴈呼卿情大薄，聞鷄起舞意還醒。", "年來縱跡渾無定，渠亦相憐水上萍。"]'),
('051e3ffe-eea7-468e-9d99-56d71f6902ba','次韻曾使君和刪定鮑倅喜譙樓雙門復舊觀之作','虞儔','宋','宋诗','song-poetry','','[]','公家文字足搜尋，間覽容陪夏日臨。',64,'全唐诗/poet.song.154000.json','["公家文字足搜尋，間覽容陪夏日臨。", "句裏江山元自舊，筆端造化速宜今。", "朱扉對啟雄潭府，秀氣平分入泮林。", "青佩龍門行在望，躍鞭莫負使君心。"]'),
('ad7f5ec0-cf9c-4457-9f07-74fd5e64f5ba','和王誠之羣圃勝集','虞儔','宋','宋诗','song-poetry','','[]','何人浪說四難并，此地追隨眼更清。',64,'全唐诗/poet.song.154000.json','["何人浪說四難并，此地追隨眼更清。", "飛蓋數移紅步幛，肩輿穩度翠圍屏。", "春回觴詠頻頻舉，風度笙歌處處聽。", "晝短夜長公莫恨，當家故事有蘭亭。"]'),
('6b954863-3aa2-4dad-b8b2-dce1cf50b39b','元日小集耘老弟有詩和韻','虞儔','宋','宋诗','song-poetry','','[]','弟姪團欒豈偶然，華堂綺席間嬋娟。',64,'全唐诗/poet.song.154000.json','["弟姪團欒豈偶然，華堂綺席間嬋娟。", "試看今夕知何夕，頗覺新年勝舊年。", "黄紙除書須有命，青春作伴且隨緣。", "從今屢費何須惜，日辦盃觴趁和篇。"]'),
('0eac32eb-dbaa-479e-b2a1-873c79b012b6','簡友人','虞儔','宋','宋诗','song-poetry','','[]','按劍何由駭夜光，險心真復易羊腸。',64,'全唐诗/poet.song.154000.json','["按劍何由駭夜光，險心真復易羊腸。", "未能種橘千奴足，且欲滋蘭九畹香。", "俗物滿前多汩沒，玉人在側獨清凉。", "夜來忽有家山夢，便向清溪欲艤艎。"]'),
('584613d8-574e-4769-b2d7-bef90a053d3e','途中述懷','虞儔','宋','宋诗','song-poetry','','[]','悠然旅酌夜沉沉，漫想歌眉带淺顰。',64,'全唐诗/poet.song.154000.json','["悠然旅酌夜沉沉，漫想歌眉带淺顰。", "興寄鱗鴻寧有限，詩成珠玉未羞貧。", "尚煩瀟灑登山屐，聊慰崎嶇窮谷民。", "已笑割鷄非我事，頗嘗栖棘有斯人。"]'),
('3b5b4fb8-6e5f-4793-b1c7-b9c47f8b5646','和郁簿','虞儔','宋','宋诗','song-poetry','','[]','先生雅意在垂虹，底事鸞栖枳棘中。',64,'全唐诗/poet.song.154000.json','["先生雅意在垂虹，底事鸞栖枳棘中。", "幾欲上書排北闕，却應舉扇障西風。", "官清高枕夢魂好，興動長吟詩句工。", "瑣瑣升沉何足道，只憑心地與天通。"]'),
('a126584a-5be6-418b-b5cf-ca379a01b9fa','清明','虞儔','宋','宋诗','song-poetry','','[]','江南三月暮春天，上巳清明五日前。',64,'全唐诗/poet.song.154000.json','["江南三月暮春天，上巳清明五日前。", "紅杏園林初過雨，綠楊庭院欲生烟。", "無花無酒傷今日，宜麥宜蠶勝去年。", "却怪山中時候早，樹林深處有鳴蟬。"]'),
('ba44919e-c653-47aa-8e02-f4348c29b3b7','讀漢老弟中秋前一夕之詩似太凄切輒次韻勉釋之','虞儔','宋','宋诗','song-poetry','','[]','秋與詩人著意清，不平寧作候蟲鳴。',64,'全唐诗/poet.song.154000.json','["秋與詩人著意清，不平寧作候蟲鳴。", "閒愁有底能千斛，久雨終當快一晴。", "富貴時來何足道，英雄天亦不徒生。", "來宵徑就姮娥約，丹桂當年種已成。"]'),
('0299ccf4-0735-4956-af0f-44b784661116','自中秋月圓木犀開後倡酬絡繹今可以止矣再書數句殿其後','虞儔','宋','宋诗','song-poetry','','[]','秋月秋花自一回，錦囊收拾靡遺才。',64,'全唐诗/poet.song.154000.json','["秋月秋花自一回，錦囊收拾靡遺才。", "吟餘顧兔毫端滿，賦罷文犀紙面開。", "十里清香供隠几，三人對影稱揮杯。", "笑渠冷淡爲生活，何似笙歌鼎沸催。"]'),
('fba38d0e-2edd-4cd5-8273-cc09db42a8fd','酬常丞見和','虞儔','宋','宋诗','song-poetry','','[]','周南留滯玉堂仙，千騎那教下蜀川。',64,'全唐诗/poet.song.154000.json','["周南留滯玉堂仙，千騎那教下蜀川。", "梁上幾看明月夜，江東空想暮雲天。", "五年契闊音書斷，萬里歸來語笑鮮。", "喜有常郎天下士，肯來相對語殘編。"]'),
('2e1eec87-5c3c-4341-b26d-e67565364b6a','用韻酬翟曾二倅和章  其一','虞儔','宋','宋诗','song-poetry','','[]','那得朝朝瓊樹新，擁爐添炭費烏銀。',64,'全唐诗/poet.song.154000.json','["那得朝朝瓊樹新，擁爐添炭費烏銀。", "試呵凍筆還搜句，淺酌香醪未計巡。", "過眼年華休恨晚，轉頭天令即行春。", "紛紛桃李誰知問，祇有寒梅是故人。"]'),
('d6b1aaa1-18b5-42fd-a165-2348a802c31f','用韻酬翟曾二倅和章  其二','虞儔','宋','宋诗','song-poetry','','[]','詩成開府讓清新，紙掃溪藤筆弄銀。',64,'全唐诗/poet.song.154000.json','["詩成開府讓清新，紙掃溪藤筆弄銀。", "斗轉蒼龍歸北望，日行黄道傒東巡。", "人情自是隨時變，天意何私與物春。", "官裏簿書殊未了，不知花事屬何人。"]'),
('14c4ae8a-c636-4761-80ba-9949e6c1e5a2','兩日絕市無肉舉家不免蔬食因書數語  其一','虞儔','宋','宋诗','song-poetry','','[]','市無晨飲助加餐，空愧先生苜蓿盤。',64,'全唐诗/poet.song.154000.json','["市無晨飲助加餐，空愧先生苜蓿盤。", "尚有園人供菜把，漫勞穉子寫牌單。", "俸錢先自無多了，賓客從來不慣看。", "已誓長齋依繡佛，妻孥休怪瘦欒欒。"]'),
('004163e7-5e28-4eac-a2d4-d90837d8fcb2','兩日絕市無肉舉家不免蔬食因書數語  其二','虞儔','宋','宋诗','song-poetry','','[]','山園秀色故堪餐，明月批來白玉盤。',64,'全唐诗/poet.song.154000.json','["山園秀色故堪餐，明月批來白玉盤。", "小縣經年常乏俸，頹牆過午尚懸單。", "婦興舉案齊眉歎，婢媿添薪墨腕看。", "無肉縱令人解瘦，却宜相對碧檀欒。"]'),
('02d68e25-1ec4-4c8d-97b4-0101c16a6c47','兩日絕市無肉舉家不免蔬食因書數語  其三','虞儔','宋','宋诗','song-poetry','','[]','怪生食指動晨餐，拗項蒸毛忽滿盤。',64,'全唐诗/poet.song.154000.json','["怪生食指動晨餐，拗項蒸毛忽滿盤。", "總爲饑驅嗟我老，未能飽死笑人單。", "不除豪氣杯中興，空有功名鏡裏看。", "菽水雖貧歸去好，白頭慈母要團欒。"]'),
('52df4641-d2f1-4d86-af7e-a053d076d74b','再用韻述懷','虞儔','宋','宋诗','song-poetry','','[]','少年發憤欲忘餐，信木能鑽透石盤。',64,'全唐诗/poet.song.154000.json','["少年發憤欲忘餐，信木能鑽透石盤。", "燈火半生徒自苦，虀鹽併日不嫌單。", "嗟來未肯低頭拜，臭腐那須著眼看。", "何物馬肝猶不悟，憐渠五利竟誅欒。"]'),
('64d4e995-229d-4e35-a5c7-318a571405f9','送顔尚書知泉州','虞儔','宋','宋诗','song-poetry','','[]','聽履星辰最上頭，一麾得請暫南州。',64,'全唐诗/poet.song.154000.json','["聽履星辰最上頭，一麾得請暫南州。", "高風凜凜推前輩，政路駸駸却倦游。", "地近枌榆同衣錦，天低雨露密承流。", "只今廊廟須公等，燕寢凝香莫久留。"]'),
('c0c2736b-eb1a-483b-a0ce-fdd19f8a3103','臨安泛舟','虞儔','宋','宋诗','song-poetry','','[]','雨送行人上短篷，東君更借一帆風。',64,'全唐诗/poet.song.154000.json','["雨送行人上短篷，東君更借一帆風。", "桃源春水半篙穩，錦谷清溪幾曲通。", "遠岫天邊凝晚碧，夕陽波面泛微紅。", "舟行又勝山行好，兩岸芳菲一顧中。"]'),
('0cc9ad59-4f00-4c3e-9049-42f118f5442a','往瓜州護使客回程','虞儔','宋','宋诗','song-poetry','','[]','寒天短日少晶輝，薄暮邊城鼓角悲。',64,'全唐诗/poet.song.154000.json','["寒天短日少晶輝，薄暮邊城鼓角悲。", "外使方將接踵至，淮民未有息肩期。", "吁嗟道路頻牽挽，表裏河山幾合離。", "聞道遺黎尚思漢，中原恢復定何時。"]'),
('8702956f-f114-457b-9cbe-1fd5a2294318','夜舟過龜山','虞儔','宋','宋诗','song-poetry','','[]','長淮東下月西流，起視龜山勢若浮。',64,'全唐诗/poet.song.154000.json','["長淮東下月西流，起視龜山勢若浮。", "砢岸崎嶇須列炬，波濤洶湧更行舟。", "今秋暴漲尤堪畏，去歲堅冰亦合憂。", "有底往來能屑屑，癡兒了事幾時休。"]'),
('ba91bb86-b0fd-4025-b1b3-c7426bab0988','上巳恐可回舟略訪子長園亭然未敢爲宿諾','虞儔','宋','宋诗','song-poetry','','[]','名園天氣更須新，况有彈箏甲用銀。',64,'全唐诗/poet.song.154000.json','["名園天氣更須新，况有彈箏甲用銀。", "舟欲暫回成邂逅，酒因同載作逡巡。", "飛花一片休嗟晚，啼鳥千巖莫怨春。", "未暇湖亭修故事，水嬉遍閲水邊人。"]'),
('0d46de8c-bb06-4b3a-a569-6029856fe229','和漢老弟立春','虞儔','宋','宋诗','song-poetry','','[]','吹葭六管候頻頻，眉壽先儲酒十旬。',64,'全唐诗/poet.song.154000.json','["吹葭六管候頻頻，眉壽先儲酒十旬。", "鞭到土牛休袖手，斗迴天駟已馳神。", "花梢綵勝翻新樣，鏡裏朱顔只故人。", "生菜玉纖能細縷，大家醉賞滿盤春。"]'),
('fffe8776-c1dc-468e-b729-107ca7b8a35b','正月二日大雪','虞儔','宋','宋诗','song-poetry','','[]','東風欲動管灰飛，剪綵工夫莫恨遲。',64,'全唐诗/poet.song.154000.json','["東風欲動管灰飛，剪綵工夫莫恨遲。", "殘臘竟呈三白瑞，新春元與六花期。", "羊羔酒好浮瓊液，牛尾狸堪削玉肌。", "欲就江梅賒一笑，前村容有未開枝。"]'),
('0e50b758-ed7d-4423-ad0b-461dd338f44c','和宋宰立春雨  其一','虞儔','宋','宋诗','song-poetry','','[]','怪生淑氣靜氛埃，知是東君一笑開。',64,'全唐诗/poet.song.154000.json','["怪生淑氣靜氛埃，知是東君一笑開。", "膏雨任能滋宿麥，香風先已上寒梅。", "交情太薄鶑猶懶，遠信難憑鴈却迴。", "聞道君家春最勝，十分眉嫵畫章臺。"]'),
('e4349349-a15d-4cd1-885d-eb41ce29105f','和宋宰立春雨  其二','虞儔','宋','宋诗','song-poetry','','[]','鏡裏朱顔一寸埃，感時懷抱向誰開。',64,'全唐诗/poet.song.154000.json','["鏡裏朱顔一寸埃，感時懷抱向誰開。", "典衣餖飣盤心菜，貰酒留連眼底梅。", "三月鶑花勞問訊，幾家幡勝带能迴。", "新來不作溫柔夢，有底詩情似玉臺。"]'),
('52881853-2274-4277-821c-e67351920edf','和漢老弟迎春','虞儔','宋','宋诗','song-poetry','','[]','青旂小隊喚渠頻，新曆先看早二旬。',64,'全唐诗/poet.song.154000.json','["青旂小隊喚渠頻，新曆先看早二旬。", "羯鼓催花誇敏捷，舞腰迴雪鬭精神。", "燕飛欲傍釵頭月，鴈過纔歸陌上人。", "誰道土牛鞭不動，也能脚底散陽春。"]'),
('6c1c1d11-cd85-4ef8-8ba4-f281605596be','社日邀溫卿溪王天仕吳欽孺遊草堂欽孺有詩因次其韻','虞儔','宋','宋诗','song-poetry','','[]','煙霞痼疾自年齡，冷落江城處士星。',64,'全唐诗/poet.song.154000.json','["煙霞痼疾自年齡，冷落江城處士星。", "松下茶烟青羃羃，竹間碁韻子丁丁。", "林泉雅許幽人往，猿鶴應羞俗駕經。", "沽酒抱琴還有約，要看桂子月中零。"]'),
('dd7f002b-04e2-41c3-8868-4701dba6f7a8','冬至日泊舟嚴陵灘下','虞儔','宋','宋诗','song-poetry','','[]','書雲瑞應協黄鐘，人事天時訝許同。',64,'全唐诗/poet.song.154000.json','["書雲瑞應協黄鐘，人事天時訝許同。", "葭管陰陽消長際，朱幡新舊送迎中。", "嚴陵灘昔懷高節，茂苑城今愧下風。", "醉裏不知鄉國異，團圞相映酒顔紅。"]'),
('3bc0d509-8de2-4f83-95fa-ccd5c6785b73','和漢老弟牛尾貍韻','虞儔','宋','宋诗','song-poetry','','[]','堂饋流涎玉面貍，也知臭腐出神奇。',64,'全唐诗/poet.song.154000.json','["堂饋流涎玉面貍，也知臭腐出神奇。", "分無竹葉浮酥面，尚想梅花映雪肌。", "渠幸臘前能漏網，人言春後亦非時。", "吾儕口腹真餘事，莫倚雄豪浪賦詩。"]'),
('60f3f463-f9c3-4ae3-a61a-ed9fd9083d43','戲和東坡先生牛尾貍詩韻且效其體','虞儔','宋','宋诗','song-poetry','','[]','夜寒那得到簾帷，前擁紅爐後翠眉。',64,'全唐诗/poet.song.154000.json','["夜寒那得到簾帷，前擁紅爐後翠眉。", "未致馬蹄沙水鼈，且嘗牛尾雪天貍。", "葅寒石芥愁辛鼻，鮓熟雛鵝怯带脂。", "端的爲渠添酒興，紅顔相映玉膚肌。"]'),
('88dfe74c-0be6-443c-9df7-028a1bb902b5','觀鶴','虞儔','宋','宋诗','song-poetry','','[]','仙格孤高老始成，臨池愛刷羽毛輕。',64,'全唐诗/poet.song.154000.json','["仙格孤高老始成，臨池愛刷羽毛輕。", "未看月下婆娑舞，且聽風前嘹唳聲。", "向人自在有真態，伴我官閒無俗情。", "少待相將林下去，携筇更引鹿同行。"]'),
('28b03323-eb2f-4685-ad94-070f66f4b6c1','疊蒙林子長和章愈索愈奇未敢遽豎降旗猶能背城借一也','虞儔','宋','宋诗','song-poetry','','[]','詩情引上碧天高，侍史毋辭走送勞。',64,'全唐诗/poet.song.154000.json','["詩情引上碧天高，侍史毋辭走送勞。", "栗里正思陶靖節，愚溪不數柳儀曹。", "只慙同隊疎頭角，莫戀樊籠損羽毛。", "取友如君千載士，陸機作賦豈其豪。"]'),
('4c3af3a7-c462-4685-9308-ce4110011789','甲寅十一月朔旦冬至適值先妣太夫人服闋從吉感而賦詩二首  其一','虞儔','宋','宋诗','song-poetry','','[]','黄鷄催曉破霜天，起整冠裳拜影前。',64,'全唐诗/poet.song.154000.json','["黄鷄催曉破霜天，起整冠裳拜影前。", "又見刺文添一線，誰知泣血已三年。", "蟠桃海上今應熟，雙橘懷中祇自憐。", "未必兒童知此恨，綵衣依舊戲蹁躚。"]'),
('b2f1dca1-54a5-47ab-a58a-76f4bf94b3cc','甲寅十一月朔旦冬至適值先妣太夫人服闋從吉感而賦詩二首  其二','虞儔','宋','宋诗','song-poetry','','[]','維摩應待散花天，無復稱觴壽母前。',64,'全唐诗/poet.song.154000.json','["維摩應待散花天，無復稱觴壽母前。", "從隔蓬壺三萬里，尚期華表一千年。", "弟兄黄髮三人在，故舊青雲衆目憐。", "自愧阿奴真碌碌，不妨鑒井又蹁躚。"]'),
('242de507-b53c-4f00-b74b-4f05d07b12a5','再和','虞儔','宋','宋诗','song-poetry','','[]','天時人事日相煎，否泰俄驚在眼前。',64,'全唐诗/poet.song.154000.json','["天時人事日相煎，否泰俄驚在眼前。", "積閏盡歸冬十月，紀元一似太初年。", "聯珠合璧猶重見，華髮蒼顔益可憐。", "三撫祥琴無意緒，當筵那忍舞蹁躚。"]'),
('bd905bde-dbb2-4fa8-b0de-0bd31246a9ab','讀樂天詩戲效其體','虞儔','宋','宋诗','song-poetry','','[]','杖屨南坡路不賒，就中景物四時佳。',64,'全唐诗/poet.song.154000.json','["杖屨南坡路不賒，就中景物四時佳。", "春林競秀烘遲日，雪岫初晴眩曉霞。", "炎夏清風橫一榻，澄秋明月滿千家。", "人生適意須行樂，况是樽前鬢未華。"]'),
('6ed8c493-a0d5-4572-a6ce-60f4eb6b3bed','同主簿過翠眉亭  其一','虞儔','宋','宋诗','song-poetry','','[]','墨綬低回歎陸沉，好山渾作翠眉顰。',64,'全唐诗/poet.song.154000.json','["墨綬低回歎陸沉，好山渾作翠眉顰。", "我聊爾耳寧違俗，仕有時乎亦爲貧。", "老去催科非所學，向來凋瘵愧斯民。", "整襟再拜欒城像，幸賸殘膏丐後人。"]'),
('7723fc01-25c9-4a9b-b1ce-62f1c2c8b948','同主簿過翠眉亭  其二','虞儔','宋','宋诗','song-poetry','','[]','宦情元薄且浮沉，撫字勞心祇效顰。',64,'全唐诗/poet.song.154000.json','["宦情元薄且浮沉，撫字勞心祇效顰。", "白首論交嗟已晚，青衫捧檄祇緣貧。", "簡書豈不懷朋友，德意安能及吏民。", "誤矣折腰成底事，誰歟高枕有閒人。"]'),
('e740e7e1-fc85-48cc-bc0a-2c590e6dd75d','木犀晚來盛開寄吳守','虞儔','宋','宋诗','song-poetry','','[]','繚枝偃蹇傍巖隈，密葉稜層不露才。',64,'全唐诗/poet.song.154000.json','["繚枝偃蹇傍巖隈，密葉稜層不露才。", "一色渾疑新釀熟，十分端爲好詩開。", "佳人宜與簪雲髻，上客須邀釂玉杯。", "只恐王孫歸未得，小山招隠故應催。"]'),
('2d7c607b-cb1c-40fc-8136-b3680d9b22d3','木犀花開折贈縣宰代簡','虞儔','宋','宋诗','song-poetry','','[]','緗黄襞積間琉璃，病眼看花喜欲迷。',64,'全唐诗/poet.song.154000.json','["緗黄襞積間琉璃，病眼看花喜欲迷。", "半樹斕斑藏霧豹，一秋清絕辟塵犀。", "誰分仙種來蟾窟，知有生香洗麝臍。", "天女維摩應大笑，一枝扶上髻鬟低。"]'),
('94ed7a89-9702-47b9-92b4-e1bdc2fb2da9','木犀初開悉離披於雨今再著花特盛因折送常丞代簡以詩兼簡孫尉','虞儔','宋','宋诗','song-poetry','','[]','萬壑千巖秋欲闌，金商點綴破天慳。',64,'全唐诗/poet.song.154000.json','["萬壑千巖秋欲闌，金商點綴破天慳。", "未須狂雨相將去，且索西風一笑還。", "香列酴醾薝萄右，清宜茅舍竹籬間。", "聞君畫柳爲眉嫵，可復扶花上髻鬟。"]'),
('1390b807-a705-4560-b8db-82393e6cd79e','和人木犀','虞儔','宋','宋诗','song-poetry','','[]','月娥一笑抵千金，玉粟枝頭點綴深。',64,'全唐诗/poet.song.154000.json','["月娥一笑抵千金，玉粟枝頭點綴深。", "莫怪謫仙猶未賞，却因犬子喜相尋。", "漙漙白露新秋色，楚楚黄裳翠雨襟。", "高興已辜紅袖飲，何心相伴白頭吟。"]'),
('3ac0a1ed-6330-47f5-bc79-760e4c151cbd','問訊木犀','虞儔','宋','宋诗','song-poetry','','[]','兩行叢桂手親栽，移自深巖遠壑來。',64,'全唐诗/poet.song.154000.json','["兩行叢桂手親栽，移自深巖遠壑來。", "今夏蒙茸看葉長，來秋端的見花開。", "早時切記頻澆灌，瘦地仍須苦壅培。", "待得東堂枝可折，滿山桃李盡輿臺。"]'),
('703efe4e-f628-4dcc-a174-3d8ffa3adc05','和木犀','虞儔','宋','宋诗','song-poetry','','[]','巖桂無人也自芳，月宮仙子道家粧。',64,'全唐诗/poet.song.154000.json','["巖桂無人也自芳，月宮仙子道家粧。", "露漙僊掌三秋色，風動枝頭十里香。", "先世栽培雖地僻，近年卜築發天藏。", "後堂元有文犀貴，可但腰金照地光。"]'),
('6e56dad5-b9e5-4f35-a032-9d3a4e4ab9bb','和耘老弟木犀詩韻且督漢老弟同賦','虞儔','宋','宋诗','song-poetry','','[]','團餠秋光入好枝，一天風露最清時。',64,'全唐诗/poet.song.154000.json','["團餠秋光入好枝，一天風露最清時。", "管窺豹霧巖前隠，杯泛鵝黄月下宜。", "子落誰賡滄海詠，叢生應有小山知。", "惠連更喜姮娥近，底事觀書却廢詩。"]'),
('e3ae1c07-53ee-43e5-bf64-8626720936f9','和木犀再開','虞儔','宋','宋诗','song-poetry','','[]','東堂留得最高枝，向道重開果有時。',64,'全唐诗/poet.song.154000.json','["東堂留得最高枝，向道重開果有時。", "仙掌露漙秋氣重，山頭月照晚粧宜。", "層層黄色眉間見，拂拂清香鼻觀知。", "更約菊花爲老伴，四難并處可無詩。"]'),
('02e4b56f-8fa7-4aa4-b446-6e325e7f958d','即事  其一','虞儔','宋','宋诗','song-poetry','','[]','奪得饑民鬼手中，誤恩增秩敢言功。',64,'全唐诗/poet.song.154000.json','["奪得饑民鬼手中，誤恩增秩敢言功。", "頗聞有意徵黄霸，却坐無書遺子公。", "莫我愁眉勞撫字，從渠醉眼亂青紅。", "床頭况有韋編在，消長何妨以數窮。"]'),
('fddb475c-2a77-4aa2-a358-39cf54bc38f3','即事  其二','虞儔','宋','宋诗','song-poetry','','[]','光陰老去漫匆匆，千騎南來歲又窮。',64,'全唐诗/poet.song.154000.json','["光陰老去漫匆匆，千騎南來歲又窮。", "竹瘦固應留晚節，梅開寧亦待春風。", "青冥蹭蹬何關我，白髮飄蕭恐未翁。", "畢竟田園歸去好，暮雲回首自江東。"]'),
('87f14f49-1f61-4ed5-830c-8b96821d323a','即事  其三','虞儔','宋','宋诗','song-poetry','','[]','歸來世事任浮沉，車馬蕭條門巷深。',64,'全唐诗/poet.song.154000.json','["歸來世事任浮沉，車馬蕭條門巷深。", "一榻容身無妄想，兩餐度日少關心。", "園收佳實隨時薦，甕有新篘待月斟。", "老覺閒居渾有味，不須榮宦說駸駸。"]'),
('6731e402-677e-485b-ae56-109fa7957ae7','即事  其四','虞儔','宋','宋诗','song-poetry','','[]','春工投老日駸駸，閲遍芳菲又綠陰。',64,'全唐诗/poet.song.154000.json','["春工投老日駸駸，閲遍芳菲又綠陰。", "不復椅梧傾宿鳳，幾番淮海變鳴禽。", "太阿自撫爲知己，焦尾誰彈莫賞音。", "高下風花何足問，向來出處固無心。"]'),
('23914d7d-2e98-4c80-9ace-cd2a19816ddd','和吳守韻送木犀','虞儔','宋','宋诗','song-poetry','','[]','珍重黄堂遺送來，淮南未數小山才。',64,'全唐诗/poet.song.154000.json','["珍重黄堂遺送來，淮南未數小山才。", "分從月裏雙株在，趁得風前一笑開。", "秋著屏幃蟾弄影，春生酒面蟻浮杯。", "姮娥自與花爲約，不愛人間羯鼓催。"]'),
('392ac21b-6617-49a0-b7bb-1e717932d336','枕上再賦','虞儔','宋','宋诗','song-poetry','','[]','折桂東堂又一回，秋花此外祇凡才。',64,'全唐诗/poet.song.154000.json','["折桂東堂又一回，秋花此外祇凡才。", "千巖萬壑幽深處，玉露金風爛漫開。", "有客揮犀紛入坐，幾時清燕小持盃。", "作詩且與留花住，青女繁霜未要催。"]'),
('9e82aed5-39a1-446a-9b84-7ab70e15ad9c','再用韻賦木犀','虞儔','宋','宋诗','song-poetry','','[]','高枝曾折記前回，晚路重逢歎滯才。',64,'全唐诗/poet.song.154000.json','["高枝曾折記前回，晚路重逢歎滯才。", "天上移來和月種，人間占得及秋開。", "香浮翠葆花藏葉，影動燃犀酒映杯。", "猶有黄花堪殿後，爲渠留戀爲渠催。"]'),
('247ce49e-5e11-412a-b464-83552497142f','送張伯子尚書帥隆興  其一','虞儔','宋','宋诗','song-poetry','','[]','舂容聽履上星辰，玉笋班中第一人。',64,'全唐诗/poet.song.154000.json','["舂容聽履上星辰，玉笋班中第一人。", "暫藉威名分閫寄，賸留風采照廷紳。", "何人重記西山雨，老我空傷南浦春。", "此去莫貪爲郡樂，紫樞黄閣待經綸。"]'),
('7c33b2ca-1352-494c-bc50-5cf73c4ed9f8','送張伯子尚書帥隆興  其二','虞儔','宋','宋诗','song-poetry','','[]','十年沉落困推擠，出處於公恨不齊。',64,'全唐诗/poet.song.154000.json','["十年沉落困推擠，出處於公恨不齊。", "本謂重來酬契闊，豈期一見又分携。", "風吹渭水波聲小，春壓陽關柳色低。", "老矣銷魂難語別，且須倒盡玉東西。"]'),
('a8db6be2-b004-40cd-bd18-65c86927c898','鞏使君勸耕汪倅有詩次韻','虞儔','宋','宋诗','song-poetry','','[]','小隊行春簇使旌，黄童白叟遞逢迎。',64,'全唐诗/poet.song.154000.json','["小隊行春簇使旌，黄童白叟遞逢迎。", "勸耕試向何山麓，競渡還傾極樂城。", "畫舫驍騰喧鼓吹，紅粧凝佇傍軒楹。", "山公歸路人爭看，已有豐年笑語聲。"]'),
('283ee63a-0265-401d-afd6-b2ffa68857c6','戲書','虞儔','宋','宋诗','song-poetry','','[]','去年今日到湖州，救得饑民歲又周。',64,'全唐诗/poet.song.154000.json','["去年今日到湖州，救得饑民歲又周。", "閲遍炎凉還自笑，坐靡廩餼更何求。", "淵明栗里終歸去，太史周南枉滯留。", "咄咄大鈞何必問，固知薄命與仇謀。"]'),
('0fb43cc6-5226-4528-b042-314ae4471e0e','子長來詩乃有杜口毗那之語但天女天花未嘗見也詩以先之','虞儔','宋','宋诗','song-poetry','','[]','屬和何須蚌鷸持，笙歌鼎沸政相宜。',64,'全唐诗/poet.song.154000.json','["屬和何須蚌鷸持，笙歌鼎沸政相宜。", "勸君莫惜松醪酒，容我來看柳葉眉。", "春去自憐鶑命友，夜來空費雨催詩。", "海棠還有風流伴，留得芳菲不恨遲。"]'),
('056f37fb-6eee-4a58-958f-b7ed417b7b85','送湯倅二首  其一','虞儔','宋','宋诗','song-poetry','','[]','青衫試吏古桐川，識面池陽別駕賢。',64,'全唐诗/poet.song.154000.json','["青衫試吏古桐川，識面池陽別駕賢。", "但喜論交時一笑，不知爲客度三年。", "新來懷抱愁分袂，此去功名好著鞭。", "未必九華清絕地，更能留滯玉堂仙。"]'),
('89ab7027-5170-47df-8a0a-4337fd0dc0dc','送湯倅二首  其二','虞儔','宋','宋诗','song-poetry','','[]','別乘詞鋒不費磨，江山得助想經過。',64,'全唐诗/poet.song.154000.json','["別乘詞鋒不費磨，江山得助想經過。", "離情柳色長亭暮，愁緒梅腮細雨多。", "渭北論文須細與，洛南問業念如何。", "有時尺素頻相寄，莫負東來錦鯉波。"]'),
('3351278a-41b1-411f-ad8a-0c3fa8ca5943','立秋四十日矣天氣甚凉南坡杖屨之興猶懶何也不應今年歡意頓減如此因以詩挑之','虞儔','宋','宋诗','song-poetry','','[]','灝氣南坡日夕清，杖藜緣底邈無情。',64,'全唐诗/poet.song.154000.json','["灝氣南坡日夕清，杖藜緣底邈無情。", "讀書乃爾妨行樂，覓句從來怪瘦生。", "况有鷄豚燕同社，政須鐘鼓報新晴。", "似聞巖桂花開遍，早晚携壺一就傾。"]'),
('b0a900d2-4eaa-4a77-80ad-9e311f538efb','出郊','虞儔','宋','宋诗','song-poetry','','[]','萬山深處長官貧，不慣將迎懶是真。',64,'全唐诗/poet.song.154000.json','["萬山深處長官貧，不慣將迎懶是真。", "誰解移文迴俗駕，漫勞舉扇障風塵。", "碧雲日暮還無信，白眼途窮易見嗔。", "歸去荒村望燈火，是何雞狗亦驚人。"]'),
('641d62f2-a0a9-42f4-b873-19e820f78ed5','姚黄牡丹','虞儔','宋','宋诗','song-poetry','','[]','紅紫爭先有底忙，姚黄晚出最芬芳。',64,'全唐诗/poet.song.154000.json','["紅紫爭先有底忙，姚黄晚出最芬芳。", "玉非蒸栗難同色，露是薔薇更染香。", "翠幄密遮春去路，黄雲低映曉來粧。", "十分喜氣眉間見，快瀉鵝兒醉洛陽。"]'),
('d7589e55-5019-41f5-9516-5b307fdef16b','種牡丹','虞儔','宋','宋诗','song-poetry','','[]','新向坡頭種牡丹，更開小徑傍層壇。',64,'全唐诗/poet.song.154000.json','["新向坡頭種牡丹，更開小徑傍層壇。", "先生倍費栽培力，俗子那容取次看。", "應有司花來守護，更須插槿與遮欄。", "何時一醉酬心賞，屈指春風半歲寬。"]'),
('cfe67766-5aa6-4175-b4bf-17fa21991ed6','和漢老弟雙蓮詩韻','虞儔','宋','宋诗','song-poetry','','[]','青桂留連最上枝，待君奮翼到天池。',64,'全唐诗/poet.song.154000.json','["青桂留連最上枝，待君奮翼到天池。", "秋蓮又喜呈嘉兆，春草何勞費夢思。", "雅想分香風靜處，更憐並影月明時。", "姮娥似辦雙荷製，故遣馮夷預報知。"]'),
('6d57aa8f-2ece-4236-9d66-b5ce43b632ee','又主簿和雙蓮詩所以期待甚厚再韻爲謝','虞儔','宋','宋诗','song-poetry','','[]','君家雙桂有高枝，便令齊飛集鳳池。',64,'全唐诗/poet.song.154000.json','["君家雙桂有高枝，便令齊飛集鳳池。", "底事乳溪迷簿領，相望泮水費懷思。", "四明人物誰能儷，萬里功名自有時。", "爲我雙蓮出佳句，箇中氣味許君知。"]'),
('d0e7d4a0-ff42-4672-ae3e-f7af9cd212f0','和松老弟同上伯兄塚','虞儔','宋','宋诗','song-poetry','','[]','鶺鴒原上思何窮，排遣新愁酒有功。',64,'全唐诗/poet.song.154000.json','["鶺鴒原上思何窮，排遣新愁酒有功。", "不見老松孤晚歲，忍看宿草又春風。", "危亭徙倚前峯碧，歸路遲迴夕照紅。", "誰謂死生真永訣，會應相對夢魂中。"]'),
('a8e5926e-3fa9-40d4-8c76-008f5c227fde','再用韻謝沈德遠少卿和詩','虞儔','宋','宋诗','song-poetry','','[]','倒指西城我廩高，天公自欲慰民勞。',64,'全唐诗/poet.song.154000.json','["倒指西城我廩高，天公自欲慰民勞。", "聲名敢望黄丞相，詩律間追何水曹。", "三徑就荒身似贅，一行作吏事如毛。", "只須多釀兵厨酒，聊伴先生醉後豪。"]'),
('9ce444b5-26d8-458a-a2a0-a99d3054c052','郁簿以侍御李公頃宰中山清賞圖詩軸相示因賦','虞儔','宋','宋诗','song-poetry','','[]','中山清賞好家風，父母猶能說此翁。',64,'全唐诗/poet.song.154000.json','["中山清賞好家風，父母猶能說此翁。", "誰與畫圖傳浙右，更餘詩句滿江東。", "日邊縱識雙鳬舄，天上難留一馬驄。", "投紱歸來名愈重，橐金雖盡樂何窮。"]'),
('9c5b4cd2-033f-4f8d-8f0e-ff9e979fed26','本縣折納州粳零殘蓋從民便又且可以趣應州府期限張倅反以爲罪','虞儔','宋','宋诗','song-poetry','','[]','平生學道未純全，游宦何須苦著鞭。',64,'全唐诗/poet.song.154000.json','["平生學道未純全，游宦何須苦著鞭。", "作縣又將書下考，離鄉今已跨三年。", "性多忤物無非罪，命與仇謀孰使然。", "撫字催科俱大謬，不如投檄早歸田。"]'),
('2fcac99c-a872-40d4-916c-3df6301212c4','七月一日知丞往衆潯潭命道士投鐵簡是日有雨二日知丞過訪共道靈驗相與感歎因以數語記之','虞儔','宋','宋诗','song-poetry','','[]','老龍高卧古靈湫，喚醒須煩尺簡投。',64,'全唐诗/poet.song.154000.json','["老龍高卧古靈湫，喚醒須煩尺簡投。", "澒洞溪雲隨起雨，渺瀰陂水急通溝。", "定看田里還豐歲，且豢雞豚作好秋。", "可是藍田修故事，爲民精禱益同憂。"]'),
('e3e3dc53-753d-4b01-bfd5-52f9c2e2db40','和廣德鮑宮使寄詩','虞儔','宋','宋诗','song-poetry','','[]','當年書劍走風塵，傾蓋桃花一笑春。',64,'全唐诗/poet.song.154000.json','["當年書劍走風塵，傾蓋桃花一笑春。", "別去交情渾似舊，向來時事幾番新。", "詩壇雄健看前輩，官路低回愧此身。", "珍重煩公問消息，雙溪烟雨政垂綸。"]'),
('565125a4-53cf-4200-91fb-c30026143048','和林子長別後寄詩','虞儔','宋','宋诗','song-poetry','','[]','尺素西來字字真，詩成膠漆重雷陳。',64,'全唐诗/poet.song.154000.json','["尺素西來字字真，詩成膠漆重雷陳。", "連城喜子重增價，敝箒憐吾亦自珍。", "窮達舊聞俱有命，功命底事要知津。", "一樽別後開懷抱，只有湖山似可人。"]'),
('883d125a-4caf-42c8-bd6d-4addc764c478','和吳守拜上方曆日之賜已而雪作約同僚登俯江樓見懷之作  其一','虞儔','宋','宋诗','song-poetry','','[]','六花飛舞到江頭，清賞朝來破客愁。',64,'全唐诗/poet.song.154000.json','["六花飛舞到江頭，清賞朝來破客愁。", "便遣郢人傳白雪，快呼從事到青州。", "寵珍曆象占星鳥，混一疆封驗斗牛。", "遥想倚欄看未足，寒江浩蕩沒輕鷗。"]'),
('30d7cb34-be19-4abe-a077-985f78a80be1','和吳守拜上方曆日之賜已而雪作約同僚登俯江樓見懷之作  其二','虞儔','宋','宋诗','song-poetry','','[]','天教三白瑞來麰，黄竹歌聲浪自愁。',64,'全唐诗/poet.song.154000.json','["天教三白瑞來麰，黄竹歌聲浪自愁。", "未問騎馿遊霸上，行將跨鶴上揚州。", "橋橫忽度行天馬，簾捲何須壓海牛。", "鼓吹從來殺風景，丁寧江上莫驚鷗。"]'),
('e94b7aee-02d1-4d91-9021-9507072539ff','和林正父見寄','虞儔','宋','宋诗','song-poetry','','[]','一別十年難再逢，君今浙左我淮東。',64,'全唐诗/poet.song.154000.json','["一別十年難再逢，君今浙左我淮東。", "功名老去終安在，出處年來恨不同。", "已是死灰何足溺，祇應怪事更書空。", "雞蟲得失無期了，莫爲元規扇障風。"]'),
('a7fa7e73-214b-413b-83b3-f131f9aa880f','和漢老弟','虞儔','宋','宋诗','song-poetry','','[]','寸進鮎魚上竹竿，磨馿終日困團團。',64,'全唐诗/poet.song.154000.json','["寸進鮎魚上竹竿，磨馿終日困團團。", "諸公有意故推挽，議者獻言防誕謾。", "胡不罷休嗟已晚，只堪付與一長嘆。", "杜陵有語君知否，才士從來汲引難。"]'),
('11184438-df4d-4a1e-8c9c-e3b071063a65','得黄仲本詩再和二首以寄之  其一','虞儔','宋','宋诗','song-poetry','','[]','相得詩人我與兄，平生無一不真情。',64,'全唐诗/poet.song.154000.json','["相得詩人我與兄，平生無一不真情。", "河梁莫恨看雲別，剡棹曾經載雪行。", "近喜雙魚傳尺素，遠勝孤鴈带邊城。", "江湖老去知何用，空把葵心向日傾。"]'),
('c5736bee-abe1-4ad7-b823-aad572dd858d','得黄仲本詩再和二首以寄之  其二','虞儔','宋','宋诗','song-poetry','','[]','檣燕呢喃浪語人，岸花飛舞苦傷情。',64,'全唐诗/poet.song.154000.json','["檣燕呢喃浪語人，岸花飛舞苦傷情。", "賸窮詩眼三千界，漫鼓琴心一再行。", "他日湖山還帝里，別時風雨滿江城。", "思君直欲令人老，流水沄沄日夜傾。"]'),
('9ccb0a13-678b-435a-8294-a90a1cc28d8e','和耘老弟韻','虞儔','宋','宋诗','song-poetry','','[]','緩步詩成不用催，松門開徑破莓苔。',64,'全唐诗/poet.song.154000.json','["緩步詩成不用催，松門開徑破莓苔。", "池塘夢草人何在，風雨連山子獨來。", "望斷驚鴻憐片影，愁生雊雉應遊媒。", "僕夫忽報天將暮，又是籃輿寂寞迴。"]'),
('0d69b853-0ec6-4a44-bc2a-a76945861761','和韻','虞儔','宋','宋诗','song-poetry','','[]','粗衣糲飯不難供，有底令人芥蔕胸。',64,'全唐诗/poet.song.154000.json','["粗衣糲飯不難供，有底令人芥蔕胸。", "但得千奴足吾事，不須萬里建侯封。", "繰絲何許逢園客，學稼誰能問老農。", "粗喜近來薪水給，免教雨外急村舂。"]'),
('43f5051f-03f6-4b6f-b572-9a3e712ee297','出郊誌喜','虞儔','宋','宋诗','song-poetry','','[]','香霧崇朝一炷薰，雷聲便得晚來聞。',64,'全唐诗/poet.song.154000.json','["香霧崇朝一炷薰，雷聲便得晚來聞。", "今年雖欠梅黄雨，仲夏猶敷稻綠雲。", "審象已能蘇大旱，卧龍何用說三分。", "腐儒竊有區區見，例奏囊封愧不文。"]'),
('ec93c63a-1e56-43f1-83dc-dfdd7e448d0c','和吳守修蓋禁兵營屋之韻','虞儔','宋','宋诗','song-poetry','','[]','使君事業此權輿，軍政留心盡返初。',64,'全唐诗/poet.song.154000.json','["使君事業此權輿，軍政留心盡返初。", "尺籍伍符須補闕，連營列戍且羣居。", "更觀堅利修兵甲，可但帡幪有屋廬。", "我亦向來飛薦墨，况聞佳頌起閻閭。"]'),
('dae19585-fe22-4a96-8a19-4c51fd593a3f','和漢老弟見寄二首  其一','虞儔','宋','宋诗','song-poetry','','[]','平安一鴈带書來，頓解愁腸日九回。',64,'全唐诗/poet.song.154000.json','["平安一鴈带書來，頓解愁腸日九回。", "珍重梅花還庾嶺，別離楊柳自章臺。", "宦情落落思三徑，世事悠悠付一杯。", "桃李河陽無好手，南坡隨處賸栽培。"]'),
('db69a478-c4b0-4bbb-b3b7-74c21194252a','和漢老弟見寄二首  其二','虞儔','宋','宋诗','song-poetry','','[]','王式當年本不來，送塗未遠徑須回。',64,'全唐诗/poet.song.154000.json','["王式當年本不來，送塗未遠徑須回。", "自憐白璧頻遭劍，何許黄金更築臺。", "夜榻對眠空撫枕，寒爐孤坐懶持盃。", "權門氣燄堪薰炙，况是無資與甕醅。"]'),
('d570dfb7-dbaa-4683-a65d-f5aeb533b991','和耘老弟韻  其一','虞儔','宋','宋诗','song-poetry','','[]','雪意垂垂漫不收，預愁嚴凜壓貂裘。',64,'全唐诗/poet.song.154000.json','["雪意垂垂漫不收，預愁嚴凜壓貂裘。", "十分果是滋農穀，一片何妨上酒舟。", "天遠鴈飛難寄字，江寒魚懶不吞鈎。", "欲酬妙唱無佳思，歲惡詩人且罷休。"]'),
('c1e6720a-c616-425a-b6d6-dccc4761ef90','和耘老弟韻  其二','虞儔','宋','宋诗','song-poetry','','[]','歲旱十分無一收，苦寒何許索重裘。',64,'全唐诗/poet.song.154000.json','["歲旱十分無一收，苦寒何許索重裘。", "流民豈是無常産，觸處渾如不繫舟。", "但願天心憐凍餒，莫教雪意大牽鈎。", "祇今宿麥無人種，誰問王師休未休。"]'),
('cda4fd22-f1bf-422b-b248-2c7fbab2cbe7','和王天任韻','虞儔','宋','宋诗','song-poetry','','[]','槐影侵階晝未移，筠筒忽見破愁眉。',64,'全唐诗/poet.song.154000.json','["槐影侵階晝未移，筠筒忽見破愁眉。", "新篇誰出諸公右，此事終成一段奇。", "我欲潑醅浮大白，君當枉駕授前綏。", "相從日日南坡上，流落人間總是詩。"]'),
('39583dc6-4d66-4b39-9f88-f23f08b2df0d','和姜總管有懷南澗老人','虞儔','宋','宋诗','song-poetry','','[]','一杯相屬豈非天，目送歸鴻付五絃。',64,'全唐诗/poet.song.154000.json','["一杯相屬豈非天，目送歸鴻付五絃。", "霜後黄花秋漠漠，風前丹葉暮翩翩。", "憑欄把酒青山共，即席賡詩紅袖傳。", "我亦從來無此客，敢將觴詠斷前賢。"]'),
('d0c4723d-61dd-4a91-bdf2-55a0e5674c25','和漢老弟秋夜有感  其一','虞儔','宋','宋诗','song-poetry','','[]','一翻梧葉又驚秋，鬢上侵尋歲月流。',64,'全唐诗/poet.song.154000.json','["一翻梧葉又驚秋，鬢上侵尋歲月流。", "夜永只憐燈作伴，詩成却欠酒澆愁。", "多情行雨空揚袂，何物非烟解擊甌。", "室有天遊魂夢好，屏山不遣污油頭。"]'),
('f68a8abf-cc75-4a29-9263-947e2a4cc0ee','和漢老弟秋夜有感  其二','虞儔','宋','宋诗','song-poetry','','[]','西窗風露不禁秋，時數微螢幾點流。',64,'全唐诗/poet.song.154000.json','["西窗風露不禁秋，時數微螢幾點流。", "識字故應甘寂寞，著書初不爲窮愁。", "倦橫如意方三鼓，渴飲門冬自一甌。", "喜報燈花知底事，玉蟲連夜綴釵頭。"]'),
('08093a1e-a3ff-434d-be18-953777ff099b','贈總領韓郎中四十韻','虞儔','宋','宋诗','song-poetry','','[]','玉帛修和好，邊隅久晏寧。',288,'全唐诗/poet.song.154000.json','["玉帛修和好，邊隅久晏寧。", "狼貪素谿壑，鯨浪忽滄溟。", "江漢危航葦，關河失固扃。", "兩淮先齮齕，四海漸凋零。", "稍喜呻吟地，重霑廟社靈。", "帝方恢祚運，公合在朝廷。", "故國非喬木，聞詩飽過庭。", "經綸一門事，風采四夷聽。", "共喜難兄弟，于今尚典刑。", "陵雲臨北固，雪涕陋新亭。", "清切郎官宿，光輝使者星。", "深源觀出處，李泌盛年齡。", "人傑今爲用，天驕盍暫停。", "大弨弦白羽，雄劍發新硎。", "貔虎三千士，芻糧十萬舲。", "少須姿宿飽，作氣上青冥。", "傳檄收天府，偏師下井陘。", "孑遺新雨露，幽蟄待雷霆。", "命服期三錫，腰鐶擁萬釘。", "歸來覲旒冕，早晚煥丹青。", "伊昔蒙傾蓋，隨羣預掣鈴。", "初筵叨禮數，接武奉儀型。", "載酒桃花浪，尋詩杜若汀。", "一斑窺豹管，什襲換鵝經。"]'),
('66400191-9a26-49b0-b80f-711a9b1d7e1a','代鞏使君上東宮生日','虞儔','宋','宋诗','song-poetry','','[]','儲極天開秀，皇圖日又新。',240,'全唐诗/poet.song.154000.json','["儲極天開秀，皇圖日又新。", "夢熊初卜夜，禖燕蚤祠春。", "瑞靄蓬萊殿，祥標析木津。", "準龍真帝子，眉宇只天人。", "少海涵輿地，前星耀紫宸。", "英姿生不世，雄畧動如神。", "仁孝蘭同毓，溫恭玉比純。", "雲章輝步障，月御契重輪。", "堯曆占蓂莢，莊年數大椿。", "千齡符會慶，五福自天申。", "鶴禁移舟夕，龍樓問寢晨。", "慈顔俱有喜，習俗盡還淳。", "湛露漙金菊，凉風動白蘋。", "好秋澄似洗，函夏肅無塵。", "羽翼商山老，簪纓望苑賓。", "歡呼稱壽斚，諧讌接芳裀。", "景邑曾開幕，郎垣偶濫巾。", "不才蒙眄睞，何力贊彌綸。", "符竹分苕水，才華想洛濱。", "歌詩形善祝，秉筆愧徐陳。"]'),
('41986e73-eeaf-4f7d-87d6-bb912b92bd64','往天目祈雨','虞儔','宋','宋诗','song-poetry','','[]','伏謁三池上，難窮一壑幽。',120,'全唐诗/poet.song.154000.json','["伏謁三池上，難窮一壑幽。", "萬山從此起，衆水盡分流。", "暑雨雖愆夏，陰風鎮若秋。", "天高還有目，地險好回頭。", "御府金奩賜，仙壇鐵板投。", "不須憂旱魃，直是起潛虯。", "聖主思霖切，微臣盡日留。", "精誠三禱罷，神聽一聞不。", "霶霈斯爲澤，遲回恐作羞。", "奉常司典禮，秋報敢忘優。"]'),
('bf264c8f-dde4-4534-b40b-7cdd4549f47e','自雲門還泛若耶溪入鏡湖寄院中諸公','虞儔','宋','宋诗','song-poetry','','[]','山中秋賞罷，溪上晚歸時。',84,'全唐诗/poet.song.154000.json','["山中秋賞罷，溪上晚歸時。", "出谷秦人望，經湖謝客期。", "日斜愁路遠，風橫畏舟遲。", "章句懷文友，途程問檝師。", "淺沙游蚌蛤，危石起鸕鷀。", "落葉飛孤戍，橫塘向古祠。", "行行多逸興，無處不相思。"]'),
('0b86b5a9-91a5-4b6e-8a6b-e4d70a67ab16','和漢老弟南坡三十韻','虞儔','宋','宋诗','song-poetry','','[]','北闕書休上，東山妓不携。',288,'全唐诗/poet.song.154000.json','["北闕書休上，東山妓不携。", "宦情元夢鹿，交道只黄鸝。", "瓜戍懷桐汭，星回直攝提。", "雙鳬方欲下，隻履又還西。", "塵土慙書劍，江山識杖藜。", "青冥甘蹭蹬，素手孰提撕。", "笑幕空巢燕，憐藩幾觸羝。", "茲坡何爽塏，造物復推擠。", "蕭寺鐘聲遠，坊門酒旆低。", "目行無遠近，脚力免攀躋。", "更喜經前圃，何妨過小溪。", "烟林輕曳練，雲岫近橫梯。", "井邑千家麗，川原四望迷。", "披榛通曲逕，鋤麥亂蔬畦。", "梅杏增奇觀，牛羊失舊蹊。", "道傍知苦李，霜後認紅梨。", "植竹行抽笋，栽楊蚤秀稊。", "霞蒸桃處處，露怨草凄凄。", "紅白宜相間，高卑未得齊。", "壺漿旁舍乞，飯裹小童齎。", "著屐應同謝，登仙不羨倪。", "芳菲催羯鼓，早晚映榱題。", "葵綠新含露，芹香舊煮泥。", "鴻賓天外去，鳩婦雨中啼。"]'),
('5b2817e0-f72c-4077-880c-13201b76f322','林子長錄舊詩來覓酒因送似之','虞儔','宋','宋诗','song-poetry','','[]','酒者忘憂物，難教與願違。',96,'全唐诗/poet.song.154000.json','["酒者忘憂物，難教與願違。", "未能聊爾耳，時復一中之。", "全醉無乘墜，偏醒有是非。", "兵厨那可戀，州紱屢交馳。", "莫訝臺無餽，相逢蓋有時。", "留髠從昔慣，舍蓋有誰知。", "短棹能來往，經年慰別離。", "何嘗有此客，了事笑癡兒。"]'),
('46a21770-30eb-4854-a5c0-585ceaaaf91e','代黄仲本賀趙漕','虞儔','宋','宋诗','song-poetry','','[]','嶽鎮凝華久，天潢析派初。',120,'全唐诗/poet.song.154000.json','["嶽鎮凝華久，天潢析派初。", "長庚秋入夢，佳氣夜充閭。", "奕葉蘭同茂，懷珠玉不如。", "詞章賀白右，經術向歆餘。", "已近長安日，聊登使者車。", "著鞭先禁路，儲寶鎮皇居。", "家世曾重席，王門昔曳裾。", "彈冠慚似續，入幕借吹噓。", "願獻長生籙，何須鴻寶書。", "黑頭須兩地，玉带擁金魚。"]'),
('3e18f553-178a-4a76-b739-146f7d5bca82','和潘簿食筍詩','虞儔','宋','宋诗','song-poetry','','[]','平生愛竹幾成癖，到處成陰已足嘉。',96,'全唐诗/poet.song.154000.json','["平生愛竹幾成癖，到處成陰已足嘉。", "瀟灑未輸彭澤柳，檀欒偏映杜林花。", "園林日日饒春事，紅紫紛紛盡歲華。", "清節抱萌初入眼，金盤當饋莫摇牙。", "從渠燕頷誇千尺，還我鼇竿是一家。", "須信直鈎終有用，渭川元不釣煙霞。"]'),
('12a27ada-1192-4eac-b3b6-5ae019ba0674','新闢東軒夜間月色滿床可愛簡耘老弟','虞儔','宋','宋诗','song-poetry','','[]','偃息飛簷下，開軒適向東。',24,'全唐诗/poet.song.154000.json','["偃息飛簷下，開軒適向東。", "滿床今夜月，只欠與君同。"]'),
('782eafc1-b803-4771-8f2c-bc7daadb6210','和姜總管感秋七首  其一','虞儔','宋','宋诗','song-poetry','','[]','年華紛代謝，時態幾沉浮。',24,'全唐诗/poet.song.154000.json','["年華紛代謝，時態幾沉浮。", "天末凉風起，何人不感秋。"]'),
('440c6cb9-a5d2-41ff-8b6a-3f34e1b8e4c2','和姜總管感秋七首  其二','虞儔','宋','宋诗','song-poetry','','[]','已是詩成集，何妨酒拍浮。',24,'全唐诗/poet.song.154000.json','["已是詩成集，何妨酒拍浮。", "人生不行樂，空惜鬢驚秋。"]'),
('4686eb10-e01d-45f4-ac1c-50494c953966','和姜總管感秋七首  其三','虞儔','宋','宋诗','song-poetry','','[]','向道鱸魚美，須渠太白浮。',24,'全唐诗/poet.song.154000.json','["向道鱸魚美，須渠太白浮。", "季鷹歸未得，空憶五湖秋。"]'),
('16d249de-1656-48f5-87be-c6ca27d05067','和姜總管感秋七首  其四','虞儔','宋','宋诗','song-poetry','','[]','柏寺官聯謬，萍蹤宦海浮。',24,'全唐诗/poet.song.154000.json','["柏寺官聯謬，萍蹤宦海浮。", "向來苕霅夢，罪我亦春秋。"]'),
('bab27884-88a8-4caa-8b8a-9e30663c282d','和姜總管感秋七首  其五','虞儔','宋','宋诗','song-poetry','','[]','故里經年別，虛舟盡日浮。',24,'全唐诗/poet.song.154000.json','["故里經年別，虛舟盡日浮。", "有書誰與寄，目送鴈橫秋。"]'),
('fcf24098-5791-4522-aa12-a34cd617baee','和姜總管感秋七首  其六','虞儔','宋','宋诗','song-poetry','','[]','窗暗燈花結，簾疎露氣浮。',24,'全唐诗/poet.song.154000.json','["窗暗燈花結，簾疎露氣浮。", "晚來城上角，吹斷一天秋。"]'),
('7c0e8cba-c356-47ad-b526-70c6db8a4ebd','和姜總管感秋七首  其七','虞儔','宋','宋诗','song-poetry','','[]','詩到齊梁後，名多李杜浮。',24,'全唐诗/poet.song.154000.json','["詩到齊梁後，名多李杜浮。", "誰能追正始，蟪小豈知秋。"]'),
('3bf69e12-6861-4952-983d-240dcef7e404','雨過','虞儔','宋','宋诗','song-poetry','','[]','處處村舂急，家家晚爨煙。',24,'全唐诗/poet.song.154000.json','["處處村舂急，家家晚爨煙。", "青山映丹杏，過雨轉嫣然。"]'),
('fa6849ac-97f9-4e34-bb91-eada43afd2bd','南坡雜興','虞儔','宋','宋诗','song-poetry','','[]','寒食無多日，梨花又一春。',24,'全唐诗/poet.song.154000.json','["寒食無多日，梨花又一春。", "鹿門山下路，真有姓龐人。"]'),
('a3f54d32-8880-46b0-9a0c-68b2963e2662','轎中疲甚作絕句','虞儔','宋','宋诗','song-poetry','','[]','謝雨還如禱雨時，籃輿頓撼不勝疲。',32,'全唐诗/poet.song.154000.json','["謝雨還如禱雨時，籃輿頓撼不勝疲。", "兩回往返千餘里，祿馬交馳恐應之。"]'),
('37bcd1c0-a8a2-4284-aa9b-9324fb20e224','歸途轎上口占','虞儔','宋','宋诗','song-poetry','','[]','三尺蒼頭佩酒壺，籃輿穩度白氈鋪。',32,'全唐诗/poet.song.154000.json','["三尺蒼頭佩酒壺，籃輿穩度白氈鋪。", "憑誰爲把無塵筆，畫取先生看雪圖。"]'),
('a6d40bcf-2fc6-4eca-a04a-13e879aa8211','和主簿郁同年','虞儔','宋','宋诗','song-poetry','','[]','紫鸞合在煙霄上，斂翅聊棲枳棘間。',32,'全唐诗/poet.song.154000.json','["紫鸞合在煙霄上，斂翅聊棲枳棘間。", "若向兩途分上下，可能句裏有江山。"]'),
('4a596beb-4f9d-4b33-b75b-7897c51c9507','登舟往瓜州護使客回程','虞儔','宋','宋诗','song-poetry','','[]','冬來長夜數更籌，耿耿青燈照客愁。',32,'全唐诗/poet.song.154000.json','["冬來長夜數更籌，耿耿青燈照客愁。", "底事舟中能好睡，覺來身已抵瓜州。"]'),
